# ── Color scheme picker ───────────────────────────────────────────────────────

def _pick_color_scheme(title: str, rng: random.Random) -> str:
    _load_learned()
    # Use LLM-chosen color scheme if available
    if title in _LEARNED:
        cs = _LEARNED[title].get("color_scheme", "")
        if cs in FACE_GRADIENTS:
            return cs
    lower = title.lower()
    for scheme, kws in [
        ("fire",   ["fire","hot","heat","blaze","burn","red","passion","intense"]),
        ("ice",    ["ice","cold","frost","crystal","blue","chill","cool","frozen"]),
        ("gold",   ["gold","premium","luxury","elite","vip","milky","honey","queen","royal"]),
        ("silver", ["silver","metal","steel","chrome","sharp","clean","blade"]),
        ("rose",   ["rose","pink","love","soft","sweet","sensual","desire","pleasure","kiss"]),
        ("violet", ["purple","violet","dream","fantasy","magic","night","mystic"]),
        ("cyan",   ["neon","electric","cyber","digital","future","techno","glow","wet"]),
        ("lime",   ["green","fresh","wild","jungle","natural","spring"]),
        ("coral",  ["warm","orange","sunset","tropical","exotic","spice","ginger"]),
        ("amber",  ["amber","golden","sunny","summer","tan","caramel","brown"]),
        ("pink",   ["pink","feminine","girl","she","her","pretty","gorgeous","babe"]),
        ("teal",   ["teal","aqua","sea","ocean","water","mermaid","splash"]),
        ("sunset", ["sunset","dusk","dawn","evening","twilight","fall","autumn"]),
        ("cream",  ["cream","morning","bed","gentle","cozy","intimate","lazy","slow"]),
    ]:
        if any(k in lower for k in kws):
            return scheme
    schemes = list(FACE_GRADIENTS.keys())
    return schemes[title_seed(title) % len(schemes)]

# ── Treatment renderers ───────────────────────────────────────────────────────

def _group_for_impact(words: list) -> list:
    """Smart grouping so impact never has >6 rows or orphaned short tokens."""
    # Merge single-char / numeric tokens with neighbour
    merged = []
    i = 0
    while i < len(words):
        w = words[i]
        if len(w) <= 2 and merged:
            merged[-1] = merged[-1] + " " + w
        elif len(w) <= 2 and i + 1 < len(words):
            merged.append(w + " " + words[i+1]); i += 1
        else:
            merged.append(w)
        i += 1
    # If still too many rows, pair them up
    while len(merged) > 6:
        paired = []
        for j in range(0, len(merged), 2):
            if j + 1 < len(merged):
                paired.append(merged[j] + " " + merged[j+1])
            else:
                paired.append(merged[j])
        merged = paired
    return merged


def render_impact(title: str, rng: random.Random) -> Image.Image:
    """Per-word vivid colors, stacked condensed all-caps, thick outline."""
    words = _group_for_impact(title.split())
    bank  = rng.choice(VIVID_BANKS)
    longest = max(words, key=len)
    n = len(longest)
    size = 160 if n<=4 else (140 if n<=6 else (110 if n<=9 else 90))
    font = F("condensed", size, rng)
    sw, ed = 9, 9

    word_imgs = []
    for i, word in enumerate(words):
        mask = make_mask(word.upper(), font, pad=12)
        col  = bank[i % len(bank)]
        sc   = tuple(max(0,c-100) for c in col)
        ec   = tuple(max(0,c-130) for c in col)
        sm   = dilate(mask, sw)
        ext  = extrude(sm, ed, 145, sc, ec)
        sl   = flat_color(sm, (10,10,10))
        face = flat_color(mask, col)
        hl   = highlight(mask, 0.4)
        sh   = drop_shadow(mask, ed+2, ed+3, blur=6, alpha=120)
        img  = composite(sh, ext, sl, face, hl, size=mask.size)
        word_imgs.append(img)

    gap     = 8
    total_w = max(i.width for i in word_imgs) + 60
    total_h = sum(i.height for i in word_imgs) + gap*(len(word_imgs)-1) + 60
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 30
    for img in word_imgs:
        x = (total_w-img.width)//2
        canvas.paste(img, (x,y), img)
        y += img.height + gap
    return canvas


def render_neon_wire(title: str, rng: random.Random) -> Image.Image:
    """Wide-tracked all-caps, electric neon glow with dark bloom (works on any bg)."""
    NEON_COLS = [
        (255,20,147),(0,255,220),(57,255,20),
        (255,100,0),(180,0,255),(255,230,0),
    ]
    col  = NEON_COLS[title_seed(title) % len(NEON_COLS)]
    col2 = NEON_COLS[(title_seed(title)+2) % len(NEON_COLS)]
    n    = len(title)
    size = 140 if n<=15 else (105 if n<=25 else 82)
    font = F("tech", size, rng)
    spacing = rng.randint(14, 30)
    lines   = wrap_chars(title.upper(), 18)
    colors  = [col, col2]

    line_imgs = []
    for i, ln in enumerate(lines):
        c    = colors[i%2]
        mask = wide_track_mask(ln, font, spacing, pad=24)
        # Dark bloom makes glow readable on any background
        dark_bloom = glow_layer(mask, (0,0,0), radii=[(22,0.75),(12,0.90)])
        gl_w = glow_layer(mask, c, radii=[(26,0.40)])
        gl_m = glow_layer(mask, c, radii=[(12,0.70)])
        gl_t = glow_layer(mask, c, radii=[(4,1.00)])
        core = flat_color(mask, c, alpha=255)
        img  = composite(dark_bloom, gl_w, gl_m, gl_t, core, size=mask.size)
        line_imgs.append(img)

    gap     = 16
    total_w = max(i.width for i in line_imgs) + 60
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 50
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 25
    for img in line_imgs:
        x = (total_w-img.width)//2
        canvas.paste(img, (x,y), img)
        y += img.height + gap
    return canvas


def render_editorial(title: str, rng: random.Random) -> Image.Image:
    """Wide letter spacing, decorative rule lines, luxury gradient."""
    scheme   = _pick_color_scheme(title, rng)
    stops    = FACE_GRADIENTS[scheme]
    stroke_c = STROKE_COLORS[scheme]
    n        = len(title)
    size     = 110 if n<=16 else (88 if n<=26 else 72)
    spacing  = rng.randint(8, 20)
    font     = F("elegant", size, rng)
    lines    = wrap_chars(title.upper(), 20)

    line_imgs, line_widths = [], []
    for ln in lines:
        mask = wide_track_mask(ln, font, spacing, pad=14)
        sm   = dilate(mask, 5)
        sl   = flat_color(sm, stroke_c)
        face = colorize(mask, stops)
        sh   = drop_shadow(mask, 5, 7, blur=6, alpha=100)
        img  = composite(sh, sl, face, size=mask.size)
        line_imgs.append(img)
        line_widths.append(mask.width)

    max_w   = max(i.width for i in line_imgs) + 40
    gap, rl_h = 12, 3
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + (rl_h+8)*2 + 50
    canvas  = Image.new("RGBA", (max_w, total_h), (0,0,0,0))

    rl_col = stops[0]
    rl_w   = int(max_w * rng.uniform(0.55, 0.85))
    rl     = rule_line(rl_w, rl_col, rl_h)
    canvas.paste(rl, ((max_w-rl_w)//2, 20), rl)
    y = 20 + rl_h + 10
    for img in line_imgs:
        canvas.paste(img, ((max_w-img.width)//2, y), img)
        y += img.height + gap
    rl_w2 = int(rl_w * rng.uniform(0.6, 0.9))
    rl2   = rule_line(rl_w2, stops[-1], rl_h)
    canvas.paste(rl2, ((max_w-rl_w2)//2, y+4), rl2)
    return canvas


def render_graffiti(title: str, rng: random.Random) -> Image.Image:
    """Italic shear, per-line color, sharp 3D extrusion, condensed."""
    schemes = list(FACE_GRADIENTS.keys())
    shear   = rng.uniform(0.12, 0.28)
    n       = len(title)
    size    = 120 if n<=16 else (95 if n<=26 else 78)
    # marker font first, condensed as fallback for variety
    font    = F(rng.choice(["marker", "marker", "condensed"]), size, rng)
    lines   = wrap_chars(title.upper(), 20)

    line_imgs = []
    for i, ln in enumerate(lines):
        scheme   = schemes[(title_seed(title)+i) % len(schemes)]
        stops    = FACE_GRADIENTS[scheme]
        stroke_c = STROKE_COLORS[scheme]
        ext_c    = EXTRUDE_COLORS[scheme]
        ext_dark = tuple(max(0,c-50) for c in ext_c)
        mask  = make_mask(ln, font, pad=14)
        sw    = rng.randint(7,11)
        sm    = dilate(mask, sw)
        ext   = extrude(sm, rng.randint(8,14), 140, ext_c, ext_dark)
        sl    = flat_color(sm, stroke_c)
        face  = colorize(mask, stops)
        hl    = highlight(mask, 0.5)
        sh    = drop_shadow(mask, 8, 10, blur=6, alpha=110)
        img   = composite(sh, ext, sl, face, hl, size=mask.size)
        img   = shear_image(img, shear)
        line_imgs.append(img)

    gap     = 6
    total_w = max(i.width for i in line_imgs) + 30
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 30
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 15
    for img in line_imgs:
        x = rng.randint(15,45) if len(line_imgs)>1 else (total_w-img.width)//2
        canvas.paste(img, (x,y), img)
        y += img.height + gap
    return canvas


def render_bubble(title: str, rng: random.Random) -> Image.Image:
    """Chunky rounded letters, thick black outline, alternating vivid flat colors."""
    bank = rng.choice(VIVID_BANKS)
    n    = len(title)
    size = 130 if n<=14 else (105 if n<=24 else 82)
    font = F("rounded", size, rng)
    lines = wrap_chars(title.title(), 18)

    line_imgs = []
    for i, ln in enumerate(lines):
        col   = bank[i % len(bank)]
        ext_c = tuple(max(0,c-70) for c in col)
        ext_c2= tuple(max(0,c-120) for c in col)
        mask  = make_mask(ln, font, pad=16)
        sw    = rng.randint(11,16)
        ed    = rng.randint(7,11)
        sm    = dilate(mask, sw)
        ext   = extrude(sm, ed, 148, ext_c, ext_c2)
        sl    = flat_color(sm, (8,8,8))
        # Re-dilate mask slightly less for the actual face so color shows inside outline
        face_m= dilate(mask, 2)
        face  = flat_color(face_m, col)
        hl    = highlight(face_m, 0.50)
        sh    = drop_shadow(sm, ed+2, ed+3, blur=6, alpha=110)
        img   = composite(sh, ext, sl, face, hl, size=mask.size)
        line_imgs.append(img)

    gap     = 4
    total_w = max(i.width for i in line_imgs) + 40
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 40
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 20
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


def render_cinematic(title: str, rng: random.Random) -> Image.Image:
    """Single spaced line, long parallel shadow, film-title feel."""
    scheme   = _pick_color_scheme(title, rng)
    stops    = FACE_GRADIENTS[scheme]
    shadow_c = EXTRUDE_COLORS[scheme]
    n        = len(title)
    size     = 120 if n<=12 else (90 if n<=20 else 70)
    spacing  = rng.randint(18,38)
    font     = F(rng.choice(["elegant", "condensed"]), size, rng)
    mask     = wide_track_mask(title.upper(), font, spacing, pad=16)
    ls_depth = rng.randint(22,35)
    ls_angle = rng.choice([135,140,145,150])
    ls       = long_shadow(mask, ls_depth, ls_angle, shadow_c, fade=True)
    face     = colorize(mask, stops)
    hl       = highlight(mask, 0.40)
    result   = composite(ls, face, hl, size=mask.size)
    rl_w     = int(mask.width * rng.uniform(0.4,0.7))
    rl       = rule_line(rl_w, stops[-1], 2)
    total_h  = result.height + 18
    canvas   = Image.new("RGBA", (result.width, total_h), (0,0,0,0))
    canvas.paste(result, (0,0), result)
    canvas.paste(rl, ((result.width-rl_w)//2, result.height+4), rl)
    return canvas


def render_block_3d(title: str, rng: random.Random) -> Image.Image:
    """Gradient face, deep extrusion, reliable workhorse."""
    scheme   = _pick_color_scheme(title, rng)
    stops    = FACE_GRADIENTS[scheme]
    stroke_c = STROKE_COLORS[scheme]
    ext_c    = EXTRUDE_COLORS[scheme]
    ext_dark = tuple(max(0,c-50) for c in ext_c)
    n        = len(title)
    if n<=10:   size, mc = 155, 12
    elif n<=18: size, mc = 125, 18
    elif n<=28: size, mc = 105, 22
    elif n<=40: size, mc = 85,  26
    else:       size, mc = 72,  32
    font  = F("heavy", size, rng)
    lines = wrap_chars(title.title(), mc)

    line_imgs = []
    for ln in lines:
        mask = make_mask(ln, font, pad=14)
        sw   = rng.randint(7,11)
        ed   = rng.randint(10,16)
        ea   = rng.uniform(135,150)
        sm   = dilate(mask, sw)
        ext  = extrude(sm, ed, ea, ext_c, ext_dark)
        sl   = flat_color(sm, stroke_c)
        face = colorize(mask, stops)
        hl   = highlight(mask, rng.uniform(0.35,0.55))
        sh   = drop_shadow(mask, ed+3, ed+4, blur=7, alpha=rng.randint(90,140))
        img  = composite(sh, ext, sl, face, hl, size=mask.size)
        line_imgs.append(img)

    gap     = 10
    total_w = max(i.width for i in line_imgs) + 50
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 50
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 25
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


def render_script(title: str, rng: random.Random) -> Image.Image:
    """
    Cursive/brush typeface, gradient fill, thick outline, glow shadow.
    Matches the most common style seen in the reference designs
    (SukiSins, TheaSummers, LanaSolo, ChloeRose, MillieMorgan, AriaSloan).
    """
    scheme   = _pick_color_scheme(title, rng)
    stops    = FACE_GRADIENTS[scheme]
    stroke_c = STROKE_COLORS[scheme]
    n        = len(title)
    # Script fonts render larger visually — slightly smaller size
    size     = 130 if n<=14 else (105 if n<=24 else 85)
    font     = F("script", size, rng)
    # Script looks best in Title Case, not ALL CAPS
    lines    = wrap_px(title.title(), font, max_px=900)

    line_imgs = []
    for i, ln in enumerate(lines):
        # Alternate color scheme per line for multi-line
        if i > 0:
            alt_schemes = list(FACE_GRADIENTS.keys())
            scheme2 = alt_schemes[(title_seed(title) + i) % len(alt_schemes)]
            s = FACE_GRADIENTS[scheme2]
            sc = STROKE_COLORS[scheme2]
        else:
            s, sc = stops, stroke_c

        mask = make_mask(ln, font, pad=18)
        sw   = rng.randint(10, 16)
        sm   = dilate(mask, sw)
        sl   = flat_color(sm, sc)
        # Inner glow from brightest stop color
        glow_c = s[0]
        gl     = glow_layer(mask, glow_c, radii=[(14,0.28),(6,0.55)])
        face   = colorize(mask, s)
        hl     = highlight(mask, 0.50)
        sh     = drop_shadow(mask, 14, 16, blur=12, alpha=130)
        img    = composite(sh, sl, gl, face, hl, size=mask.size)
        line_imgs.append(img)

    gap     = 10
    total_w = max(i.width for i in line_imgs) + 70
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 70
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 35
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


def render_retro_rainbow(title: str, rng: random.Random) -> Image.Image:
    """
    Per-layer hue-cycling extrusion, pop-art / retro arcade feel.
    Like the 'Let Do You' / Coco reference design.
    """
    n    = len(title)
    size = 160 if n<=8 else (130 if n<=14 else (100 if n<=22 else 80))
    font = F(rng.choice(["retro", "retro", "condensed"]), size, rng)
    lines = wrap_chars(title.upper(), 14)

    # Cream/white face sits on top of rainbow extrusion
    face_col  = rng.choice([(255,252,230),(255,255,255),(255,248,180)])
    hue_start = rng.random()
    ext_depth = rng.randint(28, 40)
    # Right-down angle so extrusion is visible and doesn't hide under next line
    ext_angle = rng.choice([40, 44, 48, 52])

    line_imgs = []
    for ln in lines:
        mask = make_mask(ln, font, pad=14)
        sw   = rng.randint(8,12)
        sm   = dilate(mask, sw)
        # High saturation/value so the rainbow really pops
        ext  = rainbow_extrude(sm, ext_depth, ext_angle,
                               hue_start=hue_start, sat=1.0, val=1.0)
        sl   = flat_color(sm, (8,8,8))
        face = flat_color(mask, face_col)
        # Second lighter stroke on mask to separate face from rainbow
        sl2  = flat_color(dilate(mask, 3), (8,8,8))
        hl   = highlight(mask, 0.22)
        sh   = drop_shadow(mask, ext_depth//3, ext_depth//3, blur=8, alpha=80)
        img  = composite(sh, ext, sl, sl2, face, hl, size=mask.size)
        line_imgs.append(img)
        hue_start = (hue_start + 0.30) % 1.0  # shift per line

    gap     = 4
    total_w = max(i.width for i in line_imgs) + 50
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 50
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 25
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


def render_chrome(title: str, rng: random.Random) -> Image.Image:
    """
    Liquid-metal chrome gradient, specular white band, deep dark shadow.
    Like the AmeenaGrren chrome block letter reference.
    """
    n    = len(title)
    size = 150 if n<=10 else (120 if n<=18 else (95 if n<=26 else 78))
    font = F(rng.choice(["tech", "condensed"]), size, rng)
    lines = wrap_chars(title.upper(), 18)

    stroke_c = (5,8,12)
    ext_c    = (18,22,32)
    ext_dark = (5,8,12)

    line_imgs = []
    for ln in lines:
        mask = make_mask(ln, font, pad=14)
        sw   = rng.randint(7,12)
        ed   = rng.randint(16,24)
        ea   = rng.uniform(138,148)
        sm   = dilate(mask, sw)
        ext  = extrude(sm, ed, ea, ext_c, ext_dark)
        sl   = flat_color(sm, stroke_c)
        face = colorize(mask, CHROME_STOPS)
        # Strong specular band — the key to the chrome look
        hl   = highlight(mask, 0.80)
        sh   = drop_shadow(mask, ed+5, ed+6, blur=12, alpha=170)
        img  = composite(sh, ext, sl, face, hl, size=mask.size)
        line_imgs.append(img)

    gap     = 8
    total_w = max(i.width for i in line_imgs) + 50
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 50
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 25
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


def render_stark(title: str, rng: random.Random) -> Image.Image:
    """
    Flat black, no extrusion, maximum type weight.
    Like JessePony 'DEEP RELEASE' or Lanan 'LET ME DO YOU'.
    """
    words = title.split()
    n     = len(title)
    # Short titles: word-per-line stack. Long: wrapped.
    if len(words) <= 4 and n <= 20:
        lines = [w.upper() for w in words]
        size  = 180
    else:
        size  = 145 if n<=14 else (115 if n<=24 else 90)
        lines = [ln.upper() for ln in wrap_chars(title, 12)]

    font = F("stark", size, rng)
    # Two variants: stark black fill or stark white fill with heavy black stroke
    variant = rng.choice(["dark", "light"])

    line_imgs = []
    for ln in lines:
        mask = make_mask(ln, font, pad=10)
        if variant == "dark":
            sw   = rng.randint(5,9)
            sm   = dilate(mask, sw)
            sl   = flat_color(sm, (255,255,255), alpha=200)
            face = flat_color(mask, (8,8,8))
            img  = composite(sl, face, size=mask.size)
        else:
            sw   = rng.randint(12,18)
            sm   = dilate(mask, sw)
            sl   = flat_color(sm, (8,8,8))
            face = flat_color(mask, (245,245,245))
            img  = composite(sl, face, size=mask.size)
        line_imgs.append(img)

    gap     = 2
    total_w = max(i.width for i in line_imgs) + 30
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 30
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 15
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


def render_vintage(title: str, rng: random.Random) -> Image.Image:
    """
    Warm sepia/cream tones, aged ornamental serif font, heritage poster feel.
    Good for: location heritage titles, "Royal Treatment", nostalgic tone.
    """
    n        = len(title)
    size     = 115 if n<=16 else (90 if n<=26 else 72)
    spacing  = rng.randint(6, 16)
    font     = F("elegant", size, rng)
    lines    = wrap_chars(title.title(), 22)

    stroke_c  = (90, 55, 10)
    ext_c     = (110, 68, 12)
    ext_dark  = (60, 30, 5)

    line_imgs = []
    for ln in lines:
        mask = wide_track_mask(ln, font, spacing, pad=14)
        sw   = rng.randint(5, 9)
        ed   = rng.randint(6, 11)
        ea   = rng.uniform(138, 148)
        sm   = dilate(mask, sw)
        ext  = extrude(sm, ed, ea, ext_c, ext_dark)
        sl   = flat_color(sm, stroke_c)
        face = colorize(mask, VINTAGE_STOPS)
        hl   = highlight(mask, 0.30)
        sh   = drop_shadow(mask, ed+2, ed+3, blur=8, alpha=100)
        img  = composite(sh, ext, sl, face, hl, size=mask.size)
        line_imgs.append(img)

    # Decorative thin rule in aged gold
    rule_c  = (200, 155, 60)
    max_w   = max(i.width for i in line_imgs) + 40
    gap     = 10
    rl_w    = int(max_w * rng.uniform(0.50, 0.80))
    rl1     = rule_line(rl_w, rule_c, 2)
    rl2     = rule_line(int(rl_w * 0.65), rule_c, 1)
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 60
    canvas  = Image.new("RGBA", (max_w, total_h), (0,0,0,0))
    canvas.paste(rl1, ((max_w-rl_w)//2, 20), rl1)
    y = 32
    for img in line_imgs:
        canvas.paste(img, ((max_w-img.width)//2, y), img)
        y += img.height + gap
    canvas.paste(rl2, ((max_w-int(rl_w*0.65))//2, y+4), rl2)
    return canvas


def render_spray_stencil(title: str, rng: random.Random) -> Image.Image:
    """
    Raw stencil-cut letterforms, overspray edge blur, urban street-art feel.
    Good for: gritty/underground/raw titles, attitude-heavy short phrases.
    """
    scheme    = rng.choice(["fire","cyan","lime","coral","violet","amber"])
    face_col  = FACE_GRADIENTS[scheme][0]
    spray_col = FACE_GRADIENTS[scheme][-1]
    stroke_c  = STROKE_COLORS[scheme]
    n         = len(title)
    size      = 140 if n<=12 else (110 if n<=20 else 85)
    font      = F(rng.choice(["condensed", "stark"]), size, rng)
    lines     = wrap_chars(title.upper(), 16)

    line_imgs = []
    for ln in lines:
        mask = make_mask(ln, font, pad=20)
        # Overspray: blurred soft halo outside the letterform
        spray_blur = rng.randint(8, 14)
        spray_mask = dilate(mask, rng.randint(4, 8))
        spray_img  = flat_color(
            spray_mask.filter(ImageFilter.GaussianBlur(spray_blur)),
            spray_col, alpha=rng.randint(100, 160)
        )
        # Thin dark edge on stencil cut
        sm   = dilate(mask, rng.randint(2, 5))
        sl   = flat_color(sm, stroke_c, alpha=200)
        face = flat_color(mask, face_col)
        # Slight noise/roughness via highlight variance
        hl   = highlight(mask, rng.uniform(0.20, 0.45))
        img  = composite(spray_img, sl, face, hl, size=mask.size)
        # Slight random rotation per line for hand-sprayed feel
        angle = rng.uniform(-2.5, 2.5)
        img   = img.rotate(angle, expand=True, resample=Image.BICUBIC)
        line_imgs.append(img)

    gap     = rng.randint(2, 8)
    total_w = max(i.width for i in line_imgs) + 60
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 40
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 20
    for img in line_imgs:
        x_jitter = rng.randint(-8, 8)
        x = (total_w - img.width)//2 + x_jitter
        canvas.paste(img, (x, y), img)
        y += img.height + gap
    return canvas


def render_liquid_gold(title: str, rng: random.Random) -> Image.Image:
    """
    Molten amber/gold pour gradient, warm opulent fill, dark amber extrusion.
    Good for: indulgent/honey/cream/warm-luxury titles.
    """
    n     = len(title)
    if n<=10:   size, mc = 155, 12
    elif n<=18: size, mc = 125, 18
    elif n<=28: size, mc = 105, 22
    else:       size, mc = 85,  28
    font  = F(rng.choice(["heavy", "condensed"]), size, rng)
    lines = wrap_chars(title.title(), mc)

    stroke_c = (70, 35, 0)
    ext_c    = (120, 65, 0)
    ext_dark = (50, 22, 0)

    line_imgs = []
    for ln in lines:
        mask = make_mask(ln, font, pad=14)
        sw   = rng.randint(8, 12)
        ed   = rng.randint(12, 20)
        ea   = rng.uniform(135, 150)
        sm   = dilate(mask, sw)
        ext  = extrude(sm, ed, ea, ext_c, ext_dark)
        sl   = flat_color(sm, stroke_c)
        face = colorize(mask, LIQUID_GOLD_STOPS)
        # Strong specular like liquid surface
        hl   = highlight(mask, 0.70)
        sh   = drop_shadow(mask, ed+4, ed+5, blur=10, alpha=160)
        img  = composite(sh, ext, sl, face, hl, size=mask.size)
        line_imgs.append(img)

    gap     = 8
    total_w = max(i.width for i in line_imgs) + 50
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 50
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 25
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


def render_neon_box(title: str, rng: random.Random) -> Image.Image:
    """
    Text inside a glowing neon rectangular sign frame.
    Good for: nightlife/venue/club energy, boxed title treatment.
    """
    pal       = rng.choice(NEON_BOX_PALETTES)
    box_col, glow_col = pal
    n         = len(title)
    size      = 120 if n<=14 else (95 if n<=24 else 75)
    spacing   = rng.randint(12, 24)
    font      = F(rng.choice(["tech", "condensed"]), size, rng)
    lines     = wrap_chars(title.upper(), 20)

    line_imgs = []
    for i, ln in enumerate(lines):
        c    = NEON_BOX_PALETTES[(NEON_BOX_PALETTES.index(pal) + i) % len(NEON_BOX_PALETTES)][0]
        mask = wide_track_mask(ln, font, spacing, pad=20)
        dark_bloom = glow_layer(mask, (0,0,0), radii=[(20,0.70),(10,0.85)])
        gl_w = glow_layer(mask, c, radii=[(22,0.35)])
        gl_t = glow_layer(mask, c, radii=[(4,1.00)])
        core = flat_color(mask, c)
        img  = composite(dark_bloom, gl_w, gl_t, core, size=mask.size)
        line_imgs.append(img)

    gap     = 12
    pad_x   = 40
    pad_y   = 28
    text_w  = max(i.width for i in line_imgs)
    text_h  = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1)
    box_w   = text_w + pad_x * 2
    box_h   = text_h + pad_y * 2
    canvas  = Image.new("RGBA", (box_w + 40, box_h + 40), (0,0,0,0))

    # Draw glowing rectangle border
    bx, by = 20, 20
    border  = rng.randint(3, 5)
    draw    = ImageDraw.Draw(canvas)
    # Outer glow layers
    for spread, alpha in [(12, 40), (7, 70), (3, 120)]:
        draw.rectangle(
            [bx-spread, by-spread, bx+box_w+spread, by+box_h+spread],
            outline=(*glow_col, alpha), width=border+2
        )
    # Solid neon line
    draw.rectangle([bx, by, bx+box_w, by+box_h],
                   outline=(*box_col, 240), width=border)
    # Inner faint line
    draw.rectangle([bx+border+2, by+border+2, bx+box_w-border-2, by+box_h-border-2],
                   outline=(*box_col, 80), width=1)

    # Paste text centered inside box
    y = by + pad_y
    for img in line_imgs:
        x = bx + pad_x + (text_w - img.width)//2
        canvas.paste(img, (x, y), img)
        y += img.height + gap

    return canvas


def render_glitch(title: str, rng: random.Random) -> Image.Image:
    """
    RGB channel split + horizontal slice corruption + scanlines. Digital chaos.
    Good for: tech/hacker/cyberpunk/distorted titles.
    """
    n    = len(title)
    size = 150 if n<=10 else (120 if n<=18 else (95 if n<=26 else 78))
    font = F(rng.choice(["tech","condensed"]), size, rng)
    lines = wrap_chars(title.upper(), 16)
    # Pick a dominant hue: cyan, magenta, or green
    hues = [
        [(220,255,255),(0,240,255),(0,140,230)],   # cyan
        [(255,200,255),(255,0,200),(160,0,180)],   # magenta
        [(180,255,180),(0,255,100),(0,160,50)],    # green
    ]
    stops = rng.choice(hues)

    line_imgs = []
    for ln in lines:
        mask  = make_mask(ln, font, pad=16)
        w, h  = mask.size
        arr_m = np.array(mask, dtype=np.uint8)

        # Base colorized face
        face  = np.array(colorize(mask, stops))
        # RGB split: red channel left, blue channel right
        shift = rng.randint(5, 12)
        rgb   = face.copy()
        rgb[:, :-shift, 0] = face[:, shift:, 0]   # red left
        rgb[:, -shift:, 0] = 0
        rgb[:, shift:,  2] = face[:, :-shift, 2]  # blue right
        rgb[:, :shift,  2] = 0
        glitch_face = Image.fromarray(rgb, "RGBA")

        # Horizontal corruption slices
        num_slices = rng.randint(2, 5)
        slice_img  = Image.fromarray(rgb.copy(), "RGBA")
        sl_arr     = np.array(slice_img)
        for _ in range(num_slices):
            sy  = rng.randint(0, h-4)
            sh  = rng.randint(2, max(3, h//10))
            sx  = rng.randint(-shift*2, shift*2)
            src = sl_arr[sy:sy+sh, :, :].copy()
            dst_x0 = max(0, sx); src_x0 = max(0, -sx)
            dst_x1 = min(w, w+sx); src_x1 = src_x0+(dst_x1-dst_x0)
            if src_x1 > src_x0 and dst_x1 > dst_x0:
                sl_arr[sy:sy+sh, dst_x0:dst_x1, :] = src[:, src_x0:src_x1, :]
        glitch_face = Image.fromarray(sl_arr, "RGBA")

        # Dark base stroke
        sm  = dilate(mask, rng.randint(5, 9))
        sl  = flat_color(sm, (0, 0, 0))
        # Glow
        gl  = glow_layer(mask, stops[1], radii=[(10,0.40),(4,0.75)])
        # Scanline overlay: faint horizontal stripes on the text
        scan_a = np.zeros((h, w, 4), dtype=np.uint8)
        step   = rng.randint(3, 6)
        for sy in range(0, h, step):
            alpha_row = np.clip(arr_m[sy, :] * 0.25, 0, 255).astype(np.uint8)
            scan_a[sy, :, 1] = 120   # green tint
            scan_a[sy, :, 3] = alpha_row
        scanlines = Image.fromarray(scan_a, "RGBA")
        img = composite(sl, gl, glitch_face, scanlines, size=mask.size)
        line_imgs.append(img)

    gap     = 6
    total_w = max(i.width for i in line_imgs) + 50
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 50
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 25
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


def render_holographic(title: str, rng: random.Random) -> Image.Image:
    """
    Diagonal rainbow iridescent gradient, prismatic sheen, pastel chrome.
    Good for: dreamy/futuristic/ethereal/cosmic titles.
    """
    n    = len(title)
    size = 140 if n<=12 else (110 if n<=20 else (88 if n<=28 else 72))
    font = F(rng.choice(["elegant","heavy"]), size, rng)
    lines = wrap_chars(title.title(), 18)
    hue_start = rng.random()
    stroke_c  = (20, 10, 30)

    line_imgs = []
    for li, ln in enumerate(lines):
        mask  = make_mask(ln, font, pad=14)
        w, h  = mask.size
        arr_m = np.array(mask, dtype=np.uint8)

        # Diagonal iridescent fill: hue cycles across both x and y
        holo  = np.zeros((h, w, 4), dtype=np.uint8)
        for row in range(h):
            for col in range(w):
                t   = ((row / max(h-1,1)) * 0.55 + (col / max(w-1,1)) * 0.45 +
                       hue_start + li * 0.22) % 1.0
                r,g,b = colorsys.hsv_to_rgb(t, 0.65, 1.0)
                holo[row, col, 0] = int(r*255)
                holo[row, col, 1] = int(g*255)
                holo[row, col, 2] = int(b*255)
                holo[row, col, 3] = arr_m[row, col]
        face = Image.fromarray(holo, "RGBA")

        # Specular white shimmer band
        hl   = highlight(mask, 0.60)
        sm   = dilate(mask, rng.randint(6, 10))
        sl   = flat_color(sm, stroke_c)
        gl   = glow_layer(mask, (200,200,255), radii=[(14,0.20),(6,0.40)])
        sh   = drop_shadow(mask, 8, 9, blur=10, alpha=110)
        img  = composite(sh, sl, gl, face, hl, size=mask.size)
        line_imgs.append(img)

    gap     = 8
    total_w = max(i.width for i in line_imgs) + 50
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 50
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 25
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


# Fire gradient: white core → yellow → orange → deep red
FIRE_STOPS = [(255,255,220),(255,240,60),(255,130,0),(200,30,0),(100,5,0)]

def render_fire(title: str, rng: random.Random) -> Image.Image:
    """
    Burning fire gradient, multi-layer orange/red glow, smoke shadow above.
    Good for: scorching/burning/blazing/hot energy titles.
    """
    n    = len(title)
    size = 155 if n<=10 else (125 if n<=18 else (100 if n<=26 else 82))
    font = F(rng.choice(["heavy","condensed"]), size, rng)
    lines = wrap_chars(title.upper(), 16)

    line_imgs = []
    for ln in lines:
        mask = make_mask(ln, font, pad=16)
        sm   = dilate(mask, rng.randint(8, 13))
        sl   = flat_color(sm, (60, 5, 0))
        # Multi-layer glow: inner hot, outer ember
        gl1  = glow_layer(mask, (255,200,0),  radii=[(6,0.70),(3,0.95)])
        gl2  = glow_layer(mask, (255,80,0),   radii=[(16,0.45),(9,0.60)])
        gl3  = glow_layer(mask, (180,10,0),   radii=[(28,0.25)])
        face = colorize(mask, FIRE_STOPS)
        hl   = highlight(mask, 0.55)
        # Smoke: dark blurred shadow rising ABOVE the text
        sh   = drop_shadow(mask, 0, -rng.randint(6,14), blur=14, alpha=90)
        img  = composite(sh, gl3, gl2, sl, gl1, face, hl, size=mask.size)
        line_imgs.append(img)

    gap     = 8
    total_w = max(i.width for i in line_imgs) + 60
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 60
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 30
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


# Ice gradient: brilliant white → crystal blue → deep navy
ICE_STOPS = [(255,255,255),(210,240,255),(130,200,255),(50,130,220),(20,60,160)]

def render_ice(title: str, rng: random.Random) -> Image.Image:
    """
    Frozen crystalline text, sharp frost edges, cold blue-white glow.
    Good for: cold/frozen/winter/cool/chill titles.
    """
    n    = len(title)
    size = 150 if n<=10 else (120 if n<=18 else (96 if n<=26 else 78))
    font = F(rng.choice(["condensed","tech"]), size, rng)
    lines = wrap_chars(title.upper(), 16)

    line_imgs = []
    for ln in lines:
        mask = make_mask(ln, font, pad=16)
        # Frost spike edge: irregular jagged dilation using two overlaid dilations
        frost_outer = dilate(mask, rng.randint(10, 16))
        frost_inner = dilate(mask, rng.randint(4,  8))
        frost_edge  = Image.fromarray(
            np.clip(np.array(frost_outer,dtype=np.int16) -
                    np.array(frost_inner,dtype=np.int16)*0.6, 0, 255).astype(np.uint8), "L")
        frost_layer = flat_color(frost_edge, (180, 230, 255), alpha=160)
        sm   = dilate(mask, rng.randint(5, 9))
        sl   = flat_color(sm, (10, 40, 100))
        gl1  = glow_layer(mask, (200, 235, 255), radii=[(10,0.50),(4,0.85)])
        gl2  = glow_layer(mask, (80,  170, 255), radii=[(22,0.25)])
        face = colorize(mask, ICE_STOPS)
        hl   = highlight(mask, 0.80)
        sh   = drop_shadow(mask, 6, 7, blur=10, alpha=120)
        img  = composite(sh, frost_layer, sl, gl2, gl1, face, hl, size=mask.size)
        line_imgs.append(img)

    gap     = 8
    total_w = max(i.width for i in line_imgs) + 50
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 50
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 25
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


# Vivid flat colors for comic pop treatment
COMIC_FILLS = [
    (255,60,60),(255,180,0),(0,210,80),(0,160,255),
    (200,60,255),(255,80,140),(80,220,80),(255,120,0),
]

def render_comic(title: str, rng: random.Random) -> Image.Image:
    """
    Thick black outline, flat vivid fill, hard angled shadow — comic book style.
    Good for: energetic/fun/action/punchy titles with pop-art flair.
    """
    n    = len(title)
    size = 155 if n<=10 else (125 if n<=18 else (100 if n<=26 else 82))
    font = F(rng.choice(["heavy","rounded"]), size, rng)
    lines = wrap_chars(title.upper(), 14)
    fill_col = rng.choice(COMIC_FILLS)
    # Shadow color: hard offset duplicate in contrasting dark
    shadow_col = (max(0, fill_col[0]-180), max(0, fill_col[1]-180), max(0, fill_col[2]-180))
    shadow_off = rng.randint(8, 16)

    line_imgs = []
    for ln in lines:
        mask = make_mask(ln, font, pad=14)
        # Hard angled shadow (no blur — comic style)
        sh_arr = np.zeros((*np.array(mask).shape, 4), dtype=np.uint8)
        m_arr  = np.array(mask)
        h, w   = m_arr.shape
        so     = shadow_off
        sh_arr[so:, so:, :3] = [shadow_col[0], shadow_col[1], shadow_col[2]]
        sh_arr[so:, so:, 3]  = m_arr[:h-so, :w-so]
        hard_sh = Image.fromarray(sh_arr, "RGBA")
        # Very thick black outline
        sw  = rng.randint(12, 18)
        sm  = dilate(mask, sw)
        sl  = flat_color(sm, (5, 5, 5))
        # Flat fill + highlight
        face = flat_color(mask, fill_col)
        hl   = highlight(mask, 0.35)
        img  = composite(hard_sh, sl, face, hl, size=mask.size)
        line_imgs.append(img)

    gap     = 4
    total_w = max(i.width for i in line_imgs) + 50
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 50
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 25
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


def render_drip(title: str, rng: random.Random) -> Image.Image:
    """
    Vivid flat fill with painted drip trails hanging below each letter.
    Good for: melting/dripping/psychedelic/paint/messy energy titles.
    """
    n    = len(title)
    size = 145 if n<=10 else (118 if n<=18 else (94 if n<=26 else 78))
    font = F(rng.choice(["heavy","condensed"]), size, rng)
    lines = wrap_chars(title.upper(), 14)
    bank  = rng.choice(VIVID_BANKS)
    drip_extra = int(size * 0.8)   # how far drips hang below text

    line_imgs = []
    for li, ln in enumerate(lines):
        col  = bank[li % len(bank)]
        dark = (max(0,col[0]-100), max(0,col[1]-100), max(0,col[2]-100))
        mask = make_mask(ln, font, pad=14)
        mw, mh = mask.size
        arr_m  = np.array(mask, dtype=np.uint8)

        # Build drip canvas — taller than text
        dh   = mh + drip_extra
        drip_canvas = np.zeros((dh, mw, 4), dtype=np.uint8)
        # Place the text fill in upper part
        drip_canvas[:mh, :, 0] = col[0]
        drip_canvas[:mh, :, 1] = col[1]
        drip_canvas[:mh, :, 2] = col[2]
        drip_canvas[:mh, :, 3] = arr_m

        # Generate drip columns at random x positions along the bottom edge
        num_drips = rng.randint(mw//30, mw//14)
        for _ in range(num_drips):
            dx     = rng.randint(0, mw-1)
            # only drip where there's text at the bottom
            base_a = arr_m[-1, dx] if dx < mw else 0
            if base_a < 60:
                # find last non-zero row in this column
                col_alpha = arr_m[:, dx]
                nz = np.where(col_alpha > 60)[0]
                if len(nz) == 0:
                    continue
                start_y = nz[-1]
            else:
                start_y = mh - 1
            dlen  = rng.randint(drip_extra//4, drip_extra)
            dw2   = rng.randint(2, max(3, size//25))
            for dy in range(dlen):
                row = start_y + dy
                if row >= dh:
                    break
                taper = 1.0 - dy/dlen
                alpha = int(220 * taper)
                x0 = max(0, dx - dw2)
                x1 = min(mw, dx + dw2 + 1)
                drip_canvas[row, x0:x1, 0] = col[0]
                drip_canvas[row, x0:x1, 1] = col[1]
                drip_canvas[row, x0:x1, 2] = col[2]
                drip_canvas[row, x0:x1, 3] = np.clip(
                    drip_canvas[row, x0:x1, 3] + alpha, 0, 255)

        drip_img = Image.fromarray(drip_canvas, "RGBA")
        # Build same-size stroke mask for the full drip shape
        drip_mask = Image.fromarray(drip_canvas[:,:,3], "L")
        sw  = rng.randint(8, 13)
        sm  = dilate(drip_mask, sw)
        sl  = flat_color(sm, dark)
        # Expand sl canvas to full drip height
        sl_full = Image.new("RGBA", (mw, dh), (0,0,0,0))
        sl_full.paste(sl, (0,0), sl)
        img = composite(sl_full, drip_img, size=(mw, dh))
        line_imgs.append(img)

    gap     = 4
    total_w = max(i.width for i in line_imgs) + 50
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 50
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 25
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


def render_outline_glow(title: str, rng: random.Random) -> Image.Image:
    """
    Hollow text — only the glowing outline is visible, transparent interior.
    Good for: overlays, minimal neon sign feel, ghost/ethereal titles.
    """
    n    = len(title)
    size = 155 if n<=10 else (125 if n<=18 else (100 if n<=26 else 82))
    spacing = rng.randint(10, 22)
    font = F(rng.choice(["condensed","tech","heavy"]), size, rng)
    lines = wrap_chars(title.upper(), 16)
    # Pick a vivid neon color
    neon_cols = [
        (0,255,220),(255,20,180),(140,0,255),(0,200,80),(255,200,0),(0,180,255),
    ]
    neon = rng.choice(neon_cols)
    dark_neon = (max(0,neon[0]-80), max(0,neon[1]-80), max(0,neon[2]-80))

    line_imgs = []
    for ln in lines:
        mask    = wide_track_mask(ln, font, spacing, pad=16)
        arr_m   = np.array(mask, dtype=np.uint8)
        # Outer glow
        gl3 = glow_layer(mask, neon, radii=[(24,0.25),(14,0.45)])
        gl2 = glow_layer(mask, neon, radii=[(7,0.75)])
        # Outer stroke
        sw_out = rng.randint(6, 10)
        outer  = dilate(mask, sw_out)
        # Inner stroke — subtract inner from outer → just the ring
        sw_in  = rng.randint(2, 4)
        inner  = dilate(mask, sw_in)
        out_arr = np.array(outer, dtype=np.uint8)
        inn_arr = np.array(inner, dtype=np.uint8)
        ring    = np.clip(out_arr.astype(np.int16) - inn_arr, 0, 255).astype(np.uint8)
        ring_img = flat_color(Image.fromarray(ring, "L"), neon)
        # Dark bloom behind glow (makes it pop on any background)
        dark_gl  = glow_layer(mask, (0,0,0), radii=[(30,0.60)])
        img = composite(dark_gl, gl3, gl2, ring_img, size=mask.size)
        line_imgs.append(img)

    gap     = 8
    total_w = max(i.width for i in line_imgs) + 60
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 60
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 30
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


