# Glitter: bright sparkle gradient base + randomized star-shaped highlights
GLITTER_STOPS = [
    (255,255,255),(255,240,220),(255,200,230),(220,180,255),(180,220,255),
]

def render_glitter(title: str, rng: random.Random) -> Image.Image:
    """
    Sparkling glitter gradient with randomized bright sparkle particles.
    Good for: glamour/diva/feminine/sparkle/luxury titles.
    """
    n    = len(title)
    size = 145 if n<=12 else (115 if n<=20 else (92 if n<=28 else 74))
    font = F(rng.choice(["elegant","script","heavy"]), size, rng)
    lines = wrap_chars(title.title(), 18)
    # Soft pastel base with slight color tint
    tints = [
        [(255,220,240),(255,170,210),(240,120,180)],  # rose
        [(230,210,255),(190,150,255),(150,80,220)],   # violet
        [(210,240,255),(150,210,255),(80,160,240)],   # blue
        [(255,245,200),(255,215,100),(220,170,30)],   # gold
    ]
    base_stops = rng.choice(tints)
    stroke_c   = (max(0,base_stops[-1][0]-80), max(0,base_stops[-1][1]-80),
                  max(0,base_stops[-1][2]-80))

    line_imgs = []
    for ln in lines:
        mask  = make_mask(ln, font, pad=16)
        w, h  = mask.size
        arr_m = np.array(mask, dtype=np.uint8)

        sw   = rng.randint(6, 10)
        sm   = dilate(mask, sw)
        sl   = flat_color(sm, stroke_c)
        face = colorize(mask, base_stops)
        hl   = highlight(mask, 0.55)
        gl   = glow_layer(mask, (255,255,255), radii=[(8,0.30),(3,0.60)])

        # Scatter bright sparkle dots over the text area
        spark = np.zeros((h, w, 4), dtype=np.uint8)
        num_sparks = rng.randint(w*h // 400, w*h // 200)
        for _ in range(num_sparks):
            sx = rng.randint(0, w-1)
            sy = rng.randint(0, h-1)
            if arr_m[sy, sx] < 80:
                continue
            radius = rng.randint(1, 3)
            bright = rng.randint(200, 255)
            for dy in range(-radius, radius+1):
                for dx in range(-radius, radius+1):
                    px, py = sx+dx, sy+dy
                    if 0 <= px < w and 0 <= py < h and arr_m[py,px] > 40:
                        d = abs(dx)+abs(dy)
                        a = int(bright * max(0, 1 - d/(radius+1)))
                        spark[py,px,0] = min(255, int(spark[py,px,0])+a)
                        spark[py,px,1] = min(255, int(spark[py,px,1])+a)
                        spark[py,px,2] = min(255, int(spark[py,px,2])+a)
                        spark[py,px,3] = min(255, int(spark[py,px,3])+a)
        sparks = Image.fromarray(spark, "RGBA")
        sh   = drop_shadow(mask, 8, 9, blur=10, alpha=100)
        img  = composite(sh, sl, gl, face, hl, sparks, size=mask.size)
        line_imgs.append(img)

    gap     = 8
    total_w = max(i.width for i in line_imgs) + 50
    total_h = sum(i.height for i in line_imgs) + gap*(len(line_imgs)-1) + 50
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 25
    for img in line_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


def render_psychedelic(title: str, rng: random.Random) -> Image.Image:
    """
    Per-word hue rotation, warped multicolor face, acid-trip retro energy.
    Good for: trippy/acid/melting/color-saturated/festival titles.
    """
    n    = len(title)
    size = 145 if n<=10 else (118 if n<=18 else (94 if n<=26 else 76))
    font = F(rng.choice(["heavy","rounded","condensed"]), size, rng)
    words = title.upper().split() or [title.upper()]
    if len(words) > 4:
        words = wrap_chars(title.upper(), 12)

    hue_start = rng.random()
    word_imgs = []
    for wi, word in enumerate(words):
        h_shift = (hue_start + wi * 0.22) % 1.0
        r1,g1,b1 = colorsys.hsv_to_rgb(h_shift, 1.0, 1.0)
        r2,g2,b2 = colorsys.hsv_to_rgb((h_shift+0.33) % 1.0, 1.0, 0.85)
        r3,g3,b3 = colorsys.hsv_to_rgb((h_shift+0.66) % 1.0, 1.0, 0.70)
        stops   = [(int(r1*255),int(g1*255),int(b1*255)),
                   (int(r2*255),int(g2*255),int(b2*255)),
                   (int(r3*255),int(g3*255),int(b3*255))]
        dark    = (max(0,stops[-1][0]-120), max(0,stops[-1][1]-120),
                   max(0,stops[-1][2]-120))
        ext_c   = (max(0,stops[0][0]-80), max(0,stops[0][1]-80),
                   max(0,stops[0][2]-80))
        mask    = make_mask(word, font, pad=14)
        sw      = rng.randint(8, 13)
        ed      = rng.randint(14, 22)
        ea      = rng.choice([40, 43, 47, 50])
        sm      = dilate(mask, sw)
        ext     = extrude(sm, ed, ea, ext_c, dark)
        sl      = flat_color(sm, (5,5,5))
        face    = colorize(mask, stops)
        hl      = highlight(mask, 0.40)
        sh      = drop_shadow(mask, ed//2, ed//2, blur=8, alpha=100)
        img     = composite(sh, ext, sl, face, hl, size=mask.size)
        word_imgs.append(img)

    # Stack words
    gap     = rng.randint(2, 8)
    total_w = max(i.width for i in word_imgs) + 50
    total_h = sum(i.height for i in word_imgs) + gap*(len(word_imgs)-1) + 50
    canvas  = Image.new("RGBA", (total_w, total_h), (0,0,0,0))
    y = 25
    for img in word_imgs:
        canvas.paste(img, ((total_w-img.width)//2, y), img)
        y += img.height + gap
    return canvas


