        ((180,10,10),  (100,5,5),   (255,255,255)),
        ((10,50,140),  (5,25,80),   (255,255,255)),
        ((0,100,50),   (0,50,25),   (255,255,255)),
        ((160,120,0),  (90,65,0),   (10,10,10)),
        ((100,0,140),  (55,0,80),   (255,255,255)),
