    colors = [(255, 0, 0), (0, 255, 0), (0, 0, 255), (0, 255, 255), (255, 255, 0)]
    rainbow_gradient = colorize(mask, colors)

    # Create a thick outline layer
    stroke_mask = dilate(mask, px=4)
