def render_go_big_or_go_home(title: str, rng: random.Random) -> Image.Image:
    font = F('sans', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Create gradient background
    bg_gradient = colorize(mask, [(255, 196, 11), (255, 228, 204)])
    
    # Apply 3D extrusion with medium depth and hard glow
    top_color = (255, 196, 11)
    bottom_color = (255, 228, 204)
    extruded_text = extrude(mask, 20, -45, top_color, bottom_color)
    
    # Add thick neon outline
    outline_mask = dilate(mask, 3)
    outline_layer = flat_color(outline_mask, (255, 196, 11), alpha=255)
    
    # Hard glow effect
    glow_radius = [(8, 200)]
    glow_effect = glow_layer(mask, (255, 196, 11), radii=glow_radius)
    
    # Combine all layers
    final_image = composite(bg_gradient, extruded_text, outline_layer, glow_effect, size=(W, H))
    
    return final_image


def render_lucky_neon(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Gradient fill for base text color
    stops = [(int(c), int(b), int(g)) for c, b, g in [colorsys.hsv_to_rgb(i/3.0, 1, 255) for i in range(3)]]
    layer_base = colorize(mask, stops)
    
    # RGB split effect
    r_mask = mask.point(lambda p: p * (p == 255))
    g_mask = mask.point(lambda p: p * (p == 170))
    b_mask = mask.point(lambda p: p * (p == 85))
    
    layer_r = flat_color(r_mask, stops[0])
    layer_g = flat_color(g_mask, stops[1])
    layer_b = flat_color(b_mask, stops[2])
    
    # Hard glow outline
    dilated_mask = dilate(mask, px=4)
    glow_base = glow_layer(dilated_mask, (255, 80, 0), [(6, 200)])
    
    # Composite layers
    base_text = composite(layer_r, layer_g, layer_b, size=(W,H))
    return composite(base_text, glow_base, size=(W,H))


def render_heatwave(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Gradient fill with specified colors
    stops = [(int(c[1:3], 16), int(c[3:5], 16), int(c[5:7], 16)) for c in ['#FFD700', '#FFC107', '#FF9653']]
    gradient_layer = colorize(mask, stops)
    
    # Outline effect
    outline_mask = dilate(mask, px=4)
    outline_color = (255, 255, 255, 255)  # White for the outline
    outline_layer = flat_color(outline_mask, outline_color)
    
    # Glow effect with hard intensity
    glow_radius = [(10, 255), (4, 190)]
    glow_layer_effect = glow_layer(mask, (255, 255, 255), radii=glow_radius)
    
    # RGB split effect
    r_split = colorize(mask, stops).split()[0].convert('L')
    g_split = colorize(mask, stops).split()[1].convert('L')
    b_split = colorize(mask, stops).split()[2].convert('L')
    rgb_split_layer = Image.merge("RGBA", (r_split, g_split, b_split, mask))
    
    # Scanlines effect
    scanline_mask = Image.new("L", (W, H), 0)
    draw = ImageDraw.Draw(scanline_mask)
    for y in range(0, H, 10):
        draw.line((0, y, W, y), fill=255)
    
    scanlines_layer = flat_color(scanline_mask, (0, 0, 0, 255))
    
    # Composite all layers
    final_image = composite(gradient_layer, outline_layer, glow_layer_effect, rgb_split_layer, scanlines_layer, size=(W, H))
    
    return final_image


def render_cloudy_text(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    bg_color = (0, 0, 0, 255)
    bg = Image.new("RGBA", (W, H), bg_color)
    
    cloudy_texture = colorize(mask, [(0, 0, 0), (200, 200, 200)])
    cloudy_texture = cloudy_texture.filter(ImageFilter.GaussianBlur(radius=3))
    
    text_layer = flat_color(mask, (255, 255, 255, 255))
    shadow_layer = drop_shadow(mask, ox=4, oy=4)
    glow_layer1 = glow_layer(mask, (255, 255, 255), [(8, 100)])
    
    return composite(bg, cloudy_texture, text_layer, shadow_layer, glow_layer1, size=(W, H))


def render_retro_outline(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size

    # Gradient fill with retro colors
    stops = [(int(c), int(m), int(y)) for c, m, y in zip(VIVID_BANKS[3][0], VIVID_BANKS[3][1], VIVID_BANKS[3][2])]
    gradient_fill = colorize(mask, stops)

    # Thin neon outline
    thin_outline_mask = dilate(mask, 2)
    outline_color = (255, 193, 11)  # Light orange for retro feel
    outline_layer = flat_color(thin_outline_mask, outline_color, alpha=180)

    # Drop shadow with soft glow
    drop_shadow_layer = drop_shadow(mask, ox=4, oy=4)
    glow_radius = [(2, 150), (3, 90)]
    glow_layer_effect = glow_layer(mask, (255, 157, 87), radii=glow_radius)

    # RGB split effect
    split_mask = mask.copy()
    for i in range(3):
        split_mask.paste(Image.new("L", (W // 3, H), int(255 / 3 * i)), (W // 3 * i, 0))
    red_layer = flat_color(split_mask, (255, 64, 64))
    green_layer = flat_color(split_mask, (64, 255, 64))
    blue_layer = flat_color(split_mask, (64, 64, 255))

    # Combine all layers
    bg = Image.new("RGBA", (W, H), (0, 0, 0, 0))
    return composite(bg, gradient_fill, outline_layer, drop_shadow_layer, glow_layer_effect, red_layer, green_layer, blue_layer, size=(W, H))


def render_concrete_grunge(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Create concrete texture background
    bg_texture = Image.new("RGB", (W, H), "#C0C0C0")
    draw = ImageDraw.Draw(bg_texture)
    
    for _ in range(15):
        x = rng.randint(0, W-1)
        y = rng.randint(0, H-1)
        size = rng.choice([2, 3, 4])
        color = "#756849"
        
        draw.ellipse((x-size//2, y-size//2, x+size//2, y+size//2), fill=color)
    
    # Apply texture as overlay
    bg_texture.putalpha(mask.split()[0].point(lambda i: i > 127 and 255))
    
    # Text layer with colorized mask
    text_color = "#3F3E3E"
    text_layer = flat_color(mask, tuple(int(text_color[i+1:i+3], 16) for i in (0, 2, 4)))
    
    # Thick outline effect
    stroke_mask = dilate(mask, 2)
    stroke_layer = flat_color(stroke_mask, (158, 104, 73))
    
    return composite(bg_texture, text_layer, stroke_layer, size=(W, H))


def render_stamp_printing(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Background color (black)
    bg = flat_color(mask, (0, 0, 0))
    
    # Text fill color (yellowish)
    text_fill = flat_color(mask, (255, 193, 11), alpha=255)
    
    # Thick outline
    thick_outline_mask = dilate(mask, px=4)
    outline_layer = flat_color(thick_outline_mask, (0, 0, 0))
    
    # White stamp effect
    white_stamp_mask = make_mask(title, font, pad=18)
    white_stamp_layer = flat_color(white_stamp_mask, (255, 255, 255), alpha=192)
    
    return composite(bg, text_fill, outline_layer, white_stamp_layer, size=(W, H))


def render_embroidery(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Base color fill with black outline
    base_color = flat_color(mask, (255, 255, 255))
    outline_layer = dilate(mask, px=1)
    outline_color = flat_color(outline_layer, (0, 0, 0), alpha=180)
    
    # Embroidery texture effect
    embroidery_mask = mask.filter(ImageFilter.BLUR).point(lambda x: x > 127 and 255 or 0)
    embroidery_texture = colorize(embroidery_mask, [(255, 255, 255), (192, 192, 192)])
    
    # Composite all layers
    return composite(base_color, outline_color, embroidery_texture, size=(W, H))


def render_halftone(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Black background
    bg = flat_color(mask, (0, 0, 0))
    
    # Colorize with a halftone effect
    colors = [(50 + i * 10, 50 + i * 10, 50 + i * 10) for i in range(6)]
    layer1 = colorize(mask, colors)
    
    # Thick outline
    stroke_mask = dilate(mask, px=4)
    stroke_layer = flat_color(stroke_mask, (255, 255, 255), alpha=200)
    
    return composite(bg, stroke_layer, layer1, size=(W, H))


def render_trust_template(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    bg = Image.new("RGBA", (W, H), (0, 0, 0, 0))
    
    # Gradient fill for text
    gradient_stops = [(int(c[0]), int(c[1]), int(c[2])) for c in VIVID_BANKS[rng.randint(0, len(VIVID_BANKS) - 1)]]
    layer1 = colorize(mask, gradient_stops)
    
    # Hard glow effect
    glow_mask = dilate(mask, 4)
    glow_layer1 = glow_layer(glow_mask, (255, 255, 255), [(6, 200)])
    
    # Drop shadow
    drop_shadow_layer = drop_shadow(mask, ox=3, oy=3, blur=8, alpha=100)
    
    # RGB split effect
    r_channel = layer1.split()[0]
    g_channel = layer1.split()[1].filter(ImageFilter.GaussianBlur(2))
    b_channel = layer1.split()[2].filter(ImageFilter.GaussianBlur(4))
    rgb_split_layer = Image.merge('RGB', (r_channel, g_channel, b_channel)).convert("RGBA")
    
    # Scanlines effect
    scanline_mask = np.zeros((H, W), dtype=np.uint8)
    for i in range(H):
        if i % 10 < rng.randint(2, 5):  # Randomly add a scanline every few rows
            scanline_mask[i] = 255
    scanlines_layer = Image.fromarray(scanline_mask).convert("L")
    scanlines_layer = flat_color(scanlines_layer, (64, 64, 64))
    
    # Composite all layers together
    final_image = composite(bg, drop_shadow_layer, glow_layer1, rgb_split_layer, scanlines_layer, size=(W, H))
    return final_image


def render_dark_neon_outline(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Create a black background
    bg = Image.new("RGBA", (W, H), (0, 0, 0, 255))
    
    # Colorize the text with gradient fill
    colors = [(255, 0, 0), (0, 255, 0)]
    layer1 = colorize(mask, colors)
    
    # Add a thick neon outline
    outline_mask = dilate(mask, px=4)
    outline_layer = flat_color(outline_mask, (255, 0, 0))
    
    # Apply glow effect with hard edges
    glow_radius = [(16, 180)]
    glow_layer_1 = glow_layer(mask, (255, 0, 0), glow_radius)
    
    # Add drop shadow for depth
    shadow_offset_x = 4
    shadow_offset_y = 4
    shadow_layer = drop_shadow(outline_mask, shadow_offset_x, shadow_offset_y)
    
    # Combine layers and apply RGB split effect
    combined_layers = composite(bg, layer1, outline_layer, glow_layer_1, shadow_layer, size=(W, H))
    
    # Apply scanlines for visual interest
    scan_line_spacing = 5
    scan_lines = Image.new("RGBA", (W, H), (0, 0, 0, 0))
    draw = ImageDraw.Draw(scan_lines)
    for y in range(0, H, scan_line_spacing):
        draw.line((0, y, W, y), fill=(255, 255, 255, 128))
    
    final_image = composite(combined_layers, scan_lines, size=(W, H))
    
    return final_image


