def render_chrome_text_effect(title: str, rng: random.Random) -> Image.Image:
    font = F('tech', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Gradient fill for text body
    stops = [(255, 193, 11), (254, 228, 196), (255, 215, 0)]
    layer_base = colorize(mask, stops)
    
    # Split RGB glow effect
    r_glow = glow_layer(mask, (255, 0, 0), [(14, 180)])
    g_glow = glow_layer(mask, (0, 255, 0), [(14, 180)])
    b_glow = glow_layer(mask, (0, 0, 255), [(14, 180)])
    
    # Combine RGB glows
    rgb_glow = composite(r_glow, g_glow, b_glow, size=(W,H))
    
    # Thin neon outline effect
    dilated_mask = dilate(mask, px=3)
