def render_cosmic_text(title: str, rng: random.Random) -> Image.Image:
    font = F('script', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Gradient fill for the base text color
    gradient_colors = [(0, 123, 255), (0, 86, 179), (0, 51, 153)]
    base_text = colorize(mask, gradient_colors)
    
    # Hard glow effect around the text
    hard_glow_mask = dilate(mask, px=4)
    glow_color = (255, 86, 179) if rng.randint(0, 1) else (255, 123, 255)
    hard_glow = glow_layer(hard_glow_mask, glow_color, [(4, 255)])
    
    # Drop shadow for depth
    drop_shadow_depth = drop_shadow(mask, ox=8, oy=8, blur=12, alpha=100)
    
    # Thick outline effect
    thick_outline_mask = dilate(mask, px=3)
    outline_color = (255, 123, 255) if rng.randint(0, 1) else (255, 86, 179)
    thick_outline = flat_color(thick_outline_mask, outline_color, alpha=150)
    
    # RGB split effect
    split_layers = []
    for shift in range(-3, 4, 3):
        shifted_mask = mask.transform(mask.size, Image.AFFINE, (1, 0, shift, 0, 1, 0))
        split_layer = colorize(shifted_mask, gradient_colors)
        split_layers.append(split_layer)
    
    # Scanlines effect
    scanline_width = rng.randint(2, 4)
    for y in range(scanline_width, H, scanline_width * 2):
        line_mask = Image.new('L', (W, scanline_width), color=255)
        line_image = flat_color(line_mask, (0, 0, 0))
        drop_shadow_depth = composite(drop_shadow_depth, line_image, size=(W, H))
    
    # Composite all layers
    final_text = composite(base_text, hard_glow, thick_outline, *split_layers, drop_shadow_depth, size=(W, H))
    
    return final_text


def render_logo_template(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Grunge texture background
    bg_texture = Image.new("RGBA", (W, H), (0, 0, 0, 255))
    draw = ImageDraw.Draw(bg_texture)
    
    for _ in range(10):
        x = rng.randint(0, W-1)
        y = rng.randint(0, H-1)
        radius = rng.randint(3, 8)
        color = (rng.randint(20, 50), rng.randint(20, 50), rng.randint(20, 50))
        draw.ellipse((x-radius, y-radius, x+radius, y+radius), fill=color)
    
    # Solid base text
    layer1 = flat_color(mask, (48, 48, 48))
    
    # Thick outline effect
    outline_mask = dilate(mask, 2)
    layer2 = glow_layer(outline_mask, (0, 0, 0), [(5, 128)])
    
    # Gradient fill for text
    stops = [((0, 0.3), (48, 48, 48)), ((0.7, 1), (255, 193, 11))]
    layer3 = colorize(mask, [(x[1] + y) for x in stops for y in VIVID_BANKS[rng.randint(0, len(VIVID_BANKS)-1)]])
    
    # Drop shadow
    drop_shadow_layer = drop_shadow(outline_mask, ox=4, oy=4)
    
    return composite(bg_texture, drop_shadow_layer, layer3, layer2, layer1, size=(W, H))


def render_broken_text(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Grunge texture base layer
    grunge_texture = np.random.randint(0, 256, (H, W), dtype=np.uint8)
    grunge_img = Image.fromarray(grunge_texture).convert("L")
    
    # Apply slight distortion to the text
    distorted_mask = mask.filter(ImageFilter.GaussianBlur(radius=1))
    
    # Create a dark base color layer with grunge texture overlay
    bg_color = flat_color(mask, (0, 0, 0), alpha=255)
    grunge_layer = Image.composite(grunge_img, bg_color.convert("RGBA"), grunge_img)
    
    # Thin outline effect
    thin_outline_mask = dilate(distorted_mask, px=1)
    outline_color = flat_color(thin_outline_mask, (75, 75, 75), alpha=255)
    
    # Distressed look with blur
    distressed_text = distorted_mask.filter(ImageFilter.GaussianBlur(radius=2))
    distressed_layer = colorize(distressed_text, [(0, 0, 0), (192, 192, 192)])
    
    return composite(grunge_layer, outline_color, distressed_layer, size=(W, H))


def render_neon_mockup(title: str, rng: random.Random) -> Image.Image:
    font = F('tech', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Background color (dark base for neon effect)
    bg_color = (30, 30, 30, 255)
    bg = Image.new("RGBA", (W, H), bg_color)
    
    # Neon outline with RGB split technique
    neon_colors = [(255, 193, 111), (255, 228, 196), (255, 150, 88)]
    outline_mask = dilate(mask, px=4)
    
    # Apply RGB split effect
    red_layer = colorize(outline_mask, [(255, 0, 0)])
    green_layer = colorize(outline_mask, [(0, 255, 0)])
    blue_layer = colorize(outline_mask, [(0, 0, 255)])
    
    # Composite RGB layers
    neon_outline = composite(red_layer, green_layer, blue_layer, size=(W,H))
    
    # Gradient fill for depth and mood enhancement
    gradient_stops = [(30, 30, 30), (192, 192, 192)]
    gradient_fill = colorize(mask, stops=gradient_stops)
    
    # Final composite with background and neon outline
    final_layer = composite(bg, neon_outline, gradient_fill, size=(W,H))
    
    return final_layer


def render_float(title: str, rng: random.Random) -> Image.Image:
    font = F('sans', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size

    # Base neon outline layer
    outline_color = (128, 0, 128)
    base_layer = flat_color(mask, outline_color)

    # Gradient fill for the text
    gradient_stops = [(64, 0, 64), (32, 0, 32)]
    gradient_layer = colorize(mask, gradient_stops)

    # Drop shadow effect
    drop_shadow_layer = drop_shadow(mask, ox=10, oy=10, blur=8, alpha=150)

    # RGB split effect
    red_channel = mask.convert("L").point(lambda x: 255 if (x > 0) else 0)
    green_channel = mask.convert("L").point(lambda x: 0)
    blue_channel = mask.convert("L").point(lambda x: 128)

    red_layer = colorize(red_channel, [(255, 0, 0), (192, 0, 0)])
    green_layer = colorize(green_channel, [(0, 255, 0), (0, 192, 0)])
    blue_layer = colorize(blue_channel, [(0, 0, 255), (0, 0, 192)])

    # Composite all layers
    return composite(base_layer, gradient_layer, drop_shadow_layer, red_layer, green_layer, blue_layer, size=(W, H))


