def render_metal_gradients(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Define color palette
    colors = [(128, 128, 128), (155, 155, 155), (192, 192, 192)]
    
    # Create gradient background
    bg = Image.new("RGBA", (W, H))
    draw = ImageDraw.Draw(bg)
    for i in range(H):
        r, g, b = colors[0][0] + (colors[1][0] - colors[0][0]) * i / H, \
                  colors[0][1] + (colors[1][1] - colors[0][1]) * i / H, \
                  colors[0][2] + (colors[1][2] - colors[0][2]) * i / H
        draw.line([(0, i), (W, i)], fill=(int(r), int(g), int(b), 255))
    
    # Create metallic texture overlay
    texture = Image.new("RGBA", (W, H))
    for x in range(W):
        for y in range(H):
            r, g, b = colors[1][0] + (colors[2][0] - colors[1][0]) * rng.random(), \
                      colors[1][1] + (colors[2][1] - colors[1][1]) * rng.random(), \
                      colors[1][2] + (colors[2][2] - colors[1][2]) * rng.random()
            texture.putpixel((x, y), (int(r), int(g), int(b), 100))
    
    # Apply metallic texture to gradient background
    bg = Image.alpha_composite(bg, texture)
    
    # Create text layer with slight shadow
    text_layer = colorize(mask, colors)
    shadow = drop_shadow(mask, 2, 2, blur=5, alpha=64)
    
    # Composite all layers
    return composite(shadow, bg, text_layer, size=(W, H))


