def render_dark_neon(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Background
    bg = Image.new("RGBA", (W, H), (0, 0, 0, 255))
    
    # Neon outline
    outline_mask = dilate(mask, 8)
    neon_outline = flat_color(outline_mask, (0, 255, 0), alpha=128)
    
    # Glow effect
    glow = glow_layer(mask, (0, 255, 0), [(14, 180)])
    
    # Drop shadow
    shadow = drop_shadow(mask, 10, 10, blur=16, alpha=100)
    
    # RGB split effect
    def rgb_split(image, offsets):
        r, g, b, a = image.split()
        r = r.point(lambda i: i + offsets[0])
        g = g.point(lambda i: i + offsets[1])
        b = b.point(lambda i: i + offsets[2])
        return Image.merge("RGBA", (r, g, b, a))
    
    # Scanlines effect
    scanline_mask = np.zeros((H, W), dtype=np.uint8)
    scanline_mask[::20] = 255
    scanline_image = Image.fromarray(scanline_mask).convert("L")
    scanline_effect = flat_color(scanline_image, (255, 255, 255, 100))
    
    # Composite all layers
    final_image = composite(bg, shadow, glow, neon_outline, scanline_effect, size=(W, H))
    
    return final_image


def render_chrome_glow(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
