def render_neon_glow(title: str, rng: random.Random) -> Image.Image:
    font = F('heavy', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Define colors
    glow_colors = [(255, 193, 7), (255, 159, 94), (255, 99, 71)]
    
    # Create glow layer
    glow_mask = dilate(mask, 10)
    glow_layer = colorize(glow_mask, glow_colors)
    
    # Create text layer with RGB split effect
    text_layer = flat_color(mask, (255, 255, 255))
    red_split = Image.new("RGBA", (W, H), (255, 0, 0, 0))
    green_split = Image.new("RGBA", (W, H), (0, 255, 0, 0))
    blue_split = Image.new("RGBA", (W, H), (0, 0, 255, 0))
    
    red_layer = composite(text_layer, glow_layer, size=(W, H)).convert("L")
    green_layer = composite(text_layer, glow_layer, size=(W, H)).convert("L")
    blue_layer = composite(text_layer, glow_layer, size=(W, H)).convert("L")
    
    red_split.paste(red_layer, (0, 0), mask=red_layer)
    green_split.paste(green_layer, (5, 5), mask=green_layer)
    blue_split.paste(blue_layer, (-5, -5), mask=blue_layer)
    
    # Combine RGB split layers
    final_image = Image.merge("RGBA", (red_split.split()[0], 
                                      green_split.split()[1], 
                                      blue_split.split()[2], 
                                      text_layer.split()[3]))
    
    return composite(final_image, glow_layer, size=(W, H))


def render_glow(title: str, rng: random.Random) -> Image.Image:
    font = F('heavy', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Define colors
    glow_colors = [(255, 193, 7), (255, 159, 94), (255, 99, 71)]
    
    # Create a gradient background for the glow effect
    bg_glow = Image.new("RGBA", (W, H))
    draw = ImageDraw.Draw(bg_glow)
    for y in range(H):
        color = tuple(int(c * (y / H)) for c in glow_colors[0])
        draw.line((0, y, W, y), fill=color)
    
    # Create the main text layer with RGB split effect
    layers = []
    for i, rgb in enumerate(glow_colors):
        shifted_mask = Image.new("L", (W, H))
        shifted_mask.paste(mask, (i * 2, 0))
        layer = colorize(shifted_mask, [rgb])
        layers.append(layer)
    
    # Composite all layers
    final_image = composite(*layers, bg_glow, size=(W, H))
    
    return final_image


