def render_grainy_text(title: str, rng: random.Random) -> Image.Image:
    font = F('serif', 120, rng=rng)
    mask = make_mask(title, font)
    W, H = mask.size
    
    # Create a black background
    bg = Image.new("RGBA", (W, H), (0, 0, 0, 255))
    
    # Apply grainy texture using Gaussian noise
    noise = np.random.poisson(25, (H, W)).astype(np.uint8)
    noise_img = Image.fromarray(noise).convert("L")
    noise_masked = Image.blend(bg, flat_color(mask, (255, 255, 255)), alpha=128)
    noise_masked.paste(Image.new("RGBA", (W, H), (0, 0, 0, 255)), mask=noise_img)
    
    # Apply RGB split effect
    split_layers = []
    for i, color in enumerate([(255, 0, 0), (0, 255, 0), (0, 0, 255)]):
        layer = flat_color(mask, color)
        split_layers.append(Image.blend(noise_masked, layer, alpha=128))
    
    # Composite the split layers
    final_image = composite(*split_layers, size=(W, H))
    
    return final_image

