def render_chrome_bevel(title: str, rng: random.Random) -> Image.Image:
    """Mirror-chrome letters, transparent background."""
    fs = auto_size(title, 200, 14)
    font = F("heavy", fs, rng)
    mask = make_mask(title.upper(), font, pad=40)
    mw, mh = mask.size
    variant = rng.choice([
        [(30,30,35),(180,180,195),(255,255,255),(200,205,215),(55,60,70)],   # silver
        [(20,22,28),(100,110,125),(200,210,225),(150,165,180),(40,45,55)],   # blue-chrome
        [(40,35,30),(130,125,120),(210,205,200),(160,155,150),(60,55,50)],   # warm gunmetal
        [(15,15,20),(160,160,175),(245,245,255),(190,195,210),(45,45,60)],   # cold steel
        [(25,20,20),(150,120,110),(230,210,205),(180,155,150),(50,35,30)],   # rose-steel
    ])
    angle = rng.choice([110, 125, 140, 155])
    strength = rng.uniform(1.8, 2.8)
    chrome = colorize(mask, variant)
    hl, sh = bevel_light(mask, angle_deg=angle, strength=strength)
    ds = drop_shadow(mask, rng.randint(4, 9), rng.randint(6, 12), blur=rng.randint(10, 18), alpha=180)
    if rng.random() < 0.5:
        tint = rng.choice([(80,140,255),(255,80,80),(80,255,180),(255,200,80)])
        ig = inner_glow(mask, tint, radii=[(5, 0.35)])
        return composite(ds, chrome, hl, sh, ig, size=(mw, mh))
    return composite(ds, chrome, hl, sh, size=(mw, mh))

