def render_neon_tube(title: str, rng: random.Random) -> Image.Image:
    """Realistic neon glow, transparent background."""
    fs = auto_size(title, 200, 14)
    font = F("heavy", fs, rng)
    mask = make_mask(title.upper(), font, pad=60)
    mw, mh = mask.size
    col = rng.choice([(255,60,120),(0,240,180),(255,120,0),(80,180,255),(200,0,255),(255,240,0),(0,255,120),(255,60,200)])
    bloom_r = rng.randint(35, 52)
    mid_r   = rng.randint(15, 24)
    tight_r = rng.randint(4, 8)
    bloom      = glow_layer(mask, col, radii=[(bloom_r, rng.uniform(0.38, 0.52))])
    mid_glow   = glow_layer(mask, col, radii=[(mid_r,   rng.uniform(0.62, 0.78))])
    tight_glow = glow_layer(mask, col, radii=[(tight_r, 0.92)])
    core = flat_color(mask, (255, 255, 255))
    ig   = inner_glow(mask, col, radii=[(rng.randint(6,10), 0.9), (3, 1.0)])
    if rng.random() < 0.45:
        # Dual-color: second accent bloom at wider radius
        col2   = rng.choice([(255,240,0),(0,200,255),(255,60,200),(0,255,160),(200,80,255)])
        accent = glow_layer(mask, col2, radii=[(bloom_r + rng.randint(12, 20), 0.22)])
        return composite(accent, bloom, mid_glow, tight_glow, core, ig, size=(mw, mh))
    return composite(bloom, mid_glow, tight_glow, core, ig, size=(mw, mh))

