def render_stone_carved(title: str, rng: random.Random) -> Image.Image:
    """Stone-textured letters with concave bevel, transparent background."""
    fs = auto_size(title, 200, 14)
    font = F("slab", fs, rng)
    mask = make_mask(title.upper(), font, pad=40)
    mw, mh = mask.size
    # Stone type: (noise_lo, noise_hi, r_off, g_off, b_off, outline_v)
    stone_type = rng.choice([
        (155, 195,  0, -10, -20, 60),   # warm granite
        (180, 215,  0,  -5, -30, 70),   # sandstone
        (200, 245,  0, -15, -10, 80),   # cool marble
        (90,  130,  5,   5,  12, 40),   # dark slate (blue-gray)
        (190, 220,  0,  -8, -25, 65),   # limestone
        (110, 155, -5,  -5,  -5, 35),   # dark granite
    ])
    lo, hi, r_off, g_off, b_off, outline_v = stone_type
    nprng = np.random.default_rng(rng.randint(0, 99999))
    noise = nprng.integers(lo, hi, (mh, mw), dtype=np.uint8)
    noise_r = np.clip(noise.astype(np.int32) + r_off, 0, 255).astype(np.uint8)
    noise_g = np.clip(noise.astype(np.int32) + g_off, 0, 255).astype(np.uint8)
    noise_b = np.clip(noise.astype(np.int32) + b_off, 0, 255).astype(np.uint8)
    m = np.array(mask, dtype=np.uint8)
    stone_arr = np.stack([noise_r, noise_g, noise_b, m], axis=2)
    stone = Image.fromarray(stone_arr, "RGBA")
    bevel_angle = rng.choice([300, 315, 330])
    hl, sh = bevel_light(mask, angle_deg=bevel_angle, strength=rng.uniform(2.0, 3.2))
    outline_thick = rng.randint(2, 4)
    outline_dil = dilate(mask, outline_thick)
    outline_arr = np.zeros((mh, mw, 4), np.uint8)
    outline_arr[:,:,3] = np.clip(np.array(outline_dil,np.int32) - np.array(mask,np.int32), 0, 255).astype(np.uint8)
    outline_arr[:,:,:3] = outline_v
    outline = Image.fromarray(outline_arr, "RGBA")
    ds = drop_shadow(mask, rng.randint(4, 7), rng.randint(4, 7), blur=rng.randint(8, 14), alpha=160)
    return composite(ds, outline, stone, sh, hl, size=(mw, mh))

def render_holographic_foil(title: str, rng: random.Random) -> Image.Image:
    """Diagonal rainbow foil, transparent background."""
    fs = auto_size(title, 200, 14)
    font = F("heavy", fs, rng)
    mask = make_mask(title.upper(), font, pad=40)
    mw, mh = mask.size
    m = np.array(mask, dtype=np.float32) / 255.0
    ys, xs = np.mgrid[0:mh, 0:mw]
    ax = rng.uniform(0.4, 1.8)
    ay = rng.uniform(0.3, 1.2)
    hue_offset = rng.uniform(0.0, 1.0)
    hue = ((xs * ax + ys * ay) / max(mw * ax + mh * ay, 1) + hue_offset) % 1.0
    sat = np.float32(rng.uniform(0.75, 1.0))
    val = np.float32(rng.uniform(0.85, 1.0))
    h6 = hue * 6.0
    i  = h6.astype(np.int32) % 6
    f  = h6 - np.floor(h6)
    p  = val * (1 - sat)
    q  = val * (1 - sat * f)
    t  = val * (1 - sat * (1 - f))
    rgb = np.zeros((mh, mw, 3), dtype=np.float32)
    for ci, (r_,g_,b_) in enumerate([(val,t,p),(q,val,p),(p,val,t),(p,q,val),(t,p,val),(val,p,q)]):
        sel = (i == ci)
        rgb[:,:,0] = np.where(sel, r_, rgb[:,:,0])
        rgb[:,:,1] = np.where(sel, g_, rgb[:,:,1])
        rgb[:,:,2] = np.where(sel, b_, rgb[:,:,2])
    foil_arr = np.zeros((mh, mw, 4), dtype=np.uint8)
    foil_arr[:,:,:3] = np.clip(rgb * 255, 0, 255).astype(np.uint8)
    foil_arr[:,:,3]  = np.clip(m * 255, 0, 255).astype(np.uint8)
    foil = Image.fromarray(foil_arr, "RGBA")
    hl, sh = bevel_light(mask, angle_deg=rng.choice([115, 130, 145, 160]), strength=rng.uniform(1.2, 2.2))
    ds = drop_shadow(mask, rng.randint(3, 6), rng.randint(4, 8), blur=rng.randint(8, 14), alpha=rng.randint(80, 130))
    if rng.random() < 0.5:
        return composite(ds, foil, hl, sh, size=(mw, mh))
    return composite(ds, foil, hl, size=(mw, mh))

def render_pop_halftone(title: str, rng: random.Random) -> Image.Image:
    """Halftone dot fill with bold outline, transparent background."""
    fs = auto_size(title, 200, 14)
    font = F("comic", fs, rng)
    mask = make_mask(title.upper(), font, pad=40)
    mw, mh = mask.size
    dot_col, outline_col = rng.choice([
        ((230,30,30),   (0,0,0)),        # red / black
        ((20,100,255),  (255,220,0)),    # blue / yellow
        ((255,180,0),   (20,20,20)),     # yellow / black
        ((0,180,60),    (200,0,60)),     # green / red
        ((200,0,255),   (255,200,0)),    # purple / gold
        ((255,60,120),  (0,200,220)),    # pink / cyan
        ((0,200,220),   (255,60,0)),     # cyan / orange
        ((20,20,20),    (255,255,255)),  # black / white
    ])
    dot_spacing = rng.choice([9, 11, 13, 16])
    r = max(2, dot_spacing // 3)
    dots_img = Image.new("L", (mw, mh), 0)
    dc = ImageDraw.Draw(dots_img)
    stagger = rng.random() < 0.5
    for row, yy in enumerate(range(0, mh, dot_spacing)):
        x_off = dot_spacing // 2 if (stagger and row % 2 == 1) else 0
        for xx in range(-x_off, mw + dot_spacing, dot_spacing):
            dc.ellipse([xx-r, yy-r, xx+r, yy+r], fill=255)
    dots_masked = apply_mask(flat_color(dots_img, dot_col), mask)
    outline_thick = rng.randint(3, 6)
    dil = dilate(mask, outline_thick)
    outline_arr = np.zeros((mh, mw, 4), np.uint8)
    outline_arr[:,:,3] = np.clip(np.array(dil,np.int32) - np.array(mask,np.int32), 0, 255).astype(np.uint8)
    outline_arr[:,:,:3] = outline_col
    outline = Image.fromarray(outline_arr, "RGBA")
    ex_depth = rng.randint(5, 10)
    ex_angle = rng.choice([210, 225, 240])
    ex_col   = tuple(max(0, c - 30) for c in outline_col)
    ex = extrude(mask, ex_depth, ex_angle, ex_col, tuple(max(0, c - 60) for c in ex_col))
    return composite(ex, dots_masked, outline, size=(mw, mh))

