        ((160,0,255),(0,180,255),(240,248,255),(0,220,255),(220,0,255)),    # purple/cyan
        ((0,200,60),(180,255,0),(240,255,240),(80,255,0),(0,255,100)),      # green/lime
        ((255,60,0),(255,200,0),(255,255,240),(255,80,0),(255,220,0)),      # fire
