def render_letterpress(title: str, rng: random.Random) -> Image.Image:
    """Dark ink with deboss bevel, transparent background."""
    fs = auto_size(title, 200, 14)
    font = F("slab", fs, rng)
    mask = make_mask(title.upper(), font, pad=40)
    mw, mh = mask.size
    ink_stops = rng.choice([
        [(15,10,8),(55,38,25)],       # black ink
        [(5,10,35),(20,35,80)],       # navy blue
        [(15,35,10),(35,75,25)],      # dark forest
        [(35,8,8),(80,20,20)],        # dark burgundy
        [(40,25,5),(90,55,15)],       # sepia
        [(25,0,40),(60,10,90)],       # deep purple
    ])
    ink = colorize(mask, ink_stops)
    bevel_angle = rng.choice([295, 310, 325, 340])
    hl, sh = bevel_light(mask, angle_deg=bevel_angle, strength=rng.uniform(1.1, 2.0))
    # Subtle ink noise texture
    nprng = np.random.default_rng(rng.randint(0, 99999))
    m = np.array(mask, dtype=np.uint8)
    noise = nprng.integers(0, 30, (mh, mw), dtype=np.uint8)
    tex_arr = np.zeros((mh, mw, 4), np.uint8)
    tex_arr[:,:,3] = ((noise.astype(np.uint32) * m.astype(np.uint32)) // 255).astype(np.uint8)
    tex_layer = Image.fromarray(tex_arr, "RGBA")
    ds = drop_shadow(mask, rng.randint(2, 5), rng.randint(2, 5), blur=rng.randint(4, 9), alpha=80)
    return composite(ds, ink, sh, hl, tex_layer, size=(mw, mh))

def render_laser_etch(title: str, rng: random.Random) -> Image.Image:
    """Brushed metal letters with laser glow edges, transparent background."""
    fs = auto_size(title, 200, 14)
    font = F("tech", fs, rng)
    mask = make_mask(title.upper(), font, pad=48)
    mw, mh = mask.size
    base_stops = rng.choice([
        [(120,122,128),(200,202,210),(240,242,248),(170,172,178)],   # silver
        [(90,80,70),(160,145,130),(200,185,170),(130,115,100)],      # gunmetal
        [(100,85,50),(180,155,80),(220,195,120),(150,125,60)],       # brass
        [(60,70,80),(130,145,160),(180,200,215),(100,115,130)],      # blue steel
        [(80,75,75),(155,150,148),(210,208,205),(140,135,132)],      # titanium
    ])
    laser_col = rng.choice([(0,255,150),(0,200,255),(255,80,0),(180,0,255),(255,220,0),(0,255,60),(255,40,120)])
    metal = colorize(mask, base_stops)
    ig_r = rng.randint(8, 15)
    ig    = inner_glow(mask, laser_col, radii=[(ig_r, 0.95), (4, 1.0)])
    outer = glow_layer(mask, laser_col, radii=[(rng.randint(11, 20), rng.uniform(0.45, 0.65))])
    hl, sh = bevel_light(mask, angle_deg=rng.choice([118, 130, 142]), strength=rng.uniform(1.0, 1.8))
    return composite(outer, metal, sh, hl, ig, size=(mw, mh))

def render_duotone_bold(title: str, rng: random.Random) -> Image.Image:
    """Bold letters with hard colour offset shadow, transparent background."""
    fs = auto_size(title, 200, 14)
    font = F("athletic", fs, rng)
    mask = make_mask(title.upper(), font, pad=42)
    mw, mh = mask.size
    shadow_col = rng.choice([(255,40,40),(255,200,0),(0,200,100),(255,80,200),(0,120,255),(255,120,0),(0,220,220),(180,0,255)])
    fill_col   = rng.choice([(255,255,255),(240,240,240),(255,255,210),(210,240,255),(255,220,255)])
    # Randomize shadow offset direction and size
    ox = rng.choice([-14,-12,-10,10,12,14])
    oy = rng.choice([8,10,12,14])
    blur_amt = rng.choice([0, 0, 0, 2])  # mostly crisp hard shadow
    shadow_layer = drop_shadow(mask, ox, oy, blur=blur_amt, alpha=255)
    sh_np = np.array(shadow_layer)
    sh_np[:,:,0]=shadow_col[0]; sh_np[:,:,1]=shadow_col[1]; sh_np[:,:,2]=shadow_col[2]
    shadow_layer = Image.fromarray(sh_np, "RGBA")
    fill = flat_color(mask, fill_col)
    # Sometimes add a thin outline matching shadow color
    if rng.random() < 0.55:
        dil = dilate(mask, rng.randint(2, 3))
        out_arr = np.zeros((mh, mw, 4), np.uint8)
        out_arr[:,:,3] = np.clip(np.array(dil,np.int32) - np.array(mask,np.int32), 0, 255).astype(np.uint8)
        out_arr[:,:,:3] = shadow_col
        outline = Image.fromarray(out_arr, "RGBA")
        return composite(shadow_layer, outline, fill, size=(mw, mh))
    return composite(shadow_layer, fill, size=(mw, mh))

