def render_aurora_borealis(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F("elegant", auto_size(title, pivot=12), rng)
    mask_L = make_mask(title, font, pad=40)
    mw, mh = mask_L.size

    # Randomize aurora start hue
    h_start = rng.uniform(90, 180) / 360.0
    v_gradient = [(h_start + x / mw * (270/360), 1.0 - abs(x/mw - 0.5) * 0.4, 1.0) for x in np.linspace(0, mw, num=5)]

    # Apply aurora colorize effect
    aurora_img = colorize(mask_L, v_gradient)

    # Soft outer glow_layer in cyan
    glow_rgba = glow_layer(mask_L, (0, 255, 255), radii=[(10, 1.5)])

    # inner_glow in white-green
    innerglow_rgba = inner_glow(mask_L, (76, 255, 0), radii=[(4, 0.8), (3, 0.5)])

    return composite(aurora_img, glow_rgba, innerglow_rgba, size=(mw, mh))


