def render_camouflage_pattern_wild1456(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'heavy'
    mask_L = make_mask(title, F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    # Generate a random camouflage pattern
    camo_pattern = np.random.rand(mw, mh) * 255
    for x in range(mw):
        for y in range(mh):
            if rng.uniform(0, 1) > 0.9:
                camo_pattern[x][y] = 0  # Dark spots
            elif rng.uniform(0, 1) > 0.85:
                camo_pattern[x][y] = rng.randint(64, 127)  # Midtones
            else:
                camo_pattern[x][y] = rng.randint(128, 255)  # Light tones

    camo_img = Image.fromarray(camo_pattern.astype('uint8'), mode='L')
    base_camo_color = (rng.randint(0, 64), rng.randint(32, 96), rng.randint(16, 48))
    camouflage_rgba = flat_color(mask_L, base_camo_color)

    # Randomize camo variant with color shifts
    if rng.uniform(0, 1) < 0.5:
        camouflage_rgba = colorize(mask_L, [(rng.randint(32, 96), rng.randint(64, 128), rng.randint(128, 192)),
                                             (rng.randint(96, 160), rng.randint(128, 192), rng.randint(160, 224))])
    else:
        camouflage_rgba = colorize(mask_L, [(rng.randint(0, 32), rng.randint(16, 64), rng.randint(8, 32)),
                                             (rng.randint(64, 96), rng.randint(128, 160), rng.randint(128, 160))])

    # Apply mask and return the final image
    masked_camo = apply_mask(camouflage_rgba, mask_L)
    return composite(masked_camo, size=(mw, mh))


