def render_camouflage_pattern_wild2051(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = ["heavy"]
    mask_L = make_mask(title, F(rng.choice(font_role), auto_size(title), rng))
    mw, mh = mask_L.size

    # Earth tones for camouflage
    earth_tones = [
        (0, 51, 31),   # Dark Green
        (46, 29, 18),  # Brown
        (165, 122, 73),# Tan
        (46, 46, 46)   # Black
    ]
    
    # Randomize colors and pattern variant
    camo_variant = rng.randint(0, 2)
    primary_color = earth_tones[camo_variant]
    secondary_colors = [color for color in earth_tones if color != primary_color]

    # Generate camouflage texture as a blend of solid fills
    base_camo = flat_color(mask_L, primary_color)
    pattern_layers = [base_camo]
    
    for _ in range(2):  # Add two more layers with secondary colors
        random_secondary = rng.choice(secondary_colors)
        pattern_layer = flat_color(dilate(mask_L, rng.randint(-5, 5)), random_secondary)
        pattern_layers.append(pattern_layer)

    camouflage_pattern = composite(*pattern_layers, size=(mw, mh))
    
    return camouflage_pattern


