def render_chalkboard_text_wild1568(title: str, rng: random.Random) -> Image.Image:
    font_role = 'marker'
    title = title.upper()
    base_font_size = auto_size(title)
    adjusted_font_size = rng.randint(int(base_font_size * 0.9), int(base_font_size * 1.1))
    mask_L = make_mask(title, F(font_role, adjusted_font_size, rng))

    # Soften the edges of the mask
    blurred_mask_L = mask_L.filter(ImageFilter.BLUR)
    
    # Randomize color and noise for chalk texture
    fill_color = (rng.randint(200, 255), rng.randint(200, 255), rng.randint(200, 255))
    texture_noise = np.random.normal(scale=10, size=(mask_L.size[1], mask_L.size[0]))
    
    # Apply chalk texture with random noise
    chalk_fill_RGBA = flat_color(blurred_mask_L, fill_color)
    chalk_texture = Image.fromarray((texture_noise * 255).astype(np.uint8), mode='L')
    chalk_filled_with_texture = Image.blend(chalk_fill_RGBA.convert('RGBA'), Image.merge("RGBA", [chalk_texture] * 4), alpha=0.3)
    
    # Apply mask to the final layer
    mw, mh = mask_L.size
    return apply_mask(chalk_filled_with_texture, blurred_mask_L)


