def render_chalkboard_text_wild497(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = "marker"
    mask_L = make_mask(title, F(font_role, 20 + auto_size(title), rng))
    
    mw, mh = mask_L.size
    noise_color_r = rng.randint(150, 255)
    noise_color_g = rng.randint(150, 255)
    noise_color_b = rng.randint(150, 255)

    # Apply texture-like noise to the chalkboard fill
    mask_L_with_noise = Image.fromarray(np.random.poisson(lam=1, size=(mw, mh)).astype('uint8') * (rng.uniform(20, 80) / 255.0))
    mask_smoothed = mask_L.filter(ImageFilter.GaussianBlur(radius=rng.uniform(1, 3)))

    fill_color_r = rng.randint(0, 256)
    fill_color_g = rng.randint(0, 256)
    fill_color_b = rng.randint(0, 256)

    chalk_fill = flat_color(mask_smoothed, (fill_color_r, fill_color_g, fill_color_b))
    chalk_noise_overlay = flat_color(mask_L_with_noise, (noise_color_r, noise_color_g, noise_color_b))

    return composite(chalk_fill, chalk_noise_overlay, size=(mw, mh))


