def render_comic_v1034(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'comic'
    mask_L = make_mask(title, F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    base_color = (rng.randint(205, 240), rng.randint(180, 230), rng.randint(150, 220))
    glow_radii = [(int(rng.expovariate(.2)), float(rng.uniform(.6, .9))) for _ in range(2)]
    gradient_stops = [
        (rng.randint(140, 220), rng.randint(110, 210), rng.randint(80, 190)),
        (rng.randint(150, 230), rng.randint(120, 220), rng.randint(90, 200))
    ]

    base_layer = flat_color(mask_L, base_color)
    glow_layer_rgba = glow_layer(mask_L, (255, 255, 255), radii=glow_radii)
    colorized_layer = colorize(mask_L, gradient_stops)

    shadow_offset_x = rng.randint(1, 3)
    shadow_offset_y = rng.randint(-4, -1)
    blur_radius = int(rng.uniform(1.0, mh * .05))
    alpha_value = int(rng.uniform(mh / 20., mw / 18.))

    dropshadow_layer = drop_shadow(mask_L, shadow_offset_x, shadow_offset_y, blur_radius, alpha_value)

    bevel_angle_deg = rng.randint(-30, 30)
    bevel_strength = rng.uniform(.75, .95)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    return composite(base_layer, glow_layer_rgba, colorized_layer, dropshadow_layer, highlight_rgba, shadow_rgba, size=(mw, mh))


