def render_comic_v110(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = "comic"
    base_font_size = auto_size(title)
    font_size = rng.randint(base_font_size - 5, base_font_size + 5)
    mask_L = make_mask(title, F(font_role, font_size, rng), pad=40)

    mw, mh = mask_L.size
    main_color = (rng.randint(230, 255), rng.randint(180, 200), rng.randint(160, 220))
    shadow_color = (rng.randint(150, 170), rng.randint(140, 160), rng.randint(130, 150))

    solid_fill_RGBA = flat_color(mask_L, main_color)
    glow_radii = [(rng.uniform(2.5, 3.5), rng.uniform(0.8, 1.2)), (rng.uniform(1.7, 2.5), rng.uniform(0.6, 0.9))]
    glow_RGBA = glow_layer(mask_L, main_color, radii=glow_radii)

    shadow_blur = int(rng.uniform(mw * 0.03, mw * 0.04))
    shadow_shift_x = int(rng.randint(-mw // 8, mw // 6))
    shadow_shift_y = int(rng.randint(-mh // 8, mh // 6))
    drop_shadow_RGBA = drop_shadow(mask_L, shadow_shift_x, shadow_shift_y, shadow_blur, rng.randint(120, 150))

    inner_glow_radii = [(rng.uniform(0.7, 1.3), rng.uniform(0.4, 0.6)), (rng.uniform(0.4, 0.8), rng.uniform(0.2, 0.5))]
    inner_glow_RGBA = inner_glow(mask_L, shadow_color, radii=inner_glow_radii)

    bevel_angle_deg = rng.uniform(-30, 30)
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, bevel_angle_deg, strength=rng.uniform(0.5, 1))

    extrude_depth = int(rng.randint(mw // 20, mw // 16))
    extrude_angle_deg = rng.uniform(-45, 45)
    near_color = (rng.randint(main_color[0] - 30, main_color[0]), rng.randint(main_color[1] - 20, main_color[1]),
                  rng.randint(main_color[2] - 20, main_color[2]))
    far_color = (rng.randint(shadow_color[0] + 5, shadow_color[0] + 20), rng.randint(shadow_color[1] + 5,
                                                                                       shadow_color[1] + 20),
                  rng.randint(shadow_color[2] + 5, shadow_color[2] + 20))
    extrude_RGBA = extrude(mask_L, extrude_depth, extrude_angle_deg, near_color, far_color)

    return composite(solid_fill_RGBA, glow_RGBA, drop_shadow_RGBA, inner_glow_RGBA, highlight_RGBA, shadow_RGBA,
                     extrude_RGBA, size=(mw, mh))


