    highlight_rgba, shadow_rgba = bevel_light(mask_L, bevel_angle, strength=0.7)
    
    drop_shadow_img = drop_shadow(dilate(mask_L, int(rng.uniform(5,10))), int(rng.gauss(-2,8)), int(rng.uniform(2,6)), 127)

    composite_layers = [
        base_text_img,
        text_glow,
        apply_mask(highlight_rgba, mask_L),
        apply_mask(shadow_rgba, dilate(mask_L, -3)),
        background_img,
        drop_shadow_img
    ]

    return composite(*composite_layers, size=(mw,mh))


