    bg_color = (rng.randint(200, 255), rng.randint(180, 230), rng.randint(160, 210))
    text_color = (rng.randint(0, 90), rng.randint(70, 140), rng.randint(100, 170))
    gradient_colors = [
        (rng.randint(50, 100), rng.randint(80, 130), rng.randint(60, 120)),
        (rng.randint(150, 200), rng.randint(140, 190), rng.randint(160, 210))
    ]
    glow_color = (rng.randint(200, 255), rng.randint(180, 230), rng.randint(160, 210))
    inner_glow_color = (rng.randint(70, 120), rng.randint(90, 140), rng.randint(110, 160))
    bevel_angle_deg = rng.uniform(-35.0, 35.0)
    drop_shadow_x = rng.choice([-2, -1, 0, 1, 2])
    drop_shadow_y = rng.choice([0, 1, 2])
    extrude_depth = rng.randint(1, mh // 20)

