    bg_gradient = colorize(dilate(mask_L, 4), gradient_colors)
    
    # Glow effect around the text
    glow_effect = glow_layer(mask_L, glow_color, radii=[(10.0, 2.5), (7.0, 3.0)])
    
    # Inner glow effect inside the text outline
    inner_glow_effect = inner_glow(mask_L, inner_glow_color, radii=[(4.0, 1.5)])

