def render_comic_v2990(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('comic', auto_size(title), rng)
    mask_L = make_mask(title, font, pad=40)
    mw, mh = mask_L.size

    # Base fill and outline
    base_color = flat_color(mask_L, (rng.randint(25,75), 180 + rng.randint(-30,60), 120))
    outline_color = flat_color(mask_L, (90+rng.randint(-40,0), 170+rng.randint(-20,10), 100))

    # Gradient effect
    gradient_stops = [(rng.randint(50,180)+r*30, rng.randint(100,200)+g*30, rng.randint(60,170)) for r,g in zip([0]*4 + [1]*4, range(-2, 6))]
    gradient_fill = colorize(mask_L, [(c[0], c[1]-rng.randint(50,90), c[2]+rng.randint(30,80)) for c in gradient_stops])
    
    # Glows and shadows
    bloom_color = glow_layer(mask_L, (rng.randint(160, 220), rng.randint(140, 200), rng.randint(150, 190)), [(rng.gauss(3.8, 0.8), 0.07)])
    inner_bloom_color = inner_glow(mask_L, (rng.randint(160, 220), rng.randint(140, 200), rng.randint(150, 190)), [(rng.gauss(3.8, 0.8), 0.07)])
    
    shadow_color = drop_shadow(mask_L, mw//4, mh//4 + mw//6, int(rng.normalvariate(mw/12, mw/60)), rng.randint(50,150))

    # Composite all elements
    return composite(base_color, gradient_fill, outline_color, inner_bloom_color, bloom_color, shadow_color, size=(mw, mh))


