def render_comic_v3014(title: str, rng: random.Random) -> Image.Image:
    mask_L = make_mask(title.upper(), F('comic', auto_size(title), rng))
    mw, mh = mask_L.size

    base_color = (rng.randint(230, 255), rng.randint(180, 220), rng.randint(170, 200))
    glow_radii = [(rng.uniform(.4, .9) * mw / 600, rng.uniform(.02, .1))]
    glow_color = (rng.randint(230, 255), rng.randint(180, 220), rng.randint(170, 200))

    base_layer = flat_color(mask_L, base_color)
    glow_effect = glow_layer(mask_L, glow_color, glow_radii)

    angle_deg = rng.uniform(-30, 30)
    highlight_rgb, shadow_rgb = bevel_light(mask_L, angle_deg, .4 + rng.random() * .6)

    drop_radius = int(.15 * mw / 480)
    drop_offset_x = rng.randint(-2, 2)
    drop_offset_y = rng.randint(3, 7)
    shadow_alpha = rng.uniform(.6, 1.0) * 255

    shadow_effect = drop_shadow(mask_L, drop_offset_x, drop_offset_y, drop_radius, int(shadow_alpha))

    return composite(base_layer, glow_effect, shadow_effect, size=(mw, mh))


