def render_comic_v3062(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'comic'
    mask_L = make_mask(title, F(font_role, 140, rng))
    mw, mh = mask_L.size

    base_font_size = auto_size(title)
    font = F('comic', base_font_size * rng.uniform(0.95, 1.2), rng)

    text_rgba = flat_color(mask_L, (rng.randint(64, 255), rng.randint(0, 128), rng.randint(0, 128)))

    glow_colors = [(rng.randint(128, 255), rng.randint(0, 127), rng.randint(128, 255)),
                   (rng.randint(64, 255), rng.randint(32, 192), rng.randint(64, 255))]
    glow_radii = [(rng.uniform(1.0, 2.0), rng.uniform(2.0, 3.0)), (rng.uniform(2.0, 3.0), rng.uniform(2.0, 4.0))]
    glow_rgba = colorize(mask_L, glow_colors)

    inner_glow_color = (rng.randint(160, 255), rng.randint(80, 200), rng.randint(80, 200))
    inner_glow_radii = [(rng.uniform(0.5, 1.5), rng.uniform(1.5, 3.0))]
    inner_glow_rgba = inner_glow(mask_L, inner_glow_color, inner_glow_radii)

    bevel_angle_deg = rng.randint(-45, 45)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, bevel_angle_deg, rng.uniform(0.1, 0.3))

    drop_shadow_offset_x = rng.randint(2, mw // 20)
    drop_shadow_offset_y = rng.randint(2, mh // 20)
    drop_shadow_blur = rng.randint(mw // 40, mw // 15)
    drop_shadow_alpha = rng.uniform(64, 192)

    extrude_depth = rng.randint(mw // 80, mw // 30)
    extrude_angle_deg = rng.randint(-45, 45)
    extrude_near_color = (rng.randint(80, 200), rng.randint(80, 192), rng.randint(80, 200))
    extrude_far_color = (rng.randint(64, 192), rng.randint(64, 192), rng.randint(64, 192))

    return composite(text_rgba,
                     glow_rgba,
                     inner_glow_rgba,
                     highlight_rgba,
                     shadow_rgba,
                     drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y, drop_shadow_blur, drop_shadow_alpha),
                     extrude(mask_L, extrude_depth, extrude_angle_deg, extrude_near_color, extrude_far_color),
                     size=(mw, mh))


