def render_comic_v314(title: str, rng: random.Random) -> Image.Image:
    font_role = 'comic'
    mask_L = make_mask(title.upper(), F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    font_color = (rng.randint(0, 255), rng.randint(160, 255), rng.randint(160, 255))
    background_gradient = [(rng.randint(240, 255), rng.randint(240, 255), rng.randint(240, 255)),
                           (rng.randint(180, 240), rng.randint(180, 240), rng.randint(180, 240))]
    glow_color = (rng.randint(160, 255), rng.randint(160, 255), rng.randint(180, 255))
    inner_glow_color = (rng.randint(90, 180), rng.randint(90, 180), rng.randint(90, 180))

    font_size = auto_size(title)
    comic_font = F(font_role, font_size, rng)

    flat_fill = flat_color(mask_L, font_color)
    gradient_fill = colorize(mask_L, background_gradient)
    glow_effect = glow_layer(mask_L, glow_color, [(rng.randint(1, 3), rng.random())])
    inner_glow_effect = inner_glow(mask_L, inner_glow_color, [(rng.randint(2, 4), rng.random()), (rng.randint(5, 8), rng.random() / 2)])

    bevel_angle = rng.uniform(-90, 90)
    bevel_strength = rng.random()
    highlight_effect, shadow_effect = bevel_light(mask_L, bevel_angle, bevel_strength)

    drop_shadow_offset_x = rng.randint(1, mw // 25) * (-1 if rng.getrandbits(1) else 1)
    drop_shadow_offset_y = rng.randint(mw // 30, mw // 18)
    drop_shadow_blur_radius = rng.randint(mw // 40, mw // 30)
    drop_shadow_alpha = int(rng.triangular(60, 255, 200))
    shadow_effect = drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y, drop_shadow_blur_radius, drop_shadow_alpha)

    extrude_depth = rng.randint(mw // 120, mw // 75)
    extrude_angle = (bevel_angle + 90) % 360
    near_color = (rng.randint(0, 80), rng.randint(0, 80), rng.randint(0, 80))
    far_color = (rng.randint(210, 255), rng.randint(210, 255), rng.randint(210, 255))

    extrude_effect = extrude(mask_L, extrude_depth, extrude_angle, near_color, far_color)

    comic_text_layer = apply_mask(flat_fill, mask_L)
    return composite(comic_text_layer, gradient_fill, glow_effect, inner_glow_effect,
                     highlight_effect, shadow_effect, extrude_effect, size=(mw, mh))


