def render_comic_v3266(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('comic', auto_size(title), rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    base_color = flat_color(mask_L, (rng.randint(200, 255), rng.randint(160, 220), rng.randint(180, 255)))
    gradient_fill = colorize(mask_L, [
        (rng.randint(230, 255), rng.randint(200, 240), rng.randint(210, 255)),
        (rng.randint(190, 230), rng.randint(160, 200), rng.randint(180, 220))
    ])

    glow_color = (rng.randint(220, 255), rng.randint(180, 220), rng.randint(200, 240))
    glows = [
        glow_layer(mask_L, glow_color, [(3.0 + rng.random(), 0.9 * rng.random())]),
        inner_glow(mask_L, (rng.randint(240, 255), rng.randint(180, 220), rng.randint(200, 240)), [(1.0 + rng.random() / 3, 0.7 * rng.random())])
    ]

    shadow_angle = 190 - (rng.randint(-30, 30))
    dropshadow = drop_shadow(mask_L, rng.choice([-6, -5, -4]), rng.randint(2, 8), 120 + rng.randint(-30, 30))

    bevel_highlight, bevel_shadow = bevel_light(mask_L, 90 + (rng.randint(-45, 45)), 0.7 * rng.random())

    extrusion_depth = rng.randint(1, 6)
    extrusion_color_near = (250 - rng.randint(0, 50), 180 + rng.randint(0, 30), 200 + rng.randint(-10, 40))
    extrusion_color_far = (rng.randint(150, 200), rng.randint(70, 120), rng.randint(90, 140))

    return composite(base_color, gradient_fill, *glows, dropshadow, bevel_highlight, bevel_shadow,
                     extrude(mask_L, extrusion_depth, 180 + (rng.randint(-30, 30)), extrusion_color_near, extrusion_color_far), size=(mw, mh))


