def render_comic_v3338(title: str, rng: random.Random) -> Image.Image:
    font = F("comic", auto_size(title), rng)
    mask_L = make_mask(title.upper(), font)
    mw, mh = mask_L.size

    # Base color and glow effects
    base_color = flat_color(mask_L, (rng.randint(0, 255), rng.randint(170, 255), rng.randint(0, 255)))
    outer_glow_radii = [(rng.uniform(4.5, 6.5), rng.random() * 0.3 + 0.1)]
    bloom_color = (rng.randint(200, 255), rng.randint(170, 255), rng.randint(180, 255))
    outer_glow = glow_layer(mask_L, bloom_color, radii=outer_glow_radii)

    # Bevel and shadow effects
    bevel_angle_deg = rng.uniform(-30, -60)
    highlight, shadow = bevel_light(mask_L, bevel_angle_deg, strength=rng.random() * 0.7 + 0.2)
    inner_shadow_radius = (rng.randint(1, 4), rng.random())
    drop_shadow_offset_x = rng.choice([-5, -3, 0, 2])
    drop_shadow_offset_y = rng.choice([0, 2, 4])

    # Colorize and extrude effects
    color_stops = [
        (rng.randint(170, 255), rng.randint(80, 160), rng.randint(90, 200)),
        (rng.randint(30, 150), rng.randint(140, 220), rng.randint(200, 255))
    ]
    colored_mask = colorize(mask_L, color_stops)
    extrusion_depth = rng.choice([7, 8])
    near_color = (rng.randint(150, 220), rng.randint(80, 160), rng.randint(90, 200))
    far_color = (rng.randint(30, 150), rng.randint(140, 220), rng.randint(200, 255))

    # Combine all effects
    return composite(base_color, outer_glow, drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y, 7, 96),
                     inner_glow(dilate(mask_L, 1), near_color, [inner_shadow_radius]),
                     extrude(mask_L, extrusion_depth, bevel_angle_deg, near_color, far_color),
                     highlight,
                     shadow,
                     size=(mw, mh))


