def render_comic_v3386(title: str, rng: random.Random) -> Image.Image:
    font_role = 'comic'
    mask_L = make_mask(title.upper(), F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    base_color = flat_color(mask_L, (rng.randint(0, 127), rng.randint(192, 255), rng.randint(0, 255)))
    glow_colors = [(rng.randint(128, 255), rng.randint(128, 255), rng.randint(128, 255)) for _ in range(rng.randint(3, 6))]
    gradient_colorize = colorize(mask_L, glow_colors)
    
    shadow_radius = [(rng.randint(1, 4) + x * 0.25, rng.random()) for x in range(rng.randint(2, 4))]
    dropshadow = drop_shadow(dilate(mask_L, rng.choice([-3, -2, -1, 1])), mw // 8, mh // 8, mw // 32, 64)
    
    highlight_angle = rng.uniform(-50, 50) % 360
    hl_rgba, sh_rgba = bevel_light(mask_L, highlight_angle, 0.3 + rng.random() * 0.7)

    extrusion_depth = rng.randint(2, 8)
    near_rgb = (rng.randint(192, 255),) * 3
    far_rgb = (rng.randint(64, 128),) * 3
    extruded_layer = extrude(mask_L, extrusion_depth, highlight_angle, near_rgb, far_rgb)

    return composite(base_color, gradient_colorize, dropshadow, hl_rgba, sh_rgba, extruded_layer, size=(mw, mh))


