def render_comic_v3446(title: str, rng: random.Random) -> Image.Image:
    mask_L = make_mask(title.upper(), F('comic', 50 + 20 * rng.randint(-1, 1), rng))
    mw, mh = mask_L.size

    base_color = (rng.choice([255, 230]), rng.randrange(70, 190), rng.randrange(100, 240))
    glow_colors = [(base_color[0] - 8 * i, base_color[1], base_color[2]) for i in range(4)]
    inner_glow_radii = [(rng.randint(i + 3, i + 15), rng.random() / 6) for i in (1, 2)]

    base_layer = colorize(mask_L, [base_color])
    glow_layer_1 = glow_layer(dilate(mask_L, 8), (*base_color, 0.7), [(rng.randint(4, 8), 0.2)])
    inner_glow_layer = inner_glow(mask_L, (base_color[0] - 64, base_color[1], base_color[2]), inner_glow_radii)
    bevel_highlight, bevel_shadow = bevel_light(mask_L, rng.randint(30, 75), 0.8 + rng.random() / 10)

    shadow_ox = rng.choice([-6, -4, -2, 2, 4, 6])
    shadow_oy = mw // 6
    shadow_blur = max(mw // 30, 3)
    drop_shadow_layer = drop_shadow(mask_L, shadow_ox, shadow_oy, shadow_blur, 192 + rng.randint(-32, 32))

    return composite(base_layer, glow_layer_1, inner_glow_layer, bevel_highlight, bevel_shadow, drop_shadow_layer, size=(mw, mh))


