def render_comic_v626(title: str, rng: random.Random) -> Image.Image:
    font_role = 'comic'
    mask_L = make_mask(title.upper(), F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    # Gradient background for comic effect
    bg_gradient_stops = [(rng.randint(0, 255), rng.randint(128, 255), rng.randint(0, 196)) for _ in range(rng.randint(2, 4))]
    base_color_img = colorize(mask_L, bg_gradient_stops)

    # Text color and glow effect
    text_rgba = flat_color(mask_L, (rng.randint(0, 180), rng.randint(100, 255), rng.randint(64, 224)))
    glow_radii = [(1 + rng.random() * r, r) for r in range(3)]
    glow_effect = glow_layer(mask_L, (rng.randint(0, 128), rng.randint(96, 255), rng.randint(16, 192)), glow_radii)

    # Inner glow and beveling
    inner_glow_rgba = inner_glow(mask_L, (rng.randint(48, 255), rng.randint(0, 160), rng.randint(32, 224)), [(r + 1.5 * rng.random(), r) for r in range(1, 4)])
    highlight_rgba, shadow_rgba = bevel_light(mask_L, (90 + rng.randint(-18, 18)), 0.7 + rng.random() * 0.3)

    # Drop shadows and extruding
    drop_shadow_effect = drop_shadow(dilate(mask_L, 2), -3 + rng.randint(0, 6), rng.randint(4, 8), int(rng.gauss(50, 15)))
    extrude_depth_angle = (rng.randint(-10, 10), 90 + rng.randint(-10, 10))
    extruded_text = extrude(mask_L, *extrude_depth_angle, (rng.randint(32, 196), rng.randint(48, 255), rng.randint(72, 224)), (rng.randint(0, 128), rng.randint(96, 255), rng.randint(16, 192)))

    return composite(base_color_img, text_rgba, glow_effect, inner_glow_rgba, highlight_rgba, shadow_rgba, drop_shadow_effect, extruded_text, size=(mw, mh))


