def render_comic_v74(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('comic', auto_size(title), rng)
    mask_L = make_mask(title, font, pad=20)
    
    mw, mh = mask_L.size
    
    base_colors = [(158, 94, 63), (237, 201, 175), (255, 242, 228)]
    primary_color = flat_color(mask_L, rng.choice(base_colors))
    
    gradient_stops = [
        (158, 94, 63),
        (237, 201, 175),
        (255, 242, 228)
    ]
    color_gradient = colorize(mask_L, gradient_stops[:rng.randint(2, 6)])
    
    glow_radius = [(rng.uniform(0.5, 1), rng.uniform(0.3, 0.7))]
    glow_effect = glow_layer(mask_L, (255, 204, 0), glow_radius)
    
    inner_glow_effect = inner_glow(mask_L, (255, 204, 0), [(rng.randint(1, 3), rng.uniform(0.2, 0.6))])
    
    shadow_offset_x = rng.choice([-2, -1, 0, 1, 2])
    shadow_offset_y = rng.choice([-2, -1, 0, 1, 2])
    drop_shadow_effect = drop_shadow(mask_L, shadow_offset_x, shadow_offset_y, rng.randint(2, 4), 150)
    
    bevel_angle = rng.uniform(-30, 30)
    bevel_intensity = rng.uniform(0.1, 0.8)
    highlight_color, shadow_color = bevel_light(mask_L, bevel_angle, bevel_intensity)
    
    depth = rng.randint(2, 4)
    near_color = (rng.randint(50, 100), rng.randint(30, 60), rng.randint(20, 40))
    far_color = (rng.randint(150, 200), rng.randint(80, 120), rng.randint(70, 90))
    
    extrusion_effect = extrude(mask_L, depth, bevel_angle, near_color, far_color)
    
    return composite(primary_color, color_gradient, glow_effect, inner_glow_effect, drop_shadow_effect,
                     highlight_color, shadow_color, extrusion_effect, size=(mw, mh))


