def render_denim_washed(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'heavy'
    base_font_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, base_font_size + 10, rng))
    mw, mh = mask_L.size

    # Denim wash gradient colors
    dark_indigo = (47, 53, 62)
    medium_blue = (98, 112, 134)
    light_stonewash = (202, 202, 202)

    # Randomize wash gradient stops
    color_stops = [medium_blue]
    if rng.randint(0, 1):
        color_stops.insert(0, dark_indigo)
    if rng.randint(0, 1):
        color_stops.append(light_stonewash)

    base_rgba = colorize(mask_L, color_stops)

    # Diagonal twill weave pattern
    weave_pattern = np.tile(np.array([[1]*4 + [0]*4] * 2), (mw // 8 + 1, mh // 8 + 1))
    weave_img = Image.fromarray(weave_pattern[:mw, :mh].astype('uint8') * 255)
    woven_rgba = composite(base_rgba, flat_color(mask_L, medium_blue).filter(ImageFilter.CONTOUR), size=(mw, mh))

    # Slight concave bevel for stitch depth
    angle_deg = rng.randint(100, 340)
    strength = rng.uniform(.2, .5)
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, angle_deg, strength)

    # Thin darker outline ring
    outline_color = (67, 79, 98) if rng.randint(0, 1) else (43, 54, 68)
    outline_rgba = glow_layer(dilate(mask_L, 2), outline_color, radii=[(rng.uniform(.5, .8), rng.random() * 1.5)])

    return composite(woven_rgba, highlight_RGBA, shadow_RGBA, outline_rgba, base_rgba, size=(mw, mh))


