def render_diamond_cut(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('elegant', auto_size(title), rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    # Base colorization with near-white gradient
    base_color = [(rng.randint(230, 255), rng.randint(230, 255), rng.randint(230, 255)) for _ in range(rng.randint(2, 6))]
    rgba_img = colorize(mask_L, base_color)

    # High strength bevel light effect
    angle1 = rng.uniform(-45, -135)
    hl1_rgba, sh1_rgba = bevel_light(mask_L, angle1, strength=rng.uniform(4.5, 6))
    rgba_img = composite(rgba_img, apply_mask(hl1_rgba, mask_L), size=(mw, mh))

    # Second high-strength bevel light effect at a different angle
    angle2 = rng.uniform(-45 - 90, -135 - 90)
    hl2_rgba, sh2_rgba = bevel_light(mask_L, angle2, strength=rng.uniform(4.5, 6))
    rgba_img = composite(rgba_img, apply_mask(hl2_rgba, mask_L), size=(mw, mh))

    # Tight bright inner glow
    inner_glow_color = (rng.randint(200, 230), rng.randint(200, 230), rng.randint(200, 230))
    rgba_img = composite(rgba_img, inner_glow(mask_L, inner_glow_color, radii=[(1, 2.5)]), size=(mw, mh))

    # Very dark drop shadow
    rgba_img = composite(rgba_img, drop_shadow(mask_L, mw // 30, mh // 30, mw // 40, 60), size=(mw, mh))
    
    return rgba_img


