# luxury_v708
# ============================================================

def render_glitch_v1027(title: str, rng: random.Random) -> Image.Image:
    font_role = 'tech'
    title_font = F(font_role, auto_size(title, base=300), rng)
    mask_L = make_mask(title.upper(), title_font, pad=rng.randint(15, 45))
    
    mw, mh = mask_L.size
    glitch_shifts = [rng.choice([-2, -1, 0, 1, 2]) for _ in range(mw)]
    glitch_img = Image.new('RGB', (mw + max(glitch_shifts), mh), color='black')
    draw = ImageDraw.Draw(glitch_img)
    
    # Draw the text on a slightly larger canvas
    draw.text((rng.randint(-10, 10), rng.randint(-10, 10)), title.upper(), font=title_font, fill=(255, 255, 255))
    
    # Apply glitch effect by shifting pixels horizontally
    glitch_img = glitch_img.transform(glitch_img.size, Image.AFFINE, (1, 0, 0, 0, 1, 0), resample=Image.BILINEAR)
    for x in range(mw):
        shift = glitch_shifts[x]
        if shift != 0:
            draw.line((x, 0, x, mh - 1), fill=(rng.randint(0, 255), rng.randint(0, 255), rng.randint(0, 255)), width=abs(shift))
    
    glitch_img = glitch_img.crop((0, 0, mw, mh))  # Crop to original size
    
    # Apply colorization and effects
    flat_color_fill = flat_color(mask_L, (rng.randint(64, 192), rng.randint(64, 192), rng.randint(64, 192)))
    
    glow_effect = glow_layer(mask_L, (rng.randint(0, 255), rng.randint(0, 255), rng.randint(0, 255)), radii=[(3 + rng.random(), 0.8)])
    inner_glow_effect = inner_glow(mask_L, (rng.randint(64, 192), rng.randint(64, 192), rng.randint(64, 192)), radii=[(2 + rng.random() * 3, 0.5)])
    
    # Combine layers
    base_layer = apply_mask(glitch_img.convert("RGBA"), mask_L)
    final_image = composite(base_layer, flat_color_fill, glow_effect, inner_glow_effect, size=(mw, mh))
    
    return final_image


# ============================================================
# gradient_v1028
# ============================================================

def render_glitch_v1087(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('tech', auto_size(title), rng)
    mask_L = make_mask(title, font)

    mw, mh = mask_L.size

    # Base color gradient
    colors = [(rng.randint(0, 255), rng.randint(128, 255), rng.randint(0, 127)),
              (rng.randint(0, 255), rng.randint(128, 255), rng.randint(0, 127))]
    base_gradient = colorize(mask_L, colors)

    # Glitch effect - random horizontal offsets
    offset_x = [rng.randint(-mw // 16, mw // 16) for _ in range(rng.randint(3, 8))]

    glitch_layers = []
    for x in offset_x:
        shifted_mask = mask_L.transform((mw, mh), Image.AFFINE, (1, 0, x, 0, 1, 0))
        glitch_layers.append(flat_color(shifted_mask, colors[0]))

    # Apply random noise and distortion
    noise_level = rng.randint(5, 20)
    distorted_mask = mask_L.filter(ImageFilter.GaussianBlur(noise_level))

    # Glitch inner glow effect
    glow_colors = [(rng.randint(128, 255), rng.randint(0, 64), rng.randint(0, 192)),
                   (rng.randint(128, 255), rng.randint(0, 64), rng.randint(0, 192))]
    inner_glow_layer = inner_glow(distorted_mask, glow_colors[0], [(3 + rng.random(), 1.2 + rng.random() * 2)])

    # Drop shadow with random intensity
    drop_shadow_int = rng.randint(5, 15)
    drop_shadow_angle_x = rng.randint(-mw // 8, mw // 8)
    drop_shadow_layer = drop_shadow(mask_L, drop_shadow_angle_x, drop_shadow_int, rng.randint(64, 200))

    # Combine all layers
    composite_layers = [base_gradient] + glitch_layers + [inner_glow_layer, drop_shadow_layer]
    
    return composite(*composite_layers, size=(mw, mh))


