def render_glitch_v1123(title: str, rng: random.Random) -> Image.Image:
    mask_L = make_mask(title.upper(), F('tech', auto_size(title), rng))
    mw, mh = mask_L.size

    base_colors = [(0x95, 0xf7, 0xff), (0x4c, 0x83, 0xbf), (0x1b, 0x2d, 0x68)]
    glitch_colors = [(rng.randint(0, 255), rng.randint(0, 255), rng.randint(0, 255)) for _ in range(rng.randint(3, 6))]
    text_color = flat_color(mask_L, rng.choice(base_colors))
    
    # Text glow and shadow
    glow_radius = [(rng.uniform(.1, .5), rng.uniform(.3, .7)) for _ in range(2)]
    glow_shadow = drop_shadow(mask_L, mw//40, mh//40, mw//60, 192)
    
    # Digital distortion effects
    glitch_layers = [glow_layer(mask_L, color, [(rng.uniform(.3, .5), rng.uniform(.4, .8))]) for color in glitch_colors]
    distorted_text = composite(text_color, *glitch_layers, size=(mw, mh))
    
    # Final composition with mask and shadow
    return apply_mask(composite(distorted_text, glow_shadow, size=(mw, mh)), dilate(mask_L, mw//100))


