def render_glitch_v1171(title: str, rng: random.Random) -> Image.Image:
    font = F('tech', auto_size(title), rng)
    mask_L = make_mask(title.upper(), font)
    mw, mh = mask_L.size

    base_rgba = flat_color(mask_L, (rng.randint(0, 63), rng.randint(128, 255), rng.randint(64, 192)))
    glitch_stripes = np.array(base_rgba).repeat(rng.randint(2, 4), axis=0)
    np.random.shuffle(glitch_stripes[::rng.randint(2, mw // 32)])
    glitch_layer = Image.fromarray(glitch_stripes)

    color_stops = [(rng.randint(0, 192), rng.randint(64, 255), rng.randint(0, 192)) for _ in range(rng.randint(2, 5))]
    gradient_rgba = colorize(mask_L, color_stops)
    
    glow_radii = [(rng.uniform(.5, .7), rng.randint(3, mw // 64)), (rng.uniform(.1, .3), rng.randint(mw // 128, mw // 64))]
    outer_bloom = glow_layer(mask_L, (0, rng.randint(64, 192), rng.randint(0, 127)), radii=glow_radii)
    
    bevel_angle = rng.uniform(-3.14, 3.14)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, bevel_angle, rng.random())
    
    drop_shadow_layer = drop_shadow(mask_L, mw // 64, mh // 8, mw // 256, 192)

    depth = rng.randint(mw // 32, mw // 16)
    extrude_col_near = (rng.randint(0, 127), rng.randint(64, 192), rng.randint(0, 128))
    extrude_col_far = (rng.randint(0, 63), rng.randint(128, 255), rng.randint(64, 192))
    extrusion_layer = extrude(mask_L, depth, bevel_angle + 3.14 / 4, extrude_col_near, extrude_col_far)
    
    return composite(base_rgba, gradient_rgba, outer_bloom, highlight_rgba, shadow_rgba, drop_shadow_layer, glitch_layer, extrusion_layer, size=(mw, mh))


