def render_glitch_v1303(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = ["tech"]
    font_size = auto_size(title)
    mask_L = make_mask(title, F(rng.choice(font_role), font_size, rng))
    mw, mh = mask_L.size

    bg_color = (rng.randint(0, 63), rng.randint(128, 191), rng.randint(254, 255))
    fg_color = (rng.randint(192, 255), rng.randint(64, 127), rng.randint(0, 63))

    bg_img = flat_color(mask_L, bg_color)
    fg_img = flat_color(mask_L, fg_color)

    glow_radii = [(int(rng.gauss(1, 0.5)), float(rng.uniform(1, 2))) for _ in range(rng.randint(2, 4))]
    glow_img = glow_layer(mask_L, (rng.randint(64, 191), rng.randint(0, 63), rng.randint(0, 63)), glow_radii)

    inner_glow_radii = [(int(rng.gauss(0.5, 0.2)), float(rng.uniform(0.5, 1))) for _ in range(rng.randint(2, 4))]
    inner_glow_img = inner_glow(mask_L, (rng.randint(64, 191), rng.randint(0, 63), rng.randint(0, 63)), inner_glow_radii)

    bevel_angle = rng.uniform(0, 359)
    bevel_strength = rng.uniform(0.2, 0.8)
    highlight_img, shadow_img = bevel_light(mask_L, bevel_angle, bevel_strength)

    shadow_offset_x = rng.randint(-1, 1)
    shadow_offset_y = rng.randint(-1, 1)
    blur_radius = int(rng.gauss(3, 1))
    alpha_level = int(rng.uniform(64, 127))
    drop_shadow_img = drop_shadow(mask_L, shadow_offset_x, shadow_offset_y, blur_radius, alpha_level)

    extrude_depth = rng.randint(-2, 2)
    angle_deg = rng.uniform(0, 359)
    near_color = (rng.randint(64, 191), rng.randint(0, 63), rng.randint(0, 63))
    far_color = (rng.randint(0, 63), rng.randint(128, 191), rng.randint(254, 255))
    extrude_img = extrude(mask_L, extrude_depth, angle_deg, near_color, far_color)

    glitch_effect = composite(bg_img, fg_img, glow_img, inner_glow_img, highlight_img, shadow_img, drop_shadow_img, extrude_img, size=(mw, mh))

    return glitch_effect


