def render_glitch_v1423(title: str, rng: random.Random) -> Image.Image:
    font = F('tech', auto_size(title), rng)
    mask_L = make_mask(title.upper(), font)
    mw, mh = mask_L.size

    # Base text color and overlay glitch effects
    base_color = flat_color(mask_L, (rng.randint(50, 150), rng.randint(200, 250), rng.randint(50, 150)))
    glitch_overlay = glow_layer(mask_L, (rng.randint(0, 255), rng.randint(0, 64), rng.randint(192, 255)), [(3.0 + mw / 100.0 * rng.random(), mw / 180.0 * rng.random())])

    # Apply glitch effect with distortion
    distorted_mask = mask_L.filter(ImageFilter.GaussianBlur(rng.uniform(0, mh / 40)))
    distorted_text = flat_color(distorted_mask, (rng.randint(0, 255), rng.randint(192, 255), rng.randint(64, 128)))

    # Add noise and color shifts
    noise_level = int(mh * rng.uniform(0.02, 0.1))
    noisy_text = flat_color(mask_L.filter(ImageFilter.GaussianBlur(noise_level)), (rng.randint(0, 96), rng.randint(128, 255), rng.randint(160, 255)))

    # Combine base text with glitch effects
    combined_glitch_effect = composite(base_color, distorted_text, noisy_text, size=(mw, mh))

    # Final drop shadow and bevel highlights
    final_shadow = drop_shadow(mask_L, mw // 30, mh // 40, int(mw * rng.uniform(0.25, 0.75)), int(rng.randint(64, 192)))
    highlight_and_shadow = composite(combined_glitch_effect, *bevel_light(mask_L, angle_deg=rng.randint(-180, 180), strength=0.3 + mw / 400.0), size=(mw, mh))

    # Final output
    return composite(highlight_and_shadow, final_shadow, size=(mw, mh))


