    shadow_offset_x = rng.randint(-mh // 4, mw // 3)
    shadow_offset_y = rng.randint(mh // 5, mw // 2)
    shadow_blur_radius = rng.randint(10, mw // 6)
    shadow_alpha = rng.randint(80, 255)
    drop_shadow_rgba = drop_shadow(mask_L, shadow_offset_x, shadow_offset_y,
                                    shadow_blur_radius, shadow_alpha)

    bevel_angle_deg = rng.uniform(-30.0, 30.0)
    bevel_strength = rng.random() / 4
    highlight_rgba, shadow_rgba = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    extrude_depth = rng.randint(1, mh // 8)
    extrude_angle_deg = rng.uniform(-25.0, 25.0)
    extrude_near_col = (rng.randint(60, 190), rng.randint(70, 200), rng.randint(80, 210))
    extrude_far_col = (rng.randint(40, 170), rng.randint(50, 190), rng.randint(60, 180))
    extrusion_rgba = extrude(mask_L, extrude_depth, extrude_angle_deg,
                              extrude_near_col, extrude_far_col)

    return composite(base_rgba, glitch_rgba, glow_rgba, inner_glow_rgba, drop_shadow_rgba,
                     highlight_rgba, shadow_rgba, extrusion_rgba, size=(mw, mh))


