def render_glitch_v1675(title: str, rng: random.Random) -> Image.Image:
    font = F('tech', auto_size(title), rng)
    mask_L = make_mask(title.upper(), font)
    mw, mh = mask_L.size

    base_color = flat_color(mask_L, (rng.randint(0, 255), rng.randint(0, 128), rng.randint(0, 64)))
    glitch_gradient = colorize(mask_L, [(rng.randint(32, 96), rng.randint(0, 255), rng.randint(128, 224)),
                                         (rng.randint(0, 127), rng.randint(128, 255), rng.randint(0, 127))])

    glow = glow_layer(mask_L, (rng.randint(64, 192), rng.randint(32, 128), rng.randint(0, 64)), [(2.0, 0.2)])
    inner_glow_effect = inner_glow(mask_L, (rng.randint(128, 255), rng.randint(64, 192), rng.randint(32, 127)), [(1.0, 0.1)])

    shadow_angle = rng.uniform(-180, 180)
    drop_shadow_effect = drop_shadow(mask_L, int(rng.gauss(mw / 5, mw / 10)), int(rng.gauss(mh / 6, mh / 12)), int(rng.gauss(4.0, 2.0)), rng.randint(32, 96))

    bevel_angle = shadow_angle + 45
    highlight, shadow = bevel_light(mask_L, bevel_angle % 360, rng.uniform(0.1, 0.8))
    extrusion_depth = int(rng.gauss(mw / 20, mw / 40))
    extrusion_effect = extrude(mask_L, extrusion_depth, bevel_angle, (rng.randint(192, 255), rng.randint(160, 224), rng.randint(128, 192)), (rng.randint(32, 127), rng.randint(0, 64), rng.randint(0, 32)))

    # Combine layers with randomness in order and opacity
    layers = [base_color, glitch_gradient, glow, inner_glow_effect, drop_shadow_effect, highlight, shadow, extrusion_effect]
    rng.shuffle(layers)

    return composite(*layers, size=(mw, mh))


