def render_glitch_v1747(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F("tech", auto_size(title), rng)
    mask_L = make_mask(title, font)

    mw, mh = mask_L.size

    # Apply glitch effect
    glitches = [flat_color(mask_L, (rng.randint(0, 255), rng.randint(160, 255), rng.randint(0, 160))) for _ in range(rng.randint(3, 7))]
    glitch_layers = [glitches[rng.randint(0, len(glitches)-1)].filter(ImageFilter.GaussianBlur(radius=rng.random())) for _ in range(rng.randint(1, 4))]

    # Add color overlay
    colors = [(rng.randint(0, 255), rng.randint(64, 192), rng.randint(0, 128)), (rng.randint(32, 128), rng.randint(0, 255), rng.randint(0, 128))]
    color_layer = colorize(mask_L, colors)

    # Apply bevel and inner glow effects
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, angle_deg=rng.uniform(-45.0, 45.0), strength=rng.random())
    inner_glow_layer = inner_glow(mask_L, (rng.randint(64, 128), rng.randint(64, 192), rng.randint(32, 128)), [(i * 0.1 + 1, i * 0.05) for i in range(rng.randint(3, 7))])

    # Combine layers
    return composite(
        *[glitch_layer for glitch_layer in glitch_layers],
        apply_mask(color_layer, mask_L),
        inner_glow_layer,
        highlight_RGBA,
        shadow_RGBA,
        size=(mw, mh)
    )


