def render_glitch_v1831(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('tech', auto_size(title), rng)
    mask_L = make_mask(title, font, pad=40)
    mw, mh = mask_L.size

    base_color = (rng.randint(32, 64), rng.randint(96, 128), rng.randint(192, 224))
    accent_color_1 = (rng.randint(0, 127), rng.randint(128, 255), rng.randint(0, 255))
    accent_color_2 = (rng.randint(0, 127), rng.randint(0, 63), rng.randint(192, 255))

    base_fill = flat_color(mask_L, base_color)
    glitch_strips = []
    for i in range(rng.randint(4, 8)):
        pos_y = rng.randint(0, mh-1)
        strip_width = rng.randint(3, 7)
        for j in range(strip_width):
            color_shift = (rng.randint(-5, 5), rng.randint(-5, 5), rng.randint(-5, 5))
            shifted_color = tuple(c + s for c, s in zip(base_color, color_shift))
            strip_img = flat_color(mask_L, shifted_color)
            glitch_strips.append(strip_img)

    glitched_base = composite(*glitch_strips, size=(mw, mh))

    glow_radius_1 = (rng.uniform(0.2, 0.4), rng.uniform(0.6, 1))
    glow_radius_2 = (rng.uniform(0.8, 1.5), rng.uniform(1.5, 2.5))
    glow_outer = glow_layer(mask_L, accent_color_1, radii=[glow_radius_1, glow_radius_2])
    
    bevel_angle_deg = rng.randint(-45, -30)
    bevel_strength = rng.random() / 8
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    final_layer = composite(base_fill, glitched_base, glow_outer, highlight_RGBA, shadow_RGBA, size=(mw, mh))
    
    return final_layer


