def render_glitch_v2011(title: str, rng: random.Random) -> Image.Image:
    font_role = 'tech'
    title = title.upper()
    base_font_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, base_font_size, rng))
    mw, mh = mask_L.size

    # Randomize color stops and glitch effects
    colors = [(rng.randint(0, 255), rng.randint(160, 255), rng.randint(0, 180)),
              (rng.randint(140, 255), rng.randint(170, 255), rng.randint(130, 255))]

    glow_radii = [(int(rng.gauss(6, 2)), float(rng.uniform(0.1, 0.3))) for _ in range(4)]
    inner_glow_radii = [(int(rng.gauss(1, 2)), float(rng.uniform(0.3, 0.5))) for _ in range(3)]

    shadow_offset_x = rng.randint(-6, 6)
    shadow_offset_y = rng.randint(8, 14)
    shadow_blur = int(rng.gauss(7, 2))
    shadow_alpha = int(rng.uniform(64, 192))

    extrude_depth = rng.randint(3, 5)
    extrude_angle = rng.randint(-30, 30)

    # Text colorization
    text_colorized = colorize(mask_L, colors)
    text_glow = glow_layer(mask_L, (rng.randint(64, 192), rng.randint(128, 255), rng.randint(128, 255)), glow_radii)

    # Inner glows
    inner_color = (rng.randint(0, 128), rng.randint(128, 255), rng.randint(128, 255))
    text_inner_glow = inner_glow(mask_L, inner_color, inner_glow_radii)

    # Shadow effect
    drop_shadow_layer = drop_shadow(mask_L, shadow_offset_x, shadow_offset_y, shadow_blur, shadow_alpha)
    
    # Extrusion for depth and dimensionality
    extrude_color_near = (rng.randint(128, 255), rng.randint(64, 192), rng.randint(64, 192))
    extrude_color_far = (rng.randint(32, 128), rng.randint(0, 64), rng.randint(0, 64))
    text_extruded = extrude(mask_L, extrude_depth, extrude_angle, extrude_color_near, extrude_color_far)

    # Composite all layers
    return composite(text_colorized, text_glow, text_inner_glow, drop_shadow_layer, text_extruded, size=(mw, mh))


