def render_glitch_v2143(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('tech', auto_size(title), rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    base_color = (rng.randint(0, 128), rng.randint(64, 192), rng.randint(32, 255))
    glow_colors = [(base_color[0] + i * 32 % 128, base_color[1], base_color[2]) for i in range(-1, 2)]
    inner_glow_color = (rng.randint(64, 192), rng.randint(32, 128), rng.randint(0, 64))
    shadow_off_x = rng.choice([-2, -1, 1, 2])
    shadow_off_y = rng.choice([0, 1, 2])

    base_layer = flat_color(mask_L, base_color)
    glow_layer_img = glow_layer(mask_L, (base_color[0] + 32, base_color[1], base_color[2]), [(mh // 4, .5), (mw // 8, .2)])
    inner_glow_layer_img = inner_glow(mask_L, inner_glow_color, [(mw // 8, .7), (mw // 6, .3)])
    shadow_layer_img = drop_shadow(dilate(mask_L, 1), shadow_off_x, shadow_off_y, mw // 40, 255)

    glitch_stripes = []
    for i in range(rng.randint(1, 3)):
        stripe_width = rng.randint(mw // 8, mw // 6)
        start_x = rng.randint(-stripe_width * 2, mw + stripe_width * 2)
        end_x = start_x + stripe_width
        stripe_color = (rng.randint(0, 255), rng.randint(0, 255), rng.randint(0, 255))
        glitch_stripes.append((start_x % mw, (end_x - start_x) % mw, stripe_color))

    for x_start, length, color in glitch_stripes:
        stripe_mask = mask_L.crop((x_start, 0, x_start + length, mh))
        stripe_img = flat_color(stripe_mask, color)
        base_layer = composite(base_layer, apply_mask(stripe_img, stripe_mask), size=(mw, mh))

    return composite(base_layer, glow_layer_img, inner_glow_layer_img, shadow_layer_img, size=(mw, mh))


