    inner_glow_effect = inner_glow(mask_L, tuple(rng.choice(glow_colors)), [(mw // 8 + rng.randint(-2, 2), mw // 16)])

    return composite(extruded_text, glow_rgba, bevel_hl, bevel_sh, drop_shdw, glitch_effect, text_rgba, inner_glow_effect, size=(mw, mh))


