    glow_radii = [(rng.uniform(0.3, 0.7) * mw / mh, 0.4 + rng.random() * 2)]
    inner_glow_color = (rng.randint(64, 192), rng.randint(128, 255), rng.randint(0, 192))
    inner_glow_radii = [(rng.uniform(0.3, 0.7) * mw / mh, 0.2 + rng.random())]
    bevel_angle_deg = rng.uniform(-45, 45)
    bevel_strength = rng.uniform(0.8, 1.6)

    base_layer = flat_color(mask_L, base_color)
    glow_layer_img = glow_layer(mask_L, (rng.randint(255, 255), rng.randint(0, 32), rng.randint(0, 64)), glow_radii)
    inner_glow_layer_img = inner_glow(mask_L, inner_glow_color, inner_glow_radii)

    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    glitch_effect = np.array(base_layer).astype(float) / 255
    for _ in range(rng.randint(3, 6)):
        start_y = rng.randint(-mw // 10, mw)
        end_y = (start_y + rng.randint(mw // 8, mw // 4)) % mw
        amount = rng.uniform(0.1, 0.5)
        glitch_effect[:, start_y:end_y] *= rng.uniform(0.2, 0.6)

    glitch_layer = Image.fromarray((glitch_effect * 255).astype(np.uint8)).convert('RGBA')

    return composite(base_layer, glow_layer_img, inner_glow_layer_img, highlight_RGBA, shadow_RGBA, glitch_layer, size=(mw, mh))


