def render_glitch_v2995(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('tech', auto_size(title), rng)
    mask_L = make_mask(title, font)

    mw, mh = mask_L.size

    # Text color
    primary_color = (rng.randint(0, 255), rng.randint(100, 255), rng.randint(0, 255))
    
    # Random glitch effect: colorize with a random gradient and add some glow
    gradient_stops = [(primary_color[0], primary_color[1] + 64 * i // mh, primary_color[2]) for i in range(mh)]
    if rng.randint(0, 1):
        gradient_stops.reverse()
    
    base_text = colorize(mask_L, gradient_stops)
    glow_rad = [(rng.uniform(.5, 3), rng.random())]
    glow_effect = glow_layer(mask_L, (255, 255, 255), radii=glow_rad)

    # Inner glow effect for depth
    inner_glow_rad = [(0.8 * r[0], r[1] ** 4) for r in glow_rad]
    inner_glow_effect = inner_glow(mask_L, (64, 64, 64), radii=inner_glow_rad)

    # Combine base text with glow effects
    text_with_effects = composite(base_text, glow_effect, size=(mw, mh))
    
    # Add some random color bleeding and distortion for glitch effect
    bleed_strength = rng.randint(10, mw // 2)
    distorted_mask_L = mask_L.filter(ImageFilter.GaussianBlur(bleed_strength)).convert('L')
    bleed_color = (rng.randint(0, 127), rng.randint(128, 255), rng.randint(64, 192))
    bleed_effect = flat_color(distorted_mask_L, bleed_color)

    # Combine text with glitch effect
    final_text_with_glitch = composite(text_with_effects, bleed_effect, size=(mw, mh))

    return final_text_with_glitch


