def render_glitch_v319(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('tech', auto_size(title), rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    base_color = (rng.randint(0, 75), rng.randint(150, 225), rng.randint(80, 160))
    glow_radius = [(rng.uniform(.4, .6) * mw, rng.uniform(.3, .4))]
    inner_glow_radius = [(rng.uniform(.1, .3) * mw, rng.uniform(.1, .2)), (rng.uniform(-.25, -.1), rng.uniform(.05, .1))]

    base_img = flat_color(mask_L, base_color)
    glow_layer_1 = glow_layer(mask_L, base_color, radii=glow_radius)
    inner_glow_layer = inner_glow(mask_L, (rng.randint(200, 230), rng.randint(50, 80), rng.randint(100, 140)), radii=inner_glow_radius)

    # Add horizontal and vertical glitches
    glitch_w, glitch_h = mw // 4, mh // 4
    for i in range(rng.randint(2, 6)):
        x_offset = rng.choice([-glitch_w, glitch_w])
        y_offset = rng.choice([-glitch_h, glitch_h])
        glitched_img = base_img.copy()
        glitched_img.paste(glow_layer_1.crop((x_offset, y_offset, mw + x_offset, mh + y_offset)), (0, 0))
        glow_layer_1 = glitched_img

    # Add a drop shadow with random parameters
    dx = rng.randint(-2, 2)
    dy = rng.randint(-2, 2)
    blur_radius = rng.randint(4, 8)
    alpha_level = rng.randint(64, 192)

    final_shadow = drop_shadow(mask_L, dx, dy, blur_radius, alpha_level)

    # Combine layers with random order for variation
    return composite(final_shadow, glow_layer_1, inner_glow_layer, base_img, size=(mw, mh))


