def render_glitch_v835(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = ["tech", "retro", "stark"][rng.randint(0, 2)]
    base_font_size = auto_size(title)
    font_size = rng.randint(int(base_font_size * 0.8), int(base_font_size * 1.2))
    font = F(font_role, size=font_size, rng=rng)

    mask_L = make_mask(title, font, pad=int(rng.gauss(40, 5)))
    mw, mh = mask_L.size

    colors = [(rng.randint(30, 150), rng.randint(90, 200), rng.randint(80, 210)),
              (rng.randint(60, 200), rng.randint(40, 170), rng.randint(50, 180))]

    solid_fill = flat_color(mask_L, colors[0])
    gradient_fill = colorize(mask_L, [colors[0], colors[1]])

    glow_radii = [(rng.uniform(1.2, 3.0), rng.uniform(0.2, 0.6))]
    glow_layer_rgba = glow_layer(mask_L, colors[0], glow_radii)

    inner_glow_radii = [(rng.uniform(0.5, 1.5), rng.uniform(0.1, 0.4)),
                        (rng.uniform(1.8, 3.2), rng.uniform(0.3, 0.7))]
    inner_glow_layer_rgba = inner_glow(mask_L, colors[1], inner_glow_radii)

    angle_deg = rng.randint(-60, 60)
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, angle_deg, strength=rng.uniform(0.2, 0.5))

    ox_int = int(rng.gauss(mw / 8, mw / 16))
    oy_int = int(rng.gauss(mh / 8, mh / 16))
    blur_int = int(rng.gauss(int(mw * 0.05), int(mw * 0.02)))
    alpha_0to255 = rng.randint(40, 160)
    shadow_layer_rgba = drop_shadow(mask_L, ox_int, oy_int, blur_int, alpha_0to255)

    depth_int = int(rng.gauss(int(mw * 0.03), int(mw * 0.01)))
    angle_deg = rng.randint(-45, 45)
    col_near_rgb = colors[0]
    col_far_rgb = colors[1]
    extrusion_layer_rgba = extrude(mask_L, depth_int, angle_deg, col_near_rgb, col_far_rgb)

    return composite(solid_fill, gradient_fill, glow_layer_rgba,
                     inner_glow_layer_rgba, highlight_RGBA, shadow_RGBA,
                     shadow_layer_rgba, extrusion_layer_rgba, size=(mw, mh))


