    # Create an inner glow
    rim_color = (rng.randint(100, 255), rng.randint(100, 255), rng.randint(100, 255))
    inner_glow_RGBA = inner_glow(mask_L, rim_color, radii=[(1.5 + rng.random(), 1.5 + rng.random())])

    # Apply bevel lighting
    highlight, shadow = bevel_light(mask_L, rng.randint(-45, 45), rng.uniform(0.3, 1.2))
    bevel_RGBA = composite(highlight, shadow, size=(mw, mh))

    return composite(gradient_RGBA, bloom_RGBA, inner_glow_RGBA, bevel_RGBA, size=(mw, mh))


