    shadow_y_offset = rng.randint(6, 9)

    extrude_depth = rng.randint(2, 4)
    extrude_angle = rng.randint(30, 60)
    extrude_near_color = (rng.randint(150, 200), rng.randint(150, 200), rng.randint(150, 200))
    extrude_far_color = (rng.randint(80, 120), rng.randint(80, 120), rng.randint(200, 230))

