    drop_shadow_effect = drop_shadow(dilate(mask_L, 3), shadow_x_offset, shadow_y_offset, 8, 64)

    # Extrusion effect for a physical look
    extrude_effect = extrude(mask_L, extrude_depth, extrude_angle, extrude_near_color, extrude_far_color)

