def render_gradient_v404(title: str, rng: random.Random) -> Image.Image:
    mask_L = make_mask(title.upper(), F('heavy', auto_size(title), rng))
    mw, mh = mask_L.size

    base_colors = [(255, 69, 0), (0, 191, 255), (255, 140, 0)]
    colors_stops = [base_colors[rng.randint(0, len(base_colors)-1)] for _ in range(rng.randint(2, 3))]
    
    gradient_img = colorize(mask_L, colors_stops)
    
    glow_radii = [(rng.uniform(5, mh/8), rng.uniform(0.2, 0.6)) for _ in range(rng.randint(1, 2))]
    glow_img = glow_layer(mask_L, (rng.randint(0, 255) if rng.random() < 0.7 else 0,
                                   rng.randint(0, 255) if rng.random() < 0.7 else 0,
                                   rng.randint(0, 255)), glow_radii)

    inner_glow_img = inner_glow(mask_L, (rng.randint(0, 128), rng.randint(64, 255), rng.randint(0, 192)),
                                [(rng.uniform(mw/32, mw/8), rng.uniform(0.2, 0.7)) for _ in range(rng.randint(2, 4))])

    shadow_img = drop_shadow(mask_L, rng.randint(-mw//6, mw//6),
                             rng.randint(-mh//12, mh//12), rng.randint(mh//32, mh//8), rng.randint(50, 200))

    bevel_angle = rng.uniform(0, 360)
    highlight_img, shadow_img_bevel = bevel_light(mask_L, bevel_angle, rng.random() * 1.5 + 0.5)

    extrusion_depth = rng.randint(-mw//8, mw//4)
    extrusion_col_near = (rng.randint(0, 255), rng.randint(64, 255), rng.randint(0, 255))
    extrusion_col_far = (rng.randint(128, 255) if rng.random() < 0.7 else 0,
                         rng.randint(32, 224) if rng.random() < 0.6 else 0,
                         rng.randint(192, 255) if rng.random() < 0.6 else 0)
    extrusion_img = extrude(mask_L, extrusion_depth, bevel_angle + 180, extrusion_col_near, extrusion_col_far)

    return composite(extrusion_img, glow_img, inner_glow_img, shadow_img_bevel, gradient_img, shadow_img, size=(mw, mh))


