    extrusion_depth = int(rng.uniform(4, mh / 15))
    light_color = (rng.randint(220, 255), rng.randint(220, 255), rng.randint(220, 255))
    dark_color = (rng.randint(80, 160), rng.randint(80, 160), rng.randint(80, 160))
    extruded_text = extrude(mask_L, extrusion_depth, bevel_angle_deg + 90, light_color, dark_color)

    return composite(extruded_text, gradient, outer_glow, rim_light, shadow, drop_shadow_effect, highlight, size=(mw, mh))


