def render_horror_v1098(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('heavy', auto_size(title), rng)
    mask_L = make_mask(title, font, pad=45)
    
    mw, mh = mask_L.size
    drip_color = (rng.randint(0, 63), rng.randint(192, 255), rng.randint(128, 255))
    background_color = (rng.randint(0, 63), rng.randint(0, 63), rng.randint(32, 96))
    
    # Dripping effect
    dripping_mask_L = mask_L.filter(ImageFilter.GaussianBlur(rng.uniform(1.5, mh / 7)))
    dripping_img_RGBA = flat_color(dripping_mask_L, drip_color)
    
    # Base color and inner glow
    base_color = (rng.randint(0, 63), rng.randint(0, 64), rng.randint(0, 96))
    inner_glow_img_RGBA = inner_glow(mask_L, base_color, [(1 + rng.random() * 2.5, 1)])
    
    # Background
    bg_img_RGBA = flat_color(dilate(mask_L, 3), background_color)
    
    # Corrupting effect
    corrupt_mask_L = mask_L.filter(ImageFilter.GaussianBlur(rng.uniform(0.5, mh / 14)))
    corrupt_glow_RGBA = glow_layer(corrupt_mask_L, (rng.randint(64, 96), rng.randint(32, 64), rng.randint(0, 32)), [(rng.random() * 1.5 + 1, 1)])
    
    # Rotting effect
    rot_glow_RGBA = inner_glow(mask_L, (rng.randint(0, 64), rng.randint(0, 96), rng.randint(0, 32)), [(rng.uniform(0.5, 1) + rng.random(), 1)])
    
    # Composite all layers
    return composite(bg_img_RGBA,
                     dripping_img_RGBA,
                     inner_glow_img_RGBA,
                     corrupt_glow_RGBA,
                     rot_glow_RGBA,
                     apply_mask(colorize(mask_L, [base_color, (rng.randint(0, 64), rng.randint(32, 128), rng.randint(0, 96))]), mask_L),
                     size=(mw, mh))


