    text_img = flat_color(mask_L, base_text_color)

    # Corrupt and drip effects
    corrupted_mask = dilate(mask_L, rng.randint(-5, -3)).filter(ImageFilter.BLUR)
    corruption_color = (rng.randint(20, 60), rng.randint(15, 40), rng.randint(70, 90))
    corruption_layer = flat_color(corrupted_mask, corruption_color)

    # Drip effect
    drip_start = rng.choice([(mw // 4, mh // 2), (3 * mw // 4, mh // 2)])
    drip_end = (drip_start[0], rng.randint(int(mh * 1.5), int(mh * 2)))
    drip_mask = Image.new('L', (mw, mh + 50))
    ImageDraw.Draw(drip_mask).line([drip_start, drip_end], fill=255, width=rng.randint(3, 5))
    drip_mask = drip_mask.crop((0, -1 * (mh // 2), mw, mh)).filter(ImageFilter.BLUR)
