    inner_glow_layer = inner_glow(mask_L, base_text_color, inner_glow_radius)
    outer_glow_radius = [(rng.uniform(10, 12), rng.random()), (rng.uniform(15, 18), rng.random())]
    outer_glow_layer = glow_layer(mask_L, base_text_color, outer_glow_radius)

    # Bevel light
