def render_horror_v1710(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = "heavy"
    base_font_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, base_font_size, rng))
    mw, mh = mask_L.size

    # Randomize parameters
    glow_radius = [(rng.randint(10, 25), rng.uniform(0.3, 0.7))]
    inner_glow_radius = [(rng.randint(5, 15), rng.uniform(0.4, 0.6)), (rng.randint(1, 4), rng.uniform(0.8, 1.0))]
    bevel_angle_deg = rng.randint(320, 350)
    bevel_strength = rng.uniform(0.2, 0.4)
    shadow_offset_x = rng.choice([-5, -4, -3, 3, 4, 5])
    shadow_offset_y = rng.choice([1, 2, 3])
    shadow_blur_radius = rng.randint(8, 15)
    shadow_alpha_0to255 = int(rng.uniform(60, 100))
    extrude_depth = rng.randint(4, 7)
    extrude_angle_deg = rng.randint(300, 359)

    # Create base text color
    primary_color = (rng.randint(50, 80), rng.randint(20, 60), rng.randint(150, 180))
    rgba_primary = flat_color(mask_L, primary_color)
    
    # Add glow effect
    glow_rgba = glow_layer(mask_L, primary_color, radii=glow_radius)

    # Inner glow to give an eerie feel
    inner_glow_rgba = inner_glow(mask_L, primary_color, radii=inner_glow_radius)

    # Bevel and shadows for depth and realism
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, bevel_angle_deg, bevel_strength)
    
    # Drop shadow for a haunting effect
    drop_shadow_rgba = drop_shadow(dilate(mask_L, 2), shadow_offset_x, shadow_offset_y, shadow_blur_radius, shadow_alpha_0to255)

    # Extrude to add physical depth and mystery
    extruded_rgba = extrude(mask_L, extrude_depth, extrude_angle_deg, (rng.randint(40, 60), rng.randint(30, 50), rng.randint(180, 200)), primary_color)

    # Composite all layers for the final effect
    return composite(
        apply_mask(extruded_rgba, mask_L),
        glow_rgba,
        inner_glow_rgba,
        highlight_RGBA,
        shadow_RGBA,
        drop_shadow_rgba,
        size=(mw, mh)
    )


