    outer_glow_radii = [(rng.randint(20, 30) / mh * mw, rng.uniform(0.1, 0.2)), (rng.randint(8, 12) / mh * mw, rng.uniform(0.4, 0.6))]
    outer_glow_layer = glow_layer(mask_L, outer_glow_colors, radii=outer_glow_radii)

    return composite(base_layer, inner_glow_layer, highlight_RGBA, shadow_RGBA, outer_glow_layer, size=(mw, mh))


