def render_long_shadow_flat(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'retro'
    base_font_size = auto_size(title)
    actual_font_size = rng.randint(base_font_size - 2, base_font_size + 2)
    font_obj = F(font_role, actual_font_size, rng)

    mask_L = make_mask(title, font_obj)
    mw, mh = mask_L.size

    depth_rng = rng.randint(25, 35)
    shadow_color_rgb = (rng.randint(0, 64), rng.randint(0, 64), rng.randint(0, 64))
    flat_shadow_rgba = flat_color(mask_L, shadow_color_rgb)

    extruded_shadow = extrude(mask_L, depth_rng, 225, shadow_color_rgb, shadow_color_rgb)
    mw, mh = mask_L.size

    fill_color_rgb = (rng.randint(80, 256), rng.randint(80, 256), rng.randint(80, 256))
    flat_fill_rgba = flat_color(mask_L, fill_color_rgb)

    return composite(flat_shadow_rgba, extruded_shadow, flat_fill_rgba, size=(mw, mh))


