    base_colors = [(255, 183, 197), (176, 112, 189), (126, 77, 179)]
    gradient_stops = [base_colors[rng.randint(0, len(base_colors) - 1)] for _ in range(rng.randint(2, 4))]
    solid_fill = flat_color(mask_L, rng.choice(base_colors))
    vertical_gradient = colorize(mask_L, gradient_stops)

    highlight_angle = rng.uniform(30, 60)
    shadow_offset = (rng.randint(-5, -1), rng.randint(8, 12))

