    glow_inner_radii = [(2 + rng.random(), 0.3 + rng.random())]

    outer_glow = glow_layer(mask_L, (255, 215, 189), radii=glow_outer_radii)
    inner_glow_effect = inner_glow(mask_L, (247, 196, 160), radii=glow_inner_radii)

    extrude_depth = rng.randint(3, 5)
    extrusion_angle = rng.uniform(45, 60)
    highlight_color = (255, 238, 197)
    shadow_color = (128, 128, 128)

