    rgba_img_gradient = colorize(mask_L, gradient_colors)

    # Inner glow effect
    inner_glow_rgb = (rng.randint(180, 255), rng.randint(160, 240), rng.randint(140, 230))
    inner_glow_radii = [(int(rng.uniform(0.5, 1) * mw / 100),
                          float(rng.uniform(0.7, 1.3))) for _ in range(2)]
    rgba_img_inner_glow = inner_glow(mask_L, inner_glow_rgb, radii=inner_glow_radii)

    # Outer glow effect
    outer_glow_rgb = (rng.randint(150, 230), rng.randint(130, 210), rng.randint(110, 190))
    outer_glow_radii = [(int(rng.uniform(0.5, 1) * mw / 50),
                          float(rng.uniform(0.7, 1.3))) for _ in range(4)]
    rgba_img_outer_glow = glow_layer(mask_L, outer_glow_rgb, radii=outer_glow_radii)

    # Bevel light effect
    bevel_angle_deg = rng.randint(0, 360)
    bevel_strength = rng.uniform(0.5, 1)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    # Drop Shadow for depth and realism
    drop_shadow_offset_x = rng.randint(-mw // 40, mw // 40)
    drop_shadow_offset_y = rng.randint(mw // 60, mw // 30)
    drop_shadow_blur_radius = rng.randint(1, mw // 50)
    drop_shadow_alpha = rng.randint(20, 80)
    rgba_img_dropshadow = drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y,
                                       drop_shadow_blur_radius, drop_shadow_alpha)

    # Extrusion for 3D effect
    extrusion_depth = rng.randint(mw // 150, mw // 75)
    extrusion_angle_deg = rng.randint(0, 360)
    rgba_img_extrude_near = flat_color(mask_L,
                                       (rng.randint(base_color[0] - 20, base_color[0]),
                                        rng.randint(base_color[1] - 20, base_color[1]),
                                        rng.randint(base_color[2] - 20, base_color[2])))
    rgba_img_extrude_far = flat_color(mask_L,
                                      (rng.randint(base_color[0], base_color[0] + 20),
                                       rng.randint(base_color[1], base_color[1] + 20),
                                       rng.randint(base_color[2], base_color[2] + 20)))
    rgba_img_extrude = extrude(mask_L, extrusion_depth, extrusion_angle_deg,
                                (rng.randint(50, 70), rng.randint(30, 60), rng.randint(10, 40)),
                                (rng.randint(base_color[0], base_color[0] + 20),
                                 rng.randint(base_color[1], base_color[1] + 20),
                                 rng.randint(base_color[2], base_color[2] + 20)))

    # Composite all layers
    return composite(rgba_img_dropshadow, rgba_img_extrude,
                     rgba_img_base, rgba_img_gradient, rgba_img_inner_glow,
                     rgba_img_outer_glow, highlight_rgba, shadow_rgba,
                     size=(mw, mh))


