    gradient_stops = [(rng.randint(70, 190), rng.randint(50, 140), rng.randint(110, 210)),
                      (rng.randint(140, 255), rng.randint(120, 230), rng.randint(160, 255))]
    color_layer = colorize(mask_L, gradient_stops)

    glow_radius = [(rng.randint(1, 3) / 8., (rng.random() + .7) * 3)]
    glow_effect = glow_layer(mask_L, (255, 240, 220), radii=glow_radius)
    inner_glow_effect = inner_glow(mask_L, (210, 190, 170), [(rng.randint(1, 3) / 8., rng.random() * 2)])

    highlight_angle = rng.uniform(.5, .9) * 360
    highlight_strength = rng.uniform(.4, .7)
    shadow_angle = (highlight_angle + 180) % 360

    bevel_hl = bevel_light(mask_L, highlight_angle, highlight_strength)[0]
    bevel_shd = drop_shadow(mask_L, mw // 5, mh // 5, rng.randint(4, 8), 128)

    depth = rng.randint(3, 6)
