    far_color = (rng.randint(140, 255), rng.randint(120, 230), rng.randint(160, 255))
    extrusion_effect = extrude(mask_L, depth, highlight_angle, near_color, far_color)

    return composite(base_color, color_layer, glow_effect, inner_glow_effect,
                     bevel_hl, bevel_shd, extrusion_effect, size=(mw, mh))


