def render_luxury_v36(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'elegant'
    base_font_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, base_font_size * 2 // 3, rng))
    mw, mh = mask_L.size

    # Gradient base layer
    color_gradient_stops = [(rng.randint(0, 255), rng.randint(180, 255), rng.randint(0, 180)) for _ in range(rng.randint(3, 6))]
    gradient_base_RGBA = colorize(mask_L, color_gradient_stops)

    # Extrude effect
    extrusion_depth = rng.randint(mh // 40, mh // 20)
    angle_deg = rng.uniform(-45, 45)
    near_col_rgb = (rng.randint(180, 255), rng.randint(180, 255), rng.randint(0, 130))
    far_col_rgb = (rng.randint(0, 60), rng.randint(130, 190), rng.randint(0, 80))
    extruded_layer_RGBA = apply_mask(extrude(mask_L, extrusion_depth, angle_deg, near_col_rgb, far_col_rgb), mask_L)

    # Bevel lighting
    bevel_angle_deg = rng.uniform(-65, -25)
    bevel_strength = rng.uniform(1.0, 3.0)
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, bevel_angle_deg, bevel_strength)
    
    # Glow effect
    glow_radius_int = [(extrusion_depth * rng.uniform(0.7, 2.5), rng.uniform(0.9, 1.2)) for _ in range(rng.randint(3, 6))]
    glow_RGBA = apply_mask(glow_layer(mask_L, (rng.randint(200, 255), rng.randint(0, 80), rng.randint(0, 70)), glow_radius_int), mask_L)

    # Inner glow
    inner_glow_radii = [(extrusion_depth * rng.uniform(0.1, 0.4), rng.uniform(0.6, 0.9)) for _ in range(rng.randint(3, 5))]
    inner_glow_RGBA = apply_mask(inner_glow(mask_L, (rng.randint(240, 255), rng.randint(180, 220), rng.randint(0, 70)), inner_glow_radii), mask_L)

    # Drop shadow
    drop_shadow_radius_int = extrusion_depth * rng.uniform(3.0, 6.0)
    drop_shadow_RGBA = apply_mask(drop_shadow(mask_L, mw // 15, mh // 20, int(drop_shadow_radius_int), 192), dilate(mask_L, int(extrusion_depth * 1.4)))

    # Final composite
    return composite(gradient_base_RGBA, extruded_layer_RGBA, glow_RGBA, inner_glow_RGBA, drop_shadow_RGBA, size=(mw, mh))


