    drop_shadow_offsets = (rng.randint(-10, -3), rng.randint(-6, -4))
    drop_shadow_blur = rng.randint(15, 25)
    drop_shadow_alpha = rng.randint(70, 90)
    shadowed_text = drop_shadow(mask_L, *drop_shadow_offsets, drop_shadow_blur, drop_shadow_alpha)

    extrude_depth = rng.randint(3, 6)
