    near_color = (207, 182, 161)
    far_color = (229, 200, 180)
    text_extrusion = extrude(mask_L, extrude_depth, extrusion_angle_deg, near_color, far_color)

    composite_layers = [solid_fill, color_gradient, outer_glow, rim_light,
                        highlight_color, shadow_color, shadowed_text, text_extrusion]
    return composite(*composite_layers, size=(mw, mh))


