    shadow_rgba = drop_shadow(mask_L, *drop_shadow_radius, drop_shadow_blur, drop_shadow_alpha)

    extrusion_depth = rng.randint(3, 5)
    extrusion_angle = rng.uniform(-45, -30)
    near_rgb = (rng.randint(220, 255), rng.randint(180, 220), rng.randint(170, 210))
    far_rgb = (rng.randint(160, 190), rng.randint(140, 170), rng.randint(130, 160))
    extrusion_rgba = extrude(mask_L, extrusion_depth, extrusion_angle, near_rgb, far_rgb)
    
    return composite(base_rgba, gradient_rgba, glow_rgba, inner_glow_rgba, highlight_rgba, shadow_rgba, extrusion_rgba, size=(mw, mh))


