def render_metallic_v1149(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('heavy', auto_size(title, 200, 14), rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    # Base color
    base_color = (rng.randint(80, 150), rng.randint(130, 190), rng.randint(200, 240))

    # Glow and inner glow layers for metallic sheen
    glow_outer = glow_layer(mask_L, base_color, [(mw * .1 / mh, mw * .07 / mh)])
    glow_inner = inner_glow(mask_L, (rng.randint(base_color[0] - 30, base_color[0]),
                                      rng.randint(base_color[1] - 30, base_color[1]),
                                      rng.randint(base_color[2] - 30, base_color[2])), [(mw * .05 / mh, mw * .03 / mh)])

    # Bevel for depth and shadow
    bevel_hl, bevel_sh = bevel_light(mask_L, rng.uniform(45, 135), 0.8)
    dropsh = drop_shadow(dilate(mask_L, 2), int(rng.gauss(mw * .1 / mh, mw * .03 / mh)), int(rng.gauss(mw * .1 / mh, mw * .03 / mh)), rng.randint(25, 65), 96)

    # Extrude for metallic texture
    extruded = extrude(mask_L, int(rng.gauss(mw * .1 / mh, mw * .04 / mh)),
                       rng.uniform(45, 135),
                       (rng.randint(base_color[0] + 20, base_color[0] + 80),
                        rng.randint(base_color[1] - 20, base_color[1] + 60),
                        rng.randint(base_color[2] - 60, base_color[2])),
                       (rng.randint(base_color[0], base_color[0] + 50),
                        rng.randint(base_color[1], base_color[1] + 40),
                        rng.randint(base_color[2], base_color[2] + 30)))

    # Composite all layers
    return composite(apply_mask(extruded, mask_L), apply_mask(glow_outer, mask_L), apply_mask(glow_inner, mask_L), bevel_hl, bevel_sh, dropsh, size=(mw, mh))


