    glow_radii = [(rng.randint(10, 25), rng.uniform(0.3, 0.6)) for _ in range(4)]
    inner_glow_radii = [(rng.randint(8, 18), rng.uniform(0.2, 0.4)) for _ in range(2)]
    extrude_depth = rng.randint(5, 12)
    extrude_angle_deg = rng.randint(30, 60)

    # Base metallic color and glow colors
    base_color_rgb = (rng.randint(80, 180), rng.randint(90, 170), rng.randint(100, 190))
    glow_colors = [(rng.randint(230, 250), rng.randint(240, 255), rng.randint(250, 255)) for _ in range(3)]
    inner_glow_color_rgb = (rng.randint(160, 220), rng.randint(180, 230), rng.randint(200, 240))

    # Create main layers
    base_rgba = flat_color(mask_L, base_color_rgb)
    glow_rgba = glow_layer(mask_L, glow_colors[0], radii=glow_radii[:2])
    inner_glow_rgba = inner_glow(mask_L, inner_glow_color_rgb, radii=inner_glow_radii)

    # Composite main layers
    metallic_base = composite(base_rgba, glow_rgba, inner_glow_rgba, size=(mw, mh))

