    extruded_layer = extrude(mask_L, extrude_depth, extrude_angle_deg,
                             (rng.randint(150, 200), rng.randint(160, 210), rng.randint(170, 220)),
                             (rng.randint(90, 140), rng.randint(80, 130), rng.randint(70, 120)))
    bevel_highlight_rgba, bevel_shadow_rgba = bevel_light(mask_L, extrude_angle_deg + 15, rng.uniform(0.6, 0.9))

    # Composite final layers
    return composite(metallic_base, extruded_layer, bevel_highlight_rgba, bevel_shadow_rgba, size=(mw, mh))


