    far_color = (rng.randint(120, 180), rng.randint(110, 170), rng.randint(100, 160))
    extrusion = extrude(mask_L, depth, highlight_angle, near_color, far_color)

    return composite(metal_fill, outer_glow, rim_glow, highlight_color, shadow_color, extrusion, size=(mw, mh))


