    mw, mh = mask_L.size

    base_color = (rng.randint(50, 120), rng.randint(80, 160), rng.randint(90, 170))
    gradient_stops = [(base_color[0] + rng.randint(-30, 30), base_color[1] + rng.randint(-40, 40), base_color[2] + rng.randint(-50, -20)),
                      (rng.randint(80, 160), rng.randint(90, 170), rng.randint(70, 130))]
    glow_radii = [(rng.uniform(1.5, 2.5) * mw / mh, rng.random() + 0.4),
                  (mw / mh * rng.choice([0.6, 0.8]), rng.random())]
    inner_glow_radii = [(mw / mh * rng.uniform(0.3, 0.7), rng.random()),
                        (mw / mh * rng.uniform(0.15, 0.45), rng.random() + 0.2)]

    colorized_img = flat_color(mask_L, base_color)
    gradient_img = colorize(mask_L, gradient_stops)
    glow_img = glow_layer(mask_L, (base_color[0] - rng.randint(30, 60), base_color[1], base_color[2]), glow_radii)
    inner_glow_img = inner_glow(mask_L, (rng.randint(base_color[0] + 50, base_color[0] + 80), base_color[1], base_color[2]), inner_glow_radii)

    shadow_x_int = rng.choice([-3, -2, -1, 1, 2, 3])
    shadow_y_int = rng.randint(-2 * mw // mh, 2 * mw // mh)
    drop_shadow_img = drop_shadow(mask_L, shadow_x_int, shadow_y_int, int(rng.uniform(0.5, 1) * mw), 192)

    extrude_depth = rng.choice([int((mw + mh) / 48), int((mw + mh) / 64)])
    highlight_angle_deg = (rng.random() - 0.5) * 360
    highlight_strength = rng.uniform(0.7, 1)
    extrude_img = extrude(mask_L, extrude_depth, highlight_angle_deg, base_color,
                           (base_color[0] + rng.randint(-20, 0), base_color[1] - rng.randint(30, 60), base_color[2] - rng.randint(40, 70)))

    bevel_angle_deg = (rng.random() - 0.5) * 360
    bevel_strength = rng.uniform(0.8, 1)
    h_light, s_dark = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    return composite(colorized_img, gradient_img, glow_img, inner_glow_img, drop_shadow_img, extrude_img, h_light, s_dark, size=(mw, mh))


