def render_metallic_v2277(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F("heavy", auto_size(title), rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    # Base metallic sheen gradient
    base_color1 = (rng.randint(200, 255), rng.randint(180, 240), rng.randint(160, 230))
    base_color2 = (rng.randint(150, 220), rng.randint(130, 200), rng.randint(110, 190))
    metallic_sheen = colorize(mask_L, [base_color1, base_color2])

    # Add a subtle inner glow with random colors
    iradii = [(rng.uniform(0.5, 1.5) * mh / 100, rng.uniform(1.5, 3.5) * mw / 100)]
    random_glow_colors = [(rng.randint(220, 255), rng.randint(200, 240), rng.randint(180, 230))]
    inner_glow_effect = inner_glow(mask_L, random.choice(random_glow_colors), iradii)

    # Add a bevel effect for depth
    angle_deg = rng.uniform(-30, 30)
    strength = rng.uniform(0.5, 1.5) / mw * mh
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, angle_deg, strength)

    # Combine effects and return final composite image
    return composite(metallic_sheen,
                     inner_glow_effect,
                     apply_mask(highlight_RGBA, mask_L),
                     apply_mask(shadow_RGBA, dilate(mask_L, 1)),
                     size=(mw, mh))


