def render_metallic_v237(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'heavy'
    base_font_size = auto_size(title)
    font_size = rng.randint(base_font_size - 10, base_font_size + 5)
    mask_L = make_mask(title, F(font_role, font_size, rng))
    mw, mh = mask_L.size

    # Randomize metallic colors and glow effects
    primary_color = (rng.randint(128, 224), rng.randint(192, 236), rng.randint(170, 250))
    secondary_color = (rng.randint(80, 170), rng.randint(120, 200), rng.randint(100, 180))
    glow_colors = [primary_color, secondary_color]
    glow_radii = [(2 + rng.random() * 5, 0.3 + rng.random() * 0.7)]

    # Create base metallic text layer
    metal_layer = colorize(mask_L, glow_colors)

    # Add outer glow effect for a rare material look
    outer_glow = glow_layer(mask_L, primary_color, glow_radii)
    inner_glow_effect = inner_glow(mask_L, secondary_color, [(1 + rng.random() * 3, 0.2)])

    # Create bevel light with random angle and strength
    angle_deg = rng.randint(0, 359)
    strength = rng.uniform(0.4, 0.8)
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, angle_deg, strength)

    # Add drop shadow for depth
    drop_shadow_layer = drop_shadow(dilate(mask_L, 1), -2 + rng.randint(-3, 3), mw // 50, 255)

    # Composite all layers to final image
    return composite(apply_mask(metal_layer, mask_L),
                     apply_mask(inner_glow_effect, dilate(mask_L, 1)),
                     drop_shadow_layer,
                     highlight_RGBA,
                     shadow_RGBA,
                     size=(mw, mh))


