    mw, mh = mask_L.size

    base_color = (rng.randint(64, 128), rng.randint(95, 130), rng.randint(112, 160))
    metallic_base = flat_color(mask_L, base_color)

    glow_radii = [(rng.uniform(0.7, 1.3) * i, rng.uniform(0.4, 0.8)) for i in range(5)]
    glow_colors = [(rng.randint(200, 255), rng.randint(200, 255), rng.randint(200, 255)) for _ in range(len(glow_radii))]
    metallic_glow = glow_layer(mask_L, glow_colors[0], radii=glow_radii)

    inner_glow_color = (rng.randint(190, 240), rng.randint(170, 230), rng.randint(150, 220))
    inner_glow_radii = [(int(rng.uniform(0.6, 1.8) * i), rng.uniform(0.2, 0.6)) for i in range(4)]
    metallic_inner_glow = inner_glow(mask_L, inner_glow_color, radii=inner_glow_radii)

    highlight_angle = rng.randint(-359, 359)
    highlight_strength = rng.uniform(0.2, 0.8)
    shadow_angle = (highlight_angle + 180) % 360
    shadow_strength = rng.uniform(0.4, 0.7)
    metallic_bevel_light = bevel_light(mask_L, highlight_angle, highlight_strength)[0]
    metallic_drop_shadow = drop_shadow(mask_L, rng.randint(-2, 2), rng.randint(1, mw // 50), rng.randint(30, 80))

    extrude_depth = rng.randint(mw // 75, mw // 40)
    extrude_angle = (highlight_angle - 90) % 360
    extrude_color_near = (rng.randint(120, 190), rng.randint(100, 180), rng.randint(90, 170))
    extrude_color_far = (rng.randint(50, 140), rng.randint(60, 130), rng.randint(70, 120))
    metallic_extrude = extrude(mask_L, extrude_depth, extrude_angle, extrude_color_near, extrude_color_far)

    return composite(metallic_base, metallic_glow, metallic_inner_glow, metallic_bevel_light,
                     metallic_drop_shadow, metallic_extrude, size=(mw, mh))


