    mw, mh = mask_L.size

    # Base text color and metallic glow
    base_color = (rng.randint(20, 50), rng.randint(60, 120), rng.randint(70, 130))
    metal_glow = glow_layer(mask_L, base_color, radii=[(8 + rng.random() * 4, 0.2 + rng.random() * 0.6)])

    # Subtle inner rim light
    inner_rim_light = inner_glow(mask_L, (rng.randint(130, 200), rng.randint(150, 220), rng.randint(170, 240)), radii=[(3 + rng.random() * 2, 0.3 + rng.random() * 0.2)])

    # Complex extrusion effect with random tilt
    extrude_depth = int(rng.uniform(-6, -2))
    extrude_angle = rng.randint(185, 195)
    extrude_color_near = (rng.randint(70, 130), rng.randint(90, 140), rng.randint(80, 150))
    extrude_color_far = (rng.randint(20, 60), rng.randint(30, 90), rng.randint(25, 100))
    extruded_text = extrude(mask_L, extrude_depth, extrude_angle, extrude_color_near, extrude_color_far)

    # Final shadow and composite layers
    drop_shadow_offset_x = int(rng.uniform(-4, -1))
    drop_shadow_offset_y = mw // 8 + int(rng.uniform(0, 2))
    drop_shadow_blur_radius = mw // 32 + int(rng.random() * mw // 64)
    drop_shadow_alpha = int(rng.uniform(95, 170))
    final_dropshadow = drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y, drop_shadow_blur_radius, drop_shadow_alpha)

    return composite(extruded_text, metal_glow, inner_rim_light, final_dropshadow, size=(mw, mh))


