def render_metallic_v549(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('heavy', auto_size(title), rng)
    mask_L = make_mask(title, font)

    base_color = (rng.randint(80, 120), rng.randint(60, 90), rng.randint(70, 110))
    gradient_colors = [(base_color[0] + i * rng.randint(-30, 30),
                        base_color[1] + i * rng.randint(-25, 25),
                        base_color[2] + i * rng.randint(-28, 28)) for i in range(4)]

    glow_radius = [(rng.randint(2, 6), rng.uniform(0.3, 0.7)),
                   (rng.randint(1, 3), rng.uniform(0.5, 1.2))]
    inner_glow_radius = [(rng.randint(1, 3), rng.uniform(0.4, 0.8))]

    extrusion_depth = rng.randint(2, 6)
    extrusion_angle = rng.choice([30, 60, 90, 120, 150])
    near_color = (rng.randint(base_color[0] - 20, base_color[0] + 40),
                  rng.randint(base_color[1] - 25, base_color[1] + 35),
                  rng.randint(base_color[2] - 30, base_color[2] + 35))
    far_color = (rng.randint(near_color[0] - 30, near_color[0] + 40),
                 rng.randint(near_color[1] - 35, near_color[1] + 50),
                 rng.randint(near_color[2] - 40, near_color[2] + 60))

    bevel_angle = rng.choice([15, 30, 45, 60, 75])
    bevel_strength = rng.uniform(0.2, 0.8)

    shadow_offset_x = rng.randint(-3, 3)
    shadow_offset_y = rng.randint(3, 9)
    shadow_blur_radius = rng.randint(5, 15)
    shadow_alpha = rng.randint(64, 192)

    base_img = flat_color(mask_L, base_color)
    gradient_img = colorize(mask_L, gradient_colors)
    glow_img = glow_layer(mask_L, (0, 0, 0), radii=glow_radius)
    inner_glow_img = inner_glow(mask_L, (rng.randint(50, 128), rng.randint(50, 128), rng.randint(50, 128)), radii=inner_glow_radius)
    extruded_img = extrude(mask_L, extrusion_depth, extrusion_angle, near_color, far_color)
    bevel_highlight, bevel_shadow = bevel_light(mask_L, bevel_angle, bevel_strength)
    shadow_img = drop_shadow(mask_L, shadow_offset_x, shadow_offset_y, shadow_blur_radius, shadow_alpha)

    mw, mh = mask_L.size
    return composite(base_img, gradient_img, glow_img, inner_glow_img, extruded_img,
                     apply_mask(bevel_highlight, dilate(mask_L, 1)), apply_mask(bevel_shadow, dilate(mask_L, -1)),
                     shadow_img, size=(mw, mh))


