def render_metallic_v561(title: str, rng: random.Random) -> Image.Image:
    font_role = 'heavy'
    mask_L = make_mask(title.upper(), F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    # Base metallic color gradient with slight variation
    base_colors = [(210 + rng.randint(-50, 50), 230 + rng.randint(-40, 40), 245 + rng.randint(-30, 30)),
                   (180 + rng.randint(-60, 60), 210 + rng.randint(-50, 50), 235 + rng.randint(-40, 40))]
    metallic_base = colorize(mask_L, base_colors)

    # Add subtle glow effect for a reflective surface
    glow_color = (rng.randint(180, 255), rng.randint(200, 255), rng.randint(230, 255))
    glow_radii = [(3 + rng.random(), 0.6 + rng.random()), (4 + rng.random(), 0.7 + rng.random())]
    metallic_glow = glow_layer(mask_L, glow_color, radii=glow_radii)

    # Subtle bevel for a polished look
    light_angle = 25 + rng.randint(-10, 10)
    light_strength = 0.4 + rng.uniform(0.05, 0.3)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, light_angle, light_strength)

    # Inner glow for depth and realism
    inner_glow_color = (rng.randint(210, 240), rng.randint(230, 250), rng.randint(245, 255))
    inner_radii = [(2 + rng.random(), 0.5 + rng.random()), (3 + rng.random(), 0.6 + rng.random())]
    metallic_inner_glow = inner_glow(mask_L, inner_glow_color, radii=inner_radii)

    # Subtle drop shadow for separation
    shadow_offset_x = 1 + rng.randint(0, 2)
    shadow_offset_y = 3 + rng.randint(2, 4)
    shadow_blur = 5 + rng.randint(1, 3)
    shadow_alpha = 64 + rng.randint(32, 96)
    metallic_shadow = drop_shadow(mask_L, shadow_offset_x, shadow_offset_y, shadow_blur, shadow_alpha)

    return composite(metallic_base, metallic_glow, highlight_rgba, shadow_rgba,
                     metallic_inner_glow, metallic_shadow, size=(mw, mh))


