def render_metallic_v57(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'heavy'
    base_font_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, base_font_size, rng))
    mw, mh = mask_L.size

    # Randomize metallic colors and effects
    metal_base_color = (rng.randint(100, 255), rng.randint(70, 180), rng.randint(90, 230))
    metal_tone_colors = [(rng.randint(60, 140), rng.randint(40, 130), rng.randint(50, 120)),
                         (rng.randint(120, 180), rng.randint(90, 160), rng.randint(100, 170))]
    glow_radius = [(rng.uniform(.5, 1.5), rng.random()), (rng.uniform(2.0, 3.5), rng.random())]
    inner_glow_radius = [(rng.uniform(.2, .8), rng.random()), (rng.uniform(1.0, 2.0), rng.random())]

    # Build the core metal layer
    metal_base_layer = flat_color(mask_L, metal_base_color)
    metal_tone_layer = colorize(mask_L, metal_tone_colors)

    # Add a glowing effect around the edges
    glow_effect = glow_layer(mask_L, metal_base_color, radii=glow_radius)

    # Add an inner glimmering effect to give depth and texture
    inner_glow_effect = inner_glow(mask_L, metal_base_color, radii=inner_glow_radius)

    # Combine all effects with proper masking and blending
    return composite(metal_tone_layer, glow_effect, inner_glow_effect, apply_mask(metal_base_layer, mask_L), size=(mw, mh))


