    col_far_rgb = (rng.randint(50, 160), rng.randint(30, 140), rng.randint(20, 120))
    rgba_extrude = extrude(mask_L, extrude_depth, extrude_angle, col_near_rgb, col_far_rgb)

    # Beveled light effect to simulate lighting on a reflective surface
    bevel_light_angle_deg = rng.uniform(30, 60)
    bevel_strength = rng.uniform(0.2, 0.8)
