    # Glow effect for a metallic sheen
    glow_color = (rng.randint(150, 230), rng.randint(120, 190), rng.randint(80, 160))
    glow_radii = [(rng.randint(1, 4), rng.uniform(1.5, 2)), (rng.randint(1, 3), rng.uniform(0.7, 1))]
    rgba_glow = glow_layer(mask_L, glow_color, radii=glow_radii)

