    inner_glow_color = (rng.randint(180, 255), rng.randint(160, 230), rng.randint(140, 220))
    inner_glow_radii = [(rng.randint(1, 3), rng.uniform(0.7, 1)), (rng.randint(1, 2), rng.uniform(0.5, 0.8))]
    rgba_inner_glow = inner_glow(mask_L, inner_glow_color, radii=inner_glow_radii)

