def render_molten_lava(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = "heavy"
    mask_L = make_mask(title, F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    base_color = (20, 20, 20)
    dark_red = (40 + int(rng.random() * 65), 10 + int(rng.random() * 35), 10 + int(rng.random() * 35))
    orange = (int(rng.random() * 75) + 100, int(rng.random() * 90) + 80, 20 + int(rng.random() * 40))
    bright_yellow = (int(rng.random() * 60) + 230, int(rng.random() * 50) + 220, int(rng.random() * 70) + 190)
    colors = [base_color, dark_red, orange, bright_yellow]

    if rng.random() < 0.5:  # cool lava
        base_color = (30, 30, 30)
        dark_red = (60, 20, 20)
        orange = (150, 90, 40)
        bright_yellow = (240, 220, 180)

    color_layer = colorize(mask_L, colors)

    inner_glow_colors = [(rng.randint(250, 255), rng.randint(220, 230), rng.randint(160, 190))]
    inner_glow_radii = [(int(rng.random() * 4 + 8), rng.random()), (int(rng.random() * 4 + 8), rng.random())]
    core_layer = inner_glow(mask_L, tuple(inner_glow_colors[0]), radii=inner_glow_radii)

    outer_glow_color = (rng.randint(120, 150), rng.randint(60, 90), rng.randint(40, 70))
    outer_glow_radii = [(int(rng.random() * 4 + 8), rng.random()), (int(rng.random() * 4 + 8), rng.random()),
                        (int(rng.random() * 4 + 8), rng.random())]
    outer_layer = glow_layer(mask_L, outer_glow_color, radii=outer_glow_radii)

    bevel_angle_deg = int(rng.random() * 360)
    bevel_strength = rng.uniform(0.15, 0.25)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, angle_deg=bevel_angle_deg, strength=bevel_strength)

    return composite(color_layer, core_layer, outer_layer, apply_mask(highlight_rgba, mask_L), apply_mask(shadow_rgba, mask_L), size=(mw, mh))


