def render_mosaic_tile_wild1582(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'heavy'
    mask_L = make_mask(title, F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    # Randomize cell size and palette
    cell_size = rng.randint(8, 14)
    num_colors = rng.randint(3, 6)  # number of colors in the palette
    color_palette = [(rng.randint(50, 255), rng.randint(50, 255), rng.randint(50, 255)) for _ in range(num_colors)]

    # Create mosaic texture with random cell fill from palette
    base_img = Image.new('RGB', (mw, mh), color=(0, 0, 0))
    draw = ImageDraw.Draw(base_img)
    
    for y in range(0, mh, cell_size):
        for x in range(0, mw, cell_size):
            # Pick random fill from palette
            color = rng.choice(color_palette)
            draw.rectangle([x, y, min(x + cell_size, mw), min(y + cell_size, mh)], fill=color)

    # Add dark grout lines (optional enhancement for texture)
    for x in range(0, mw, 2):
        draw.line([(x, 0), (x, mh)], fill=(30, 30, 30))
    
    for y in range(0, mh, 2):
        draw.line([(0, y), (mw, y)], fill=(30, 30, 30))

    # Apply mask to clip mosaic texture to text outline
    base_img.putalpha(mask_L)
    return apply_mask(base_img, mask_L)


