def render_mosaic_tile_wild2422(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'heavy'
    base_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, base_size, rng))
    mw, mh = mask_L.size

    cell_size = rng.randint(8, 14)
    palette_colors = [(rng.randint(50, 255), rng.randint(50, 255), rng.randint(50, 255)) for _ in range(rng.randint(6, 10))]
    grout_color = (30, 30, 30)

    mosaic_img = Image.new('RGB', mask_L.size)
    draw = ImageDraw.Draw(mosaic_img)

    for y in range(0, mh, cell_size):
        for x in range(0, mw, cell_size):
            color = rng.choice(palette_colors)
            draw.rectangle((x, y, x + cell_size, y + cell_size), fill=color)

    # Add grout lines
    draw.line([(i, 0) for i in range(cell_size, mw, cell_size)], fill=grout_color)
    draw.line([(0, j) for j in range(cell_size, mh, cell_size)], fill=grout_color)
    for x in range(0, mw, cell_size):
        draw.line([(x, y) for y in range(cell_size, mh, cell_size)], fill=grout_color)

    # Apply mask
    rgba_img = Image.new('RGBA', mosaic_img.size)
    rgba_img.paste(mosaic_img, (0, 0))
    masked_img = apply_mask(rgba_img, mask_L)

    return composite(masked_img, size=(mw, mh))


