        for x in range(0, mw, cell_size):
            cell_fill = color_palette[rng.randint(0, len(color_palette) - 1)]
            draw.rectangle([x + int(cell_size * rng.uniform(-0.2, 0.2)), y + int(cell_size * rng.uniform(-0.2, 0.2)),
                            x + cell_size + int(cell_size * rng.uniform(-0.2, 0.2)), y + cell_size + int(cell_size * rng.uniform(-0.2, 0.2))],
                           fill=cell_fill)

            # Grout lines
