def render_mosaic_tile_wild2835(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'heavy'
    font_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, font_size, rng))
    mw, mh = mask_L.size

    cell_size = rng.randint(8, 14)
    palette_colors = [(rng.randint(50, 255), rng.randint(50, 255), rng.randint(50, 255)) for _ in range(rng.randint(3, 6))]
    grout_color = (0, 0, 0)

    base_img = Image.new('RGB', (mw * cell_size, mh * cell_size), 'white')
    draw = ImageDraw.Draw(base_img)
    
    for x in range(mw):
        for y in range(mh):
            if mask_L.getpixel((x, y)) > 128:
                color_index = rng.randint(0, len(palette_colors) - 1)
                fill_color = palette_colors[color_index]
                
                draw.rectangle([x * cell_size, y * cell_size, (x + 1) * cell_size, (y + 1) * cell_size], fill=fill_color)

    # Draw grout lines
    for x in range(mw):
        for y in range(mh - 1):
            if mask_L.getpixel((x, y)) > 128 and mask_L.getpixel((x, y + 1)) <= 128:
                draw.line([(x * cell_size, (y + 1) * cell_size), ((x + 1) * cell_size, (y + 1) * cell_size)], fill=grout_color)
    
    for x in range(mw - 1):
        for y in range(mh):
            if mask_L.getpixel((x, y)) > 128 and mask_L.getpixel((x + 1, y)) <= 128:
                draw.line([((x + 1) * cell_size, y * cell_size), ((x + 1) * cell_size, (y + 1) * cell_size)], fill=grout_color)

    base_img = base_img.resize((mw, mh))
    
    return apply_mask(base_img.convert('RGBA'), mask_L)


