    accent_colors = [(rng.randint(0, 255), rng.randint(0, 255), rng.randint(0, 255)) for _ in range(rng.randint(2, 6))]
    bg_color = base_colors[rng.choice(range(len(base_colors)))]

    # Base layer
    base_img = flat_color(mask_L, bg_color)

    # Gradient overlay
    gradient_layers = colorize(dilate(mask_L, rng.randint(-10, 3)), accent_colors)
    
