    angle_deg = rng.uniform(-60, 60)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, angle_deg, strength=rng.random() * 2 + 1.5)

    return composite(base_img, gradient_layers, outer_glow, apply_mask(highlight_rgba, mask_L), 
                     apply_mask(shadow_rgba, dilate(mask_L, -3)), size=(mw, mh))


