def render_nature_v1354(title: str, rng: random.Random) -> Image.Image:
    mask_L = make_mask(title.upper(), F('elegant', auto_size(title), rng))
    mw, mh = mask_L.size

    # Base color gradient for organic feel
    colors = [(rng.randint(200, 255), rng.randint(160, 220), rng.randint(80, 140)),
              (rng.randint(100, 170), rng.randint(130, 200), rng.randint(70, 120))]
    base_gradient = colorize(mask_L, colors)

    # Glow effect for warmth
    glow_radii = [(rng.uniform(.5, 1.5), .5)]
    glow_effect = glow_layer(mask_L, (rng.randint(230, 255), rng.randint(80, 160), rng.randint(40, 120)), glow_radii)

    # Inner texture for depth
    inner_glow_colors = [(rng.randint(150, 200), rng.randint(90, 150), rng.randint(30, 80))]
    inner_texture = inner_glow(mask_L, (rng.randint(140, 160), rng.randint(60, 100), rng.randint(20, 70)), [(2.5, .5)])

    # Bevel effect for organic texture
    bevel_angle_deg = rng.uniform(-30, 30)
    bevel_strength = rng.uniform(.3, .7)
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    # Drop shadow for realism
    drop_shadow_offset_x = rng.randint(1, mh // 16)
    drop_shadow_offset_y = rng.randint(1, mw // 16)
    drop_shadow_blur_radius = rng.randint(mw // 32, mw // 16)
    drop_shadow_alpha = rng.uniform(.5, .8) * 255
    shadow_effect = drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y, drop_shadow_blur_radius, int(drop_shadow_alpha))

    # Final extrusion for depth and presence
    extrusion_depth = rng.randint(mw // 40, mw // 30)
    extrusion_angle_deg = rng.uniform(-15, 15)
    near_color_rgb = (rng.randint(200, 255), rng.randint(80, 160), rng.randint(30, 70))
    far_color_rgb = (rng.randint(140, 180), rng.randint(60, 120), rng.randint(20, 60))
    extrusion_effect = extrude(mask_L, extrusion_depth, extrusion_angle_deg, near_color_rgb, far_color_rgb)

    return composite(base_gradient, glow_effect, inner_texture, highlight_RGBA, shadow_RGBA, shadow_effect, extrusion_effect, size=(mw, mh))


