    base_color_air = (0, 255, 255) if chosen_element == 'air' else None
    base_color_space = (47, 79, 79) if chosen_element == 'space' else None
    base_color_storm = (63, 72, 204) if chosen_element == 'storm' else None

    # Colorize with a gradient based on the element selected
    color_gradient = [
        base_color_fire or rng.choice([(255, 99, 71), (255, 69, 0)]),
        base_color_water or rng.choice([(30, 144, 255), (0, 255, 255)]),
        base_color_earth or rng.choice([(139, 69, 19), (188, 143, 143)]),
        base_color_air or rng.choice([(0, 255, 255), (75, 0, 130)]),
        base_color_space or rng.choice([(47, 79, 79), (60, 60, 60)]),
        base_color_storm or rng.choice([(63, 72, 204), (85, 107, 47)])
    ]
