    drop_shadow_rgba = drop_shadow(mask_L, -2, 2, 4, int(64 + rng.random() * 96))

    texture_noise = (np.random.rand(mw, mh) * 255).astype(np.uint8)
    texture_img = Image.fromarray(texture_noise).convert('L')
    overlay_rgba = apply_mask(Image.new('RGBA', (mw, mh), base_color), dilate(mask_L, 1))

    final_image = composite(text_rgba, glow_rgba, highlight_rgba, shadow_rgba, drop_shadow_rgba, overlay_rgba,
                            size=(mw, mh))
    return final_image


