def render_nature_v874(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('elegant', auto_size(title), rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    # Define color stops for the organic nature of fire/water/earth/air/space/storm
    elements = ['fire', 'water', 'earth', 'air', 'space', 'storm']
    element_colors = {
        'fire': [(255, 69, 0), (178, 34, 34)],
        'water': [(0, 255, 255), (0, 0, 255)],
        'earth': [(139, 69, 19), (107, 142, 35)],
        'air': [(173, 216, 230), (100, 149, 237)],
        'space': [(0, 0, 0), (148, 0, 211)],
        'storm': [(153, 255, 153), (0, 128, 128)]
    }
    
    # Randomly select an element
    selected_element = rng.choice(elements)
    colors_stops = element_colors[selected_element]
    
    # Generate the base colorize effect for organic texture
    rgba_img = colorize(mask_L, colors_stops)
    
    # Add glow and inner glow layers to give it a vibrant feel
    glow_radii = [(rng.randint(20, 40), rng.uniform(0.1, 0.5)) for _ in range(3)]
    inner_glow_radii = [(rng.randint(10, 20), rng.uniform(0.1, 0.3)), (rng.randint(5, 10), rng.uniform(0.05, 0.2))]
    
    glow_layer_img = glow_layer(mask_L, random.choice(colors_stops), radii=glow_radii)
    inner_glow_layer_img = inner_glow(mask_L, random.choice(colors_stops), radii=inner_glow_radii)

    # Create a bevel light effect for depth and realism
    angle_deg = rng.uniform(0, 360)
    strength = rng.uniform(0.5, 1.2)
    
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, angle_deg, strength)
    
    # Add drop shadows for a floating texture effect
    ox_int = rng.randint(-10, -4)
    oy_int = rng.randint(-10, -4)
    blur_int = rng.randint(5, 20)
    alpha_0to255 = rng.randint(64, 192)

    drop_shadow_layer_img = drop_shadow(mask_L, ox_int, oy_int, blur_int, alpha_0to255)

    # Composite all layers together
    return composite(
        apply_mask(glow_layer_img, mask_L),
        inner_glow_layer_img,
        highlight_RGBA,
        shadow_RGBA,
        rgba_img,
        drop_shadow_layer_img,
        size=(mw, mh)
    )


