def render_neon_v1(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('tech', auto_size(title), rng)
    mask_L = make_mask(title, font, pad=40)
    mw, mh = mask_L.size

    # Randomize glow properties
    glow_radii = [(rng.randint(1, 3) + rng.random(), rng.gauss(2.5, 0.5))]
    inner_glow_radii = [(rng.randint(1, 2), rng.gauss(2.5, 0.5)), (rng.randint(4, 6), rng.gauss(7, 2))]

    # Randomize colors
    neon_color = (rng.randint(100, 255), rng.randint(100, 255), rng.randint(100, 255))
    inner_neon_color = (rng.randint(50, 180), rng.randint(50, 180), rng.randint(50, 180))

    # Create neon glow and inner glow layers
    glow_layer_rgba = glow_layer(mask_L, neon_color, radii=glow_radii)
    inner_glow_layer_rgba = inner_glow(mask_L, inner_neon_color, radii=inner_glow_radii)

    # Randomize bevel light properties
    angle_deg = rng.randint(0, 360)
    strength = rng.uniform(0.25, 1.75)

    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, angle_deg, strength)

    # Combine layers to create the final neon effect
    neon_effect_rgba = composite(
        flat_color(mask_L, neon_color),
        glow_layer_rgba,
        inner_glow_layer_rgba,
        drop_shadow(mask_L, rng.randint(-4, 4), rng.randint(2, 6), rng.randint(10, 30), rng.randint(50, 200)),
        apply_mask(shadow_RGBA, dilate(mask_L, rng.randint(1, 3))),
        highlight_RGBA,
        size=(mw, mh)
    )

    return neon_effect_rgba


