def render_neon_v1609(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'tech'
    base_font_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, base_font_size, rng))
    mw, mh = mask_L.size

    # Randomized parameters
    main_color = (rng.randint(0, 255), rng.randint(160, 255), rng.randint(0, 140))
    secondary_color = (rng.randint(80, 160), rng.randint(120, 200), rng.randint(0, 100))
    glow_radii = [(rng.uniform(0.3, 0.5) * mw / 100, rng.random() + 0.5),
                  (rng.uniform(0.4, 0.7) * mw / 100, rng.random() - 0.2)]
    inner_glow_radii = [(rng.uniform(0.1, 0.3) * mw / 100, rng.random() + 0.5),
                        (rng.uniform(0.15, 0.4) * mw / 100, rng.random() - 0.2)]
    bevel_angle = rng.randint(-60, 60)
    shadow_offset_x = rng.randint(-5, 5)
    shadow_offset_y = rng.randint(-3, 7)

    # Base neon color fill
    base_neon_img = flat_color(mask_L, main_color)

    # Gradient overlay for electric feel
    gradient_stops = [secondary_color, (rng.randint(80, 200), rng.randint(150, 220), rng.randint(40, 160))]
    neon_gradient_img = colorize(mask_L, gradient_stops)

    # Glow layers for vividness
    glow_layer_1 = glow_layer(dilate(mask_L, 3), main_color, glow_radii)
    inner_glow_layer = inner_glow(mask_L, secondary_color, inner_glow_radii)

    # Bevel effect for depth and contrast
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, bevel_angle, rng.random() + 0.5)

    # Drop shadow for grounding the neon text in space
    drop_shadow_img = drop_shadow(dilate(mask_L, 2), shadow_offset_x, shadow_offset_y, int(rng.uniform(1, 3) * mw / 100), 80)

    return composite(base_neon_img, neon_gradient_img, glow_layer_1, inner_glow_layer, highlight_RGBA, shadow_RGBA, drop_shadow_img, size=(mw, mh))


