def render_neon_v1705(title: str, rng: random.Random) -> Image.Image:
    font = F("tech", auto_size(title), rng)
    mask_L = make_mask(title.upper(), font)
    mw, mh = mask_L.size

    base_color = flat_color(mask_L, (rng.randint(64, 255), rng.randint(0, 128), rng.randint(0, 192)))
    glow_colors = [(rng.randint(0, 127), rng.randint(128, 255), rng.randint(192, 255)),
                   (rng.randint(64, 255), rng.randint(64, 255), rng.randint(32, 127))]
    inner_glow_color = (rng.randint(0, 64), rng.randint(64, 192), rng.randint(192, 255))
    outer_bloom_radii = [(2 + rng.random(), 0.8 + rng.random()), (3 + rng.random(), 0.5 + rng.random())]
    inner_glow_radii = [(1 + rng.random(), 0.6 + rng.random()), (1.5 + rng.random(), 0.4 + rng.random())]

    base_layer = apply_mask(base_color, mask_L)
    glow_layer_1 = colorize(mask_L, glow_colors).filter(ImageFilter.GaussianBlur(2))
    glow_layer_2 = glow_layer(mask_L, glow_colors[0], outer_bloom_radii)
    inner_glow_layer = inner_glow(mask_L, inner_glow_color, inner_glow_radii)

    highlight_rgba, shadow_rgba = bevel_light(mask_L, rng.randint(0, 360), 1.2 + rng.random())
    drop_shadow_layer = drop_shadow(mask_L, 4 + rng.randint(-2, 2), 7 + rng.randint(0, 5), 64, 192)

    final_layers = [base_layer,
                    glow_layer_1,
                    glow_layer_2,
                    inner_glow_layer,
                    apply_mask(highlight_rgba, dilate(mask_L, -3)),
                    apply_mask(shadow_rgba, dilate(mask_L, 3)),
                    drop_shadow_layer]

    return composite(*final_layers, size=(mw, mh))


