    inner_flicker_radii = [(rng.uniform(i * 0.5, i), rng.uniform(0.2, 1.0)) for i in range(rng.randint(2, 4))]
    inner_flicker = inner_glow(mask_L, base_color, radii=inner_flicker_radii)

    # Bevel effect to give depth
    bevel_angle_deg = rng.randint(-90, 90)
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, angle_deg=bevel_angle_deg, strength=rng.uniform(1.0, 2.5))

    return composite(neon_base, outer_glow, inner_flicker, apply_mask(highlight_RGBA, mask_L), apply_mask(shadow_RGBA, dilate(mask_L, 2)), size=(mw, mh))


