    mw, mh = mask_L.size

    # Randomize colors
    base_color = (rng.randint(0, 255), rng.randint(128, 255), rng.randint(128, 255))
    glow_colors = [(rng.randint(64, 192), rng.randint(128, 255), rng.randint(128, 255)) for _ in range(rng.randint(3, 5))]
    bevel_angle = rng.uniform(-70.0, 70.0)
    highlight_color, shadow_color = bevel_light(mask_L, bevel_angle, rng.random() * 1.5 + 0.8)

    # Main text fill
    neon_text_fill = flat_color(mask_L, base_color)
    
    # Glow effect layers
    glow_layers = [glow_layer(mask_L, color, [(rng.uniform(2.0, 4.0), rng.random() * 0.5)]) for color in glow_colors]
    inner_glow_layer = inner_glow(mask_L, (rng.randint(64, 192), rng.randint(128, 255), rng.randint(128, 255)), [(rng.uniform(1.0, 3.0), rng.random() * 0.5)])
    
    # Bevel and drop shadow
    bevel_shadow = drop_shadow(mask_L, int(rng.choice((-mw//4, mw//4))), mh//6 + int(mh*random.gauss(0, 2)), int(mw/10 + rng.uniform(-2, 2)), int(255 * (rng.random() ** 2)))
    
    # Combine layers
    neon_text_final = composite(neon_text_fill, colorize(mask_L, glow_colors), inner_glow_layer, bevel_shadow, size=(mw, mh))
    
    return composite(bevel_light(mask_L, bevel_angle)[0], neon_text_final, highlight_color, shadow_color, size=(mw, mh))


