    accent_color = (rng.randint(0, 80), rng.randint(80, 160), rng.randint(80, 160))

    base_rgba = flat_color(mask_L, base_color)
    glow_radii = [(rng.uniform(0.3*mw/256, mw/64), rng.uniform(0.1*mw/256, mw/64)) for _ in range(rng.randint(2, 4))]
