    inner_glow_rgbas = []
    for _ in range(rng.randint(1, 3)):
        inner_color = (rng.randint(0, base_color[0]), rng.randint(base_color[1], 255), rng.randint(base_color[2], 255))
        inner_radii = [(rng.uniform(0.05*mw/256, mw/256), rng.uniform(0.1*mw/256, mw/32)) for _ in range(rng.randint(1, 4))]
