    neon_effect = composite(neon_text, glow_outer, glow_inner,
                            bevel_lighting[1], apply_mask(bevel_lighting[0], dilate(mask_L, 2)),
                            drop_shadow(mask_L, *shadow_offset, shadow_offset[0] + rng.randint(3, 6), drop_shadow_intensity),
                            size=(mw, mh))
    return neon_effect


