    drop_shadow_offset_x = int(rng.uniform(mw * -0.25, mw * 0.25))
    drop_shadow_offset_y = int(rng.uniform(mh * -0.25, mh * 0.25))
    drop_shadow_blur_radius = int(rng.uniform(3, 6))
    drop_shadow_alpha = rng.randint(128, 255)
    shadow_img = drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y, drop_shadow_blur_radius, drop_shadow_alpha)

    # Combine all layers
    return composite(shadow_img, glow_1, glow_2, neon_text, highlight_rgba, shadow_rgba, size=(mw, mh))


