def render_neon_v577(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'tech'
    base_font_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, base_font_size, rng))
    mw, mh = mask_L.size

    # Randomized color scheme
    primary_color = (rng.randint(0, 255), rng.randint(180, 255), rng.randint(160, 255))
    secondary_color = (rng.randint(0, 100), rng.randint(140, 220), rng.randint(190, 255))
    tertiary_color = (rng.randint(0, 50), rng.randint(160, 230), rng.randint(200, 255))

    # Base neon glow layer
    base_neon_glow = colorize(mask_L, [primary_color, secondary_color])

    # Inner glows with randomized radii and colors
    inner_glows = []
    for _ in range(rng.randint(1, 3)):
        radius_set = [(rng.uniform(0.2, 0.6), rng.random()), (rng.uniform(0.4, 1.5), rng.uniform(0.7, 1))]
        color = (rng.randint(0, 80) if rng.random() < 0.5 else 255,
                 rng.randint(140, 210),
                 rng.randint(190, 255))
        inner_glows.append(inner_glow(mask_L, color, radius_set))

    # Outer glow for dramatic effect
    outer_glow = glow_layer(mask_L, tertiary_color, [(rng.uniform(1.2, 3), rng.random()), (rng.uniform(4, 6), rng.random())])

    # Random shadow and lighting effects
    shadow_offset_x = rng.randint(-5, 5)
    shadow_offset_y = rng.randint(-2, 2)
    drop_shadow_img = drop_shadow(mask_L, shadow_offset_x, shadow_offset_y, int(rng.uniform(1.8, 3)), 120)

    highlight_angle_deg = 45 + rng.randint(-20, 20)
    shadow_intensity = rng.random()
    (highlight_RGBA, shadow_RGBA) = bevel_light(mask_L, highlight_angle_deg, shadow_intensity)

    # Extrusion for depth with random angles and colors
    extrude_depth = int(rng.uniform(1.3, 2))
    extruded_img = extrude(mask_L, extrude_depth, rng.randint(-45, 45), primary_color, secondary_color)

    # Combine all layers into a single composite image
    return composite(extruded_img,
                     apply_mask(base_neon_glow, mask_L),
                     *[inner for inner in inner_glows],
                     drop_shadow_img,
                     highlight_RGBA,
                     shadow_RGBA,
                     outer_glow,
                     size=(mw, mh))


