def render_outline_v101(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('stark', auto_size(title), rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    base_color = (rng.randint(32, 192), rng.randint(32, 192), rng.randint(32, 192))
    glow_radii = [(4 + i * rng.random(), 0.5 + i * rng.random()) for i in range(1, 4)]
    bevel_angle_deg = (rng.random() < 0.6) * 90 + (rng.random() > 0.3) * 45
    shadow_offset_x_int = int(rng.randint(-mh // 8, mh // 8))
    shadow_offset_y_int = int(rng.randint(-mw // 12, mw // 12))

    glow_colors = [base_color]
    for i in range(1, 3):
        r, g, b = base_color
        step = rng.randint(40, 65) * (-1 if rng.random() < 0.5 else 1)
        new_color = (max(min(r + step, 255), 0), max(min(g + step, 255), 0), max(min(b + step, 255), 0))
        glow_colors.append(new_color)

    base_layer = flat_color(mask_L, base_color)
    glow_layer_1 = glow_layer(mask_L, glow_colors[0], glow_radii[:1])
    glow_layer_2 = glow_layer(mask_L, glow_colors[1], glow_radii[1:3])

    shadow = drop_shadow(mask_L, shadow_offset_x_int, shadow_offset_y_int, int(rng.randint(4, 8)), rng.randint(64, 192))
    bevel_highlight, _ = bevel_light(mask_L, bevel_angle_deg, rng.random() * 0.5 + 0.3)

    return composite(base_layer, glow_layer_1, glow_layer_2, shadow, bevel_highlight, size=(mw, mh))


