def render_outline_v1049(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('stark', auto_size(title, pivot=26), rng)
    mask_L = make_mask(title, font, pad=50)
    mw, mh = mask_L.size

    # Randomize parameters
    primary_color = (rng.randint(100, 255), rng.randint(0, 180), rng.randint(100, 255))
    secondary_color = (rng.randint(64, 192), rng.randint(32, 128), rng.randint(64, 192))
    tertiary_color = (rng.randint(0, 96), rng.randint(0, 64), rng.randint(0, 96))

    glow_radii = [(int(rng.gauss(2, 1)), float(rng.uniform(.5, 1.5))) for _ in range(3)]
    inner_glow_radii = [(rng.randint(0, 2), rng.uniform(0.5, 1)) for _ in range(3)]

    outline_widths = [int(rng.gauss(4, 1)), int(rng.gauss(6, 1)), int(rng.gauss(8, 1))]
    outline_colors = [primary_color, secondary_color, tertiary_color]

    # Create outline layers
    outlines = []
    for width, color in zip(outline_widths, outline_colors):
        dilated_mask_L = dilate(mask_L, width)
        outlines.append(flat_color(dilated_mask_L, color))

    glow_layer_1 = glow_layer(mask_L, primary_color, radii=glow_radii[:2])
    inner_glow_layer_1 = inner_glow(mask_L, secondary_color, radii=[inner_glow_radii[0]])
    glow_layer_2 = glow_layer(dilate(mask_L, outline_widths[-1]), tertiary_color, radii=glow_radii[2:])

    # Composite all layers
    return composite(*outlines, glow_layer_1, inner_glow_layer_1, glow_layer_2, size=(mw, mh))


