def render_outline_v1145(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('stark', auto_size(title), rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    # Main outline parameters
    main_color = (rng.randint(0, 255), rng.randint(0, 127), rng.randint(128, 255))
    second_color = (rng.randint(128, 255), rng.randint(0, 127), rng.randint(0, 255))
    third_color = (rng.randint(0, 255), rng.randint(128, 255), rng.randint(0, 127))

    # Outline width and spacing
    outline_widths = [rng.randint(1, 3) for _ in range(3)]
    outline_spacing = [rng.uniform(0.4, 1.6) * x for x in outline_widths]

    # Create multiple outlines with varying widths and colors
    layers = []
    for i in range(len(outline_widths)):
        width = outline_widths[i]
        spacing = int(round(outline_spacing[i]))
        dilated_mask = dilate(mask_L, width + spacing)
        contracted_mask = dilate(mask_L, width - 1)

        if rng.random() > 0.5:
            color = main_color
        elif rng.random() > 0.5:
            color = second_color
        else:
            color = third_color

        outline_layer = apply_mask(glow_layer(dilated_mask, color, radii=[(width, spacing)]), contracted_mask)
        layers.append(outline_layer)

    # Combine all the outlines together
    final_outline = composite(*layers, size=(mw, mh))

    return final_outline


