    mw, mh = mask_L.size

    # Define outline colors and radii
    base_color = (rng.randint(0, 255), rng.randint(0, 255), rng.randint(0, 255))
    highlight_color = (rng.randint(base_color[0] + 10, 255),
                       rng.randint(base_color[1] + 10, 255),
                       rng.randint(base_color[2] + 10, 255))

    # Generate outline layers
    outlines = []
    for i in range(3):  # Create multiple outline layers for a bold effect
        radius = (i * rng.uniform(1.2, 2.4), rng.uniform(0.8, 1.6))
        if i == 0:  # First layer is the base color with a stronger highlight
            outlines.append(glow_layer(mask_L, base_color, [radius]))
            outlines.append(bevel_light(mask_L, angle_deg=rng.randint(0, 359), strength=2)[0])
        else:
            radius = (radius[0] * rng.uniform(0.8, 1.2), radius[1] * rng.uniform(0.9, 1.1))
            outlines.append(glow_layer(mask_L, highlight_color, [radius]))
            outlines.append(bevel_light(mask_L, angle_deg=rng.randint(0, 359), strength=1)[0])

    # Combine outline layers
    base_outline = composite(*outlines, size=(mw, mh))

    return apply_mask(base_outline, mask_L)


