def render_outline_v1241(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('stark', auto_size(title), rng)
    mask_L = make_mask(title, font)

    mw, mh = mask_L.size

    main_color = (rng.randint(0, 255), rng.randint(128, 255), rng.randint(64, 192))
    secondary_color = (rng.randint(main_color[0] - 32, main_color[0] + 32),
                       rng.randint(max(0, main_color[1] - 64), min(255, main_color[1] + 64)),
                       rng.randint(max(0, main_color[2] - 64), min(255, main_color[2] + 64)))

    outline_widths = [rng.choice([3, 4]), rng.choice([1, 2])]
    outlines_rgba = []
    for width in outline_widths:
        dilated_mask_L = dilate(mask_L, width)
        if width == max(outline_widths):
            color = main_color
        else:
            color = secondary_color

        stroke_rgba = flat_color(dilated_mask_L, color)
        outlines_rgba.append(stroke_rgba)

    shadow_ox = rng.randint(-2, 2)
    shadow_oy = rng.randint(1, mh // 30) + 1
    shadow_blur = rng.randint(shadow_oy - 1, shadow_oy + 2)
    shadow_alpha = max(int((shadow_oy / (mh // 5)) * 255), 64)

    drop_shadow_rgba = drop_shadow(mask_L, shadow_ox, shadow_oy, shadow_blur, shadow_alpha)
    outlines_rgba.append(drop_shadow_rgba)

    final_image = composite(*outlines_rgba, size=(mw, mh))
    return final_image


