    mw, mh = mask_L.size

    # Randomize parameters
    main_color = (rng.randint(0, 255), rng.randint(0, 127), rng.randint(0, 63))
    secondary_color = (rng.randint(0, 255), rng.randint(0, 127), rng.randint(0, 63))
    third_color = (rng.randint(0, 255), rng.randint(0, 127), rng.randint(0, 63))

    ring_radius = [1.0 + rng.random() * 1.5 for _ in range(4)]
    glow_radius = [(1.0 + rng.random(), 0.05) for _ in range(4)]

    outline_layers = []
    for i, rad in enumerate(ring_radius):
        if i % 2 == 0:
            color = main_color
        elif i % 3 == 0:
            color = secondary_color
        else:
            color = third_color

        dilated_mask = dilate(mask_L, int(rad))
        outline_layer = flat_color(dilated_mask, color)
        outline_layers.append(outline_layer)

    glow_layers = []
    for rad in glow_radius:
        glow_layer_img = glow_layer(mask_L, main_color, radii=[rad])
        glow_layers.append(glow_layer_img)

    final_outline = composite(*outline_layers, size=(mw, mh))
    final_glow = composite(*glow_layers, size=(mw, mh))

    return composite(final_outline, final_glow, size=(mw, mh))


