def render_outline_v1793(title: str, rng: random.Random) -> Image.Image:
    mask_L = make_mask(title.upper(), F('stark', auto_size(title), rng))
    mw, mh = mask_L.size

    # Randomize parameters for the outline effect
    base_width = 4 + rng.randint(0, 2)
    outer_stroke_width = base_width + rng.randint(1, 3)
    inner_stroke_width = base_width - rng.randint(0, 1)
    stroke_color_outer = (rng.randint(50, 200), rng.randint(80, 240), rng.randint(60, 220))
    stroke_color_inner = (rng.randint(30, 150), rng.randint(70, 190), rng.randint(40, 170))

    # Generate outer and inner strokes
    mask_L_outer = dilate(mask_L, outer_stroke_width)
    mask_L_inner = dilate(mask_L, inner_stroke_width)

    outline_outer_rgba = flat_color(mask_L_outer, stroke_color_outer)
    outline_inner_rgba = flat_color(mask_L_inner, stroke_color_inner)

    # Composite the two strokes together with a subtractive effect for clean edges
    result_rgba = composite(outline_outer_rgba, apply_mask(Image.new('RGBA', (mw, mh), (0, 0, 0, 0)), mask_L),
                             outline_inner_rgba, size=(mw, mh))

    return composite(result_rgba, size=(mw, mh))


