def render_outline_v2333(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('stark', auto_size(title), rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    # Outline parameters
    stroke_widths = [2 + rng.randint(0, 3), 4 + rng.randint(1, 5)]
    stroke_colors = [(rng.randint(0, 255), rng.randint(0, 255), rng.randint(0, 255)) for _ in range(len(stroke_widths))]
    
    # Creating the outline layers
    outlines_RGBA = []
    for width, color in zip(stroke_widths, stroke_colors):
        mask_dilated = dilate(mask_L, width // 2)
        outer_mask = Image.new('L', (mw + width * 2, mh + width * 2), 0)
        draw = ImageDraw.Draw(outer_mask)
        draw.rectangle((width, width, mw + width, mh + width), fill=255)  # Inner white square
        outer_mask.paste(mask_dilated, (width, width))
        outline_RGBA = flat_color(outer_mask, color)
        outlines_RGBA.append(outline_RGBA)

    return composite(*outlines_RGBA, size=(mw, mh))


