def render_outline_v3425(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('stark', auto_size(title, pivot=16), rng)
    mask_L = make_mask(title, font)

    mw, mh = mask_L.size
    base_color = (rng.randint(50, 200), rng.randint(50, 200), rng.randint(50, 200))
    stroke_colors = [(base_color[0] + rng.choice([-30, -10, 10, 30]), base_color[1] + rng.choice([-30, -10, 10, 30]), base_color[2] + rng.choice([-30, -10, 10, 30])) for _ in range(4)]

    outline_layers = []
    for i, color in enumerate(stroke_colors):
        thickness = rng.randint(max(i-1, 1), min(mw//50, mw//20))
        glow_radius = (thickness * rng.uniform(.75, 1.25), thickness * rng.uniform(0.4, .8)) if i < len(stroke_colors) - 1 else None
        outline_mask_L = dilate(mask_L, thickness)
        outline_R = flat_color(outline_mask_L, color)

        if glow_radius:
            glow_layer_RGBA = glow_layer(mask_L, color, [glow_radius])
            outline_R = composite(outline_R, glow_layer_RGBA, size=(mw, mh))

        outline_layers.append(outline_R)

    return composite(*outline_layers[::-1], size=(mw, mh))


