def render_outline_v5(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('stark', auto_size(title), rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    # Define the outline colors and stroke widths
    base_color = (rng.randint(0, 255), rng.randint(0, 255), rng.randint(0, 255))
    secondary_color = (rng.randint(0, 255), rng.randint(0, 255), rng.randint(0, 255))
    stroke_widths = [1 + i for i in range(rng.randint(3, 6))]

    # Create outline layers
    outlines = []
    for width in stroke_widths:
        if rng.random() > 0.5:
            color = base_color
        else:
            color = secondary_color

        if rng.random() > 0.5:
            glow_radius = [(width * 2, 1)]
        else:
            glow_radius = [(width, 0)]

        outline_layer = glow_layer(mask_L, color, radii=glow_radius)
        outlines.append(outline_layer)

    # Combine all the outline layers
    base_outline = composite(*outlines, size=(mw, mh))

    # Add inner glows for depth and contrast
    inner_glow_layers = []
    for _ in range(rng.randint(1, 3)):
        color = (rng.randint(0, 255), rng.randint(0, 255), rng.randint(0, 255))
        glow_radius = [(rng.randint(1, 4), rng.random() * 0.8)]
        inner_glow_layer = inner_glow(mask_L, color, radii=glow_radius)
        inner_glow_layers.append(inner_glow_layer)

    final_image = composite(base_outline, *inner_glow_layers, size=(mw, mh))
    
    return apply_mask(final_image, mask_L)


