    mw, mh = mask_L.size

    # Define primary outline colors and glow effects.
    primary_color_1 = (rng.randint(0, 255), rng.randint(0, 64), rng.randint(192, 255))
    primary_color_2 = (rng.randint(128, 255), rng.randint(32, 128), rng.randint(64, 192))

    glow_radius_1 = [(rng.uniform(.7 * mw / mh, .8 * mw / mh), 0.2 * rng.random()), (mw / mh, 0.4)]
    inner_glow_radius_1 = [(rng.uniform(.7 * mw / mh, .8 * mw / mh), rng.uniform(0.6, 1)), (mw / mh, 0.9)]

    glow_radius_2 = [(rng.uniform(.75 * mw / mh, .95 * mw / mh), 0.3 * rng.random()), (mw / mh, 0.6)]
    inner_glow_radius_2 = [(rng.uniform(.75 * mw / mh, .95 * mw / mh), rng.uniform(0.7, 1)), (mw / mh, 0.8)]

    # Create the primary outline with a thick stroke.
    outline_1 = glow_layer(dilate(mask_L, 2), primary_color_1, radii=glow_radius_1)
    inner_outline_1 = inner_glow(dilate(mask_L, -1), primary_color_1, radii=inner_glow_radius_1)

    # Create a secondary outline for depth and contrast.
    outline_2 = glow_layer(outline_1, primary_color_2, radii=glow_radius_2)
    inner_outline_2 = inner_glow(outline_1, primary_color_2, radii=inner_glow_radius_2)

    # Combine all layers to form the final graphic text.
    return composite(
        apply_mask(inner_outline_2, mask_L),
        apply_mask(outline_2, mask_L),
        apply_mask(inner_outline_1, mask_L),
        apply_mask(outline_1, dilate(mask_L, 1)),
        size=(mw, mh)
    )


