def render_outline_v761(title: str, rng: random.Random) -> Image.Image:
    font = F('stark', auto_size(title), rng)
    mask_L = make_mask(title.upper(), font)
    mw, mh = mask_L.size

    # Outer Glow Colors
    outer_glow_colors = [(rng.randint(0, 255), rng.randint(180, 255), rng.randint(0, 255)) for _ in range(rng.randint(2, 4))]
    
    # Ring Outline Widths and Angles
    ring_widths = [rng.randint(3, 6) for _ in range(rng.randint(2, 4))]
    ring_angles = [rng.uniform(-10, 10), rng.uniform(-15, -10), rng.uniform(10, 15)]
    
    # Create Outline Layers
    outline_layers = []
    dilated_mask_L = mask_L
    for width in ring_widths:
        glow_radii = [(width / 2 + rng.random() * width / 4, 0.2)] * (rng.randint(2, 3))
        outer_glow_rgba = glow_layer(dilated_mask_L, random.choice(outer_glow_colors), radii=glow_radii)
        
        # Bevel Highlights and Shadows
        bevel_angle = rng.choice(ring_angles)
        highlight_RGBA, shadow_RGBA = bevel_light(mask_L, bevel_angle, 0.5)
        
        # Composite Layers for Outlining Effect
        outline_layer = composite(outer_glow_rgba, apply_mask(highlight_RGBA, dilate(dilated_mask_L, width)), size=(mw, mh))
        outline_layers.append(outline_layer)

        # Update mask for next ring
        dilated_mask_L = dilate(dilated_mask_L, width)
    
    # Combine all outline layers into one composite image
    final_outline = composite(*outline_layers, size=(mw, mh))

    return final_outline


