def render_outline_v989(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('stark', auto_size(title), rng)
    mask_L = make_mask(title, font, pad=40)
    mw, mh = mask_L.size

    base_color = (rng.randint(20, 235), rng.randint(20, 235), rng.randint(20, 235))
    rings = [(base_color, rng.uniform(1.0, 4.0)), 
             (tuple(rng.randint(0, 255) for _ in range(3)), rng.uniform(5.0, 8.0)),
             (tuple(rng.randint(0, 255) for _ in range(3)), rng.uniform(9.0, 12.0))]

