def render_retro_v1023(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'retro'
    decade = rng.choice(['50s', '60s', '70s', '80s'])
    
    if decade == '50s':
        palette = [(255, 140, 0), (139, 69, 19), (0, 0, 0)]
        glow_color = (255, 204, 153)
    elif decade == '60s':
        palette = [(255, 255, 0), (0, 255, 255), (192, 192, 192)]
        glow_color = (0, 255, 255)
    elif decade == '70s':
        palette = [(255, 69, 0), (47, 79, 79), (0, 0, 0)]
        glow_color = (128, 0, 128)
    elif decade == '80s':
        palette = [(255, 0, 0), (0, 0, 255), (255, 255, 255)]
        glow_color = (255, 255, 0)

    font_size = auto_size(title)
    mask = make_mask(title, F(font_role, font_size, rng))
    
    mw, mh = mask.size
    main_color = palette[rng.randint(0, len(palette) - 1)]
    inner_glow_radius = [(rng.uniform(2.5, 4), rng.random()), (rng.uniform(1.5, 3), rng.random())]
    glow_radius = [(rng.uniform(6, 8), rng.random()), (rng.uniform(4, 6), rng.random())]

    base_layer = flat_color(mask, main_color)
    glow_layers = [glow_layer(mask, glow_color, glow_radius)]
    
    if rng.randint(0, 1):
        shadow_offset_x, shadow_offset_y = rng.randint(-2, 3), rng.randint(-2, 3)
        shadow_blur_radius = rng.randint(4, 6)
        shadow_alpha = int(rng.uniform(100, 150))
        glow_layers.append(drop_shadow(mask, shadow_offset_x, shadow_offset_y, shadow_blur_radius, shadow_alpha))

    final_glow_layer = composite(*glow_layers, size=(mw, mh))
    
    inner_glow_layer = inner_glow(dilate(mask, rng.randint(2, 3)), main_color, inner_glow_radius)
    
    bevel_angle_degrees = rng.uniform(10, 70)
    highlight_rgba, shadow_rgba = bevel_light(mask, bevel_angle_degrees, 0.5)
    
    layers = [base_layer, final_glow_layer, inner_glow_layer, apply_mask(highlight_rgba, mask), apply_mask(shadow_rgba, mask)]
    return composite(*layers, size=(mw, mh))


