def render_retro_v1251(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'retro'
    base_size = auto_size(title)
    font = F(font_role, base_size + 4, rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    # Retro color palette for the chosen decade
    colors = [(250, 180, 96), (237, 145, 33), (180, 125, 65),
              (166, 103, 65), (145, 115, 100), (205, 98, 97)]
    color1 = rng.choice(colors)
    color2 = rng.choice([c for c in colors if c != color1])

    # Text colorization
    text_color = flat_color(mask_L, color1)

    # Gradient effect
    gradient = colorize(mask_L, [color1, color2])

    # Glow effects
    glow_radius = [(rng.randint(0, 3), rng.uniform(0.5, 1))]
    glow = glow_layer(mask_L, (255, 255, 255), glow_radius)

    inner_glow_radius = [(rng.randint(1, 4), rng.uniform(0.7, 1.3)), (rng.randint(2, 5), rng.uniform(0.5, 0.8))]
    inner_glow_color = (color1[0] // 2, color1[1] // 2, color1[2] // 2)
    inner_glow_effect = inner_glow(mask_L, inner_glow_color, inner_glow_radius)

    # Bevel light effect
    bevel_angle_deg = rng.randint(30, 60)
    bevel_strength = rng.uniform(0.5, 1.5)
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    # Drop Shadow
    drop_shadow_radius = (rng.randint(-4, -2), rng.randint(3, 5))
    drop_shadow_blur = rng.randint(6, 10)
    drop_shadow_alpha = rng.randint(80, 120)
    shadow_effect = drop_shadow(mask_L, *drop_shadow_radius, drop_shadow_blur, drop_shadow_alpha)

    # Extrude effect
    extrude_depth = rng.randint(-3, -1)
    extrude_angle_deg = rng.uniform(45, 90)
    near_color = (20, 20, 20) if color1[0] > 128 else (60, 60, 60)
    far_color = (30, 30, 30) if color1[0] > 128 else (90, 90, 90)
    extruded_text = extrude(mask_L, extrude_depth, extrude_angle_deg, near_color, far_color)

    # Composite all layers
    return composite(extruded_text, shadow_effect, highlight_RGBA, inner_glow_effect, glow, gradient, text_color,
                     size=(mw, mh))


