def render_retro_v1311(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'retro'
    decade = ['50s', '60s', '70s', '80s', '90s'][rng.randint(0, 4)]
    
    if decade == '50s':
        palette = [(255, 127, 39), (173, 216, 230), (128, 0, 128)] # Coral, Sky Blue, Purple
    elif decade == '60s':
        palette = [(255, 0, 0), (255, 255, 0), (0, 255, 0)] # Red, Yellow, Green
    elif decade == '70s':
        palette = [(139, 69, 19), (255, 215, 0), (255, 69, 0)] # Brown, Gold, Orange-Red
    elif decade == '80s':
        palette = [(255, 182, 193), (0, 0, 255), (255, 255, 0)] # Pink-Purple, Blue, Yellow
    else: # 90s
        palette = [(255, 69, 0), (0, 128, 0), (135, 206, 235)] # Orange-Red, Green, Sky Blue
    
    font_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, font_size, rng))
    mw, mh = mask_L.size

    base_color = flat_color(mask_L, palette[rng.randint(0, 2)])
    
    gradient_colors = [palette[i] for i in sorted(rng.sample(range(len(palette)), rng.randint(2, min(6, len(palette)))))]
    color_layer = colorize(mask_L, gradient_colors)

    glow_radius_outer = [(rng.uniform(i * 1.5 + 0.5, (i+1) * 1.5 - 0.3), rng.uniform(0.1, 0.4)) for i in range(rng.randint(2, 4))]
    glow_layer_outer = glow_layer(mask_L, palette[rng.randint(0, len(palette)-1)], glow_radius_outer)

    inner_glow_radii = [(rng.uniform(i * 0.5 + 0.1, (i+1) * 0.5 - 0.2), rng.uniform(0.1, 0.3)) for i in range(rng.randint(2, 4))]
    glow_layer_inner = inner_glow(mask_L, palette[rng.randint(0, len(palette)-1)], inner_glow_radii)

    shadow_offset_x = int(rng.gauss(-5, 3))
    shadow_offset_y = int(rng.gauss(-5, 3))
    drop_shadow_layer = drop_shadow(dilate(mask_L, rng.randint(2, 4)), shadow_offset_x, shadow_offset_y, rng.randint(10, 20), rng.randint(70, 200))

    extrude_angle_deg = rng.uniform(20, 60)
    near_color = palette[rng.randint(0, len(palette)-1)]
    far_color = palette[rng.randint(0, len(palette)-1)]
    extrusion_layer = extrude(mask_L, rng.randint(3, 5), extrude_angle_deg, near_color, far_color)

    bevel_light_angle_deg = rng.uniform(20, 60)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, bevel_light_angle_deg, rng.uniform(0.4, 1))
    
    return composite(base_color, color_layer, glow_layer_outer, glow_layer_inner, drop_shadow_layer, extrusion_layer, apply_mask(highlight_rgba, mask_L), apply_mask(shadow_rgba, dilate(mask_L, 2)), size=(mw, mh))


