def render_retro_v15(title: str, rng: random.Random) -> Image.Image:
    mask_L = make_mask(title.upper(), F('retro', auto_size(title), rng))
    mw, mh = mask_L.size

    # Randomize colors for the era-specific palette (e.g., 80s pastel tones)
    base_color = flat_color(mask_L, (rng.randint(150,200), rng.randint(190,230), rng.randint(240,255)))
    
    # Gradient fill for a retro look
    gradient_colors = [(rng.randint(200, 220), rng.randint(180, 200), rng.randint(220, 240)),
                       (rng.randint(230, 250), rng.randint(190, 210), rng.randint(240, 255))]
    gradient_fill = colorize(mask_L, gradient_colors)

    # Glow effect to enhance the retro feel
    glow_color = (rng.randint(220, 240), rng.randint(200, 220), rng.randint(230, 250))
    glow_radius_outer = [(1, rng.random() * 0.7 + 0.6)]
    glow_outer = glow_layer(mask_L, glow_color, radii=glow_radius_outer)

    # Inner glow to add depth
    inner_glow_radius = [(rng.randint(1, 2), rng.random()), (3, 0.85 - rng.random() * 0.2)]
    inner_glow_effect = inner_glow(mask_L, glow_color, radii=inner_glow_radius)

    # Bevel effect for a vintage look
    angle_deg = rng.randint(10, 70)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, angle_deg, strength=rng.random() * 2 + 1.5)

    # Drop shadow to place the text in space
    drop_shadow_offset_x = rng.choice([-3, -2, -1, 0, 1])
    drop_shadow_offset_y = rng.randint(2, 4)
    drop_shadow_blur_radius = rng.randint(2, mh // 8)
    drop_shadow_alpha = rng.randint(60, 195)

    # Extrude effect to give the text a 3D appearance
    depth = rng.choice([1, 2])
    near_color = (rng.randint(220, 240), rng.randint(200, 220), rng.randint(230, 250))
    far_color = (rng.randint(200, 220), rng.randint(180, 200), rng.randint(220, 240))
    extrude_effect = extrude(mask_L, depth, angle_deg, near_color, far_color)

    return composite(base_color, gradient_fill, glow_outer, inner_glow_effect,
                     highlight_rgba, shadow_rgba, drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y,
                                                              drop_shadow_blur_radius, drop_shadow_alpha),
                     extrude_effect, size=(mw, mh))


