def render_retro_v2043(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = "retro"
    base_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, base_size, rng))
    mw, mh = mask_L.size

    # Randomize parameters for retro style
    decade = rng.choice(["30s", "40s", "50s", "60s", "70s", "80s", "90s"])
    if decade in ["30s", "40s"]:
        palette = [(128, 0, 0), (165, 42, 42), (210, 105, 30)]
    elif decade == "50s":
        palette = [(75, 0, 130), (255, 215, 0)]
    elif decade in ["60s", "70s"]:
        palette = [(0, 0, 0), (255, 215, 0), (0, 255, 0)]
    else:
        palette = [(0, 0, 0), (255, 255, 255)]

    main_color = rng.choice(palette)
    glow_radii = [(rng.randint(1, mw // 50), rng.uniform(.2, .6))]
    inner_glow_radii = [(rng.randint(mw // 80, mw // 40), rng.uniform(.2, .4))]

    # Create layers
    flat_layer = flat_color(mask_L, main_color)
    glow_layer_img = glow_layer(mask_L, main_color, radii=glow_radii)
    inner_glow_layer_img = inner_glow(mask_L, (main_color[0] // 2,) * 3, radii=inner_glow_radii)

    # Composite layers
    base_layer = composite(flat_layer, glow_layer_img, inner_glow_layer_img, size=(mw, mh))
    
    return base_layer


