    # Extrusion effect
    depth_int = mw // 80
    col_near_rgb = palette[rng.randint(0, 2)]
    col_far_rgb = (192, 192, 192) if rng.random() < 0.5 else palette[(rng.randint(0, 2)+1)%3]
    extrusion_effect = extrude(mask_L, depth_int, angle_deg, col_near_rgb, col_far_rgb)
    
    return composite(main_fill, glow_effect, inner_glow_effect, drop_shadow_effect, highlight_rgba, shadow_rgba, extrusion_effect, size=(mw, mh))


