def render_retro_v2175(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = "retro"
    mask_L = make_mask(title, F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    # Retro palette and effects
    primary_color = (rng.randint(200, 255), rng.randint(140, 180), rng.randint(160, 200))  # Pastel Blue
    secondary_color = (rng.randint(100, 140), rng.randint(130, 170), rng.randint(150, 190))  # Lighter Green
    tertiary_color = (rng.randint(80, 120), rng.randint(60, 100), rng.randint(40, 80))  # Dark Brown

    # Solid color fill with primary and secondary colors
    rgba_img = composite(flat_color(mask_L, primary_color),
                         flat_color(mask_L, secondary_color), size=(mw, mh))

    # Add a vertical gradient overlay
    gradient_colors = [tertiary_color, (255, 210, 140), (230, 190, 80)]
    rgba_img = composite(colorize(mask_L, gradient_colors), rgba_img, size=(mw, mh))

    # Add a glowing effect
    glow_rgb = (rng.randint(200, 255), rng.randint(140, 180), rng.randint(160, 200))
    glow_radius = [(rng.randint(3, 7), 0.3)]
    rgba_img = composite(glow_layer(mask_L, glow_rgb, glow_radius), rgba_img, size=(mw, mh))

    # Inner glow effect
    inner_glow_rgb = (rng.randint(150, 200), rng.randint(90, 140), rng.randint(70, 120))
    inner_glow_radii = [(rng.randint(3, 6), 0.2)]
    rgba_img = composite(inner_glow(mask_L, inner_glow_rgb, inner_glow_radii), rgba_img, size=(mw, mh))

    # Beveled light effect
    highlight_rgba, shadow_rgba = bevel_light(mask_L, rng.uniform(-45, 45), 0.3)
    rgba_img = composite(highlight_rgba, rgba_img, size=(mw, mh))
    rgba_img = composite(shadow_rgba, rgba_img, size=(mw, mh))

    # Drop shadow effect
    drop_shadow_offset_x = rng.randint(2, mw // 16)
    drop_shadow_offset_y = rng.randint(2, mh // 16)
    drop_shadow_blur_radius = rng.randint(mw // 30, mw // 20)
    rgba_img = composite(drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y,
                                     drop_shadow_blur_radius, rng.randint(50, 180)), rgba_img, size=(mw, mh))

    # Extrude effect
    extrude_depth = rng.randint(mw // 40, mw // 30)
    extrude_angle_deg = rng.uniform(-60, -20) if rng.random() > 0.5 else rng.uniform(20, 60)
    rgba_img = composite(extrude(mask_L, extrude_depth, extrude_angle_deg,
                                 primary_color, secondary_color), rgba_img, size=(mw, mh))

    return rgba_img


