    extruded_img = extrude(mask_L, extrusion_depth, extrusion_angle, near_color, far_color)

    return composite(base_img_rgba, drop_shadow_img, inner_glow_img, glow_effect, *bevel_effect, extruded_img, size=(mw, mh))


