    inner_glow_radius = [(mw//60, rng.random()), (mw//70, rng.random())]
    inner_glow_color = (rng.randint(128, 255), rng.randint(128, 255), rng.randint(128, 255))
    rgba_inner_glow = inner_glow(mask_L, inner_glow_color, inner_glow_radius)

