    highlight_rgba, shadow_rgba = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    # Drop shadow with random offset and blur radius
    drop_shadow_radius = rng.randint(1, mw//25)
    rgba_dropshadow = drop_shadow(mask_L, mw//70, mh//60, drop_shadow_radius, 192)

