def render_retro_v255(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'retro'
    mask_L = make_mask(title, F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    # Retro palette selection based on decade
    decade = rng.choice(['30s', '40s', '50s', '60s', '70s', '80s', '90s'])
    if decade == '30s':
        primary_colors = [(210, 105, 30), (184, 134, 11), (48, 27, 21)]
    elif decade == '40s':
        primary_colors = [(204, 196, 182), (144, 128, 115), (113, 94, 78)]
    elif decade == '50s':
        primary_colors = [(255, 140, 0), (165, 42, 42), (139, 69, 19)]
    elif decade == '60s':
        primary_colors = [(79, 187, 224), (100, 149, 237), (255, 69, 0)]
    elif decade == '70s':
        primary_colors = [(240, 230, 140), (184, 134, 11), (106, 90, 205)]
    elif decade == '80s':
        primary_colors = [(255, 0, 127), (255, 215, 0), (135, 206, 235)]
    else: # 90s
        primary_colors = [(250, 128, 114), (64, 224, 208), (173, 216, 230)]

    # Randomize color palette and glow parameters
    text_color = flat_color(mask_L, primary_colors[rng.randint(0, len(primary_colors) - 1)])
    glow_color = glow_layer(mask_L, primary_colors[(rng.randint(0, len(primary_colors) - 1)) % (len(primary_colors)-1)], [(4+rng.random(), 1.5+2*rng.random())])
    gradient_stops = [primary_colors[i] for i in sorted(rng.sample(range(len(primary_colors)), rng.randint(2, min(6, len(primary_colors)))))]
    gradient_image = colorize(mask_L, gradient_stops)

    # Bevel effect
    light_angle = 45 + 90 * rng.randint(0, 3)
    highlight_color, shadow_color = bevel_light(mask_L, light_angle, (1.0 - rng.random()) ** 2)
    
    # Add inner glow and drop shadow
    inner_glow_color = inner_glow(mask_L, primary_colors[rng.randint(0, len(primary_colors) - 1)], [(rng.uniform(2,4), rng.uniform(1.5,3))])
    drop_shadow_offset_x = rng.choice([-2, -1, 0, 1, 2])
    drop_shadow_offset_y = rng.choice([0, 1, 2]) if decade in ['90s', '80s'] else rng.choice([-1, 0, 1])
    drop_shadow_blur = int(rng.uniform(3, mw * 0.05))
    drop_shadow_alpha = int((rng.random() ** 3) * 255)
    
    return composite(text_color, glow_color, gradient_image, inner_glow_color, highlight_color, shadow_color, drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y, drop_shadow_blur, drop_shadow_alpha), size=(mw, mh))


