    glow_colors = [rng.choice(colors) for _ in range(2, 6)]
    glows = glow_layer(mask_L, random.choice(glow_colors), radii=[(3 * i / mw, 0.1 + 0.1 * i / mh) for i in range(4)])

    inner_glows = inner_glow(mask_L, (51, 153, 255), radii=[(rng.randint(1, 4) * mw / 100, rng.uniform(0.05, 0.2)) for _ in range(3)])

    shadow = drop_shadow(mask_L, -mw // 8, mh // 6, mw // 12, int(rng.gammavariate(2, 127)))

    bevel_hl, bevel_shd = bevel_light(mask_L, rng.randint(-45, 45), strength=0.3)

    extruded = extrude(mask_L, mw // 60, -rng.randint(45, 90), (135, 206, 250), (75, 0, 130))

    layers = [base_color, glows, inner_glows, shadow, bevel_hl, bevel_shd, extruded]
    return composite(*layers, size=(mw, mh))


