def render_retro_v279(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = "retro"
    decade = rng.choice(["30s", "40s", "50s", "60s", "70s", "80s", "90s"])
    
    if decade == "30s":
        palette = [(128, 0, 0), (255, 0, 0), (0, 0, 255)]
    elif decade == "40s":
        palette = [(64, 64, 64), (192, 192, 192), (255, 255, 0)]
    elif decade == "50s":
        palette = [(255, 192, 0), (0, 192, 255), (255, 64, 64)]
    elif decade == "60s":
        palette = [(255, 255, 255), (238, 173, 173), (128, 0, 128)]
    elif decade == "70s":
        palette = [(47, 79, 79), (255, 69, 0), (255, 215, 0)]
    elif decade == "80s":
        palette = [(255, 0, 255), (0, 255, 255), (255, 255, 0)]
    else:  # 90s
        palette = [(165, 42, 42), (30, 144, 255), (255, 255, 0)]

    font_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, font_size, rng))
    mw, mh = mask_L.size

    # Base flat color
    base_color = palette[rng.randint(0, len(palette)-1)]
    flat_rgba = apply_mask(flat_color(mask_L, base_color), mask_L)

    # Gradient overlay
    gradient_colors = [base_color] + rng.sample(palette, 2)
    gradient_rgba = apply_mask(colorize(mask_L, gradient_colors), mask_L)

    # Glow effect
    glow_color = palette[rng.randint(0, len(palette)-1)]
    glow_radii = [(rng.uniform(3, mw/50), rng.uniform(mw/40, mw/20))]
    glow_rgba = apply_mask(glow_layer(mask_L, glow_color, radii=glow_radii), mask_L)

    # Bevel and inner glow
    angle_deg = rng.randint(150, 210)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, angle_deg, strength=rng.uniform(0.3, 0.6))
    
    inner_glow_color = palette[rng.randint(0, len(palette)-1)]
    inner_glow_radii = [(rng.uniform(mw/250, mw/150), rng.uniform(mw/400, mw/200))]
    inner_glow_rgba = apply_mask(inner_glow(mask_L, inner_glow_color, radii=inner_glow_radii), mask_L)

    # Drop shadow
    drop_shadow_offset_x = int(rng.uniform(-mw/15, mw/15))
    drop_shadow_offset_y = int(rng.uniform(mw/20, mw/10))
    drop_shadow_blur_radius = int(rng.uniform(3, mw/40))
    drop_shadow_opacity = rng.randint(64, 192)
    shadow_rgba = apply_mask(drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y,
                                         drop_shadow_blur_radius, drop_shadow_opacity), mask_L)

    # Combine layers
    return composite(shadow_rgba, flat_rgba, gradient_rgba, glow_rgba, inner_glow_rgba,
                     size=(mw, mh))


