    inner_glow_colors = [(rng.randint(230, 250), rng.randint(190, 210), rng.randint(70, 90)),
                         (rng.randint(200, 240), rng.randint(160, 200), rng.randint(50, 80))]
    bevel_angle = rng.uniform(-30, 30)
    bevel_strength = rng.uniform(0.2, 0.7)

    # Apply effects
    base_img = flat_color(mask_L, base_color)
    highlight, shadow = bevel_light(mask_L, bevel_angle, bevel_strength)
    glow = glow_layer(mask_L, glow_color, [(5 + rng.randint(-1, 1), 2 * (0.3 + rng.uniform(0, 0.7)))])

    # Composite layers
    return composite(base_img,
                     flat_color(mask_L, highlight_color),
                     flat_color(mask_L, shadow_color),
                     inner_glow(mask_L, glow_color, [(5 + rng.randint(-1, 1), 2 * (0.3 + rng.uniform(0, 0.7)))]),
                     colorize(mask_L, inner_glow_colors),
                     glow,
                     highlight,
                     shadow,
                     size=(mw, mh))


