def render_retro_v3375(title: str, rng: random.Random) -> Image.Image:
    mask_L = make_mask(title.upper(), F('retro', 20 + auto_size(title), rng))
    mw, mh = mask_L.size

    # Retro palette for the 80s
    color_stops_80s = [(153, 76, 0), (0, 191, 255), (255, 242, 0)]
    base_color_RGBA = flat_color(mask_L, rng.choice(color_stops_80s))
    gradient_RGBA = colorize(mask_L, [c for c in rng.sample(color_stops_80s, 3)])

    # Bevel and glow effects
    angle_deg = rng.randint(120, 240)
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, angle_deg, 0.6 + rng.random() * 0.5)
    bloom_radii = [(rng.randint(3, 7), rng.uniform(0.4, 1)), (8, rng.uniform(1, 2))]
    glow_RGBA = glow_layer(mask_L, rng.choice(color_stops_80s), radii=bloom_radii)

    # Inner glow for depth
    inner_glow_RGBAs = []
    inner_colors = [(51, 153, 255), (255, 69, 0)]
    for i in range(2):
        color = rng.choice(inner_colors)
        radii = [(rng.randint(1, 3) + i * 4, rng.uniform(i+0.2, i+0.7))]
        inner_glow_RGBAs.append(inner_glow(mask_L, color, radii))

    # Extrusion and drop shadow
    extrude_depth = rng.randint(5, 12)
    col_near_rgb = (89, 46, 38) if rng.random() < 0.7 else (64, 64, 64)
    col_far_rgb = (255, 255, 255) if rng.random() < 0.7 else (128, 128, 128)
    extrude_RGBA = extrude(mask_L, extrude_depth, angle_deg + 90, col_near_rgb, col_far_rgb)

    shadow_x_int = rng.randint(4, 8)
    shadow_y_int = rng.randint(-3, 3)  # slight vertical offset
    blur_radius = rng.randint(15, 25)
    alpha_val = int(rng.uniform(60, 90))
    drop_shadow_RGBA = drop_shadow(mask_L, shadow_x_int, shadow_y_int, blur_radius, alpha_val)

    return composite(base_color_RGBA, gradient_RGBA, highlight_RGBA, shadow_RGBA,
                     glow_RGBA, *inner_glow_RGBAs, extrude_RGBA, drop_shadow_RGBA,
                     size=(mw, mh))


