    title = title.upper()
    font_role = 'retro'
    mask_L = make_mask(title, F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    # Define a retro color palette for the chosen decade (1970s example)
    palette_1970s = [(255, 69, 0), (46, 139, 87), (255, 215, 0)]

    # Randomly select base color for solid fill
    base_color = rng.choice(palette_1970s)
    flat_fill = flat_color(mask_L, base_color)

    # Add glow effect with randomized radius and color from palette
    glow_radius = [(rng.randint(2, 5), rng.uniform(0.3, 0.6))]
    glow_color = rng.choice(palette_1970s)
    glow_effect = glow_layer(mask_L, glow_color, radii=glow_radius)

    # Create inner glow with a different color from the palette
    inner_glow_radius = [(rng.randint(2, 4), rng.uniform(0.3, 0.5))]
    inner_glow_color = rng.choice(palette_1970s)
    rim_effect = inner_glow(mask_L, inner_glow_color, radii=inner_glow_radius)

    # Apply a bevel light effect to give depth
    angle_deg = rng.randint(20, 60) + rng.random() * 5
    strength = rng.uniform(1.5, 3)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, angle_deg, strength)

    # Add a drop shadow with randomized offset and blur radius
    dx_dy = (rng.randint(-2, 2), rng.randint(-2, 2))
    blur_radius = rng.randint(4, 8)
    drop_shadow_effect = drop_shadow(mask_L, dx_dy[0], dx_dy[1], blur_radius, 64)

    # Combine all effects with the solid fill
    result_img = composite(flat_fill, glow_effect, rim_effect, highlight_rgba,
                            shadow_rgba, drop_shadow_effect, size=(mw, mh))

    return result_img


