def render_retro_v639(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'retro'
    mask_L = make_mask(title, F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    # Randomize parameters based on decade
    decade = [1930 + 10 * i for i in range(7)][rng.randint(0, 6)]
    if decade <= 1959:
        palette = [(255, 255, 255), (0, 185, 241), (255, 130, 0)]  # Retro classic
        glow_radius = rng.uniform(0.6, 1.2)
    else:
        palette = [(0, 0, 0), (255, 255, 0), (194, 57, 38)]  # Modern retro with neon influences
        glow_radius = rng.uniform(1.5, 2.5)

    base_color = flat_color(mask_L, palette[rng.randint(0, len(palette) - 1)])
    gradient_color = colorize(mask_L, [palette[i % len(palette)] for i in range(3)])

    glow_effect = glow_layer(mask_L, (rng.randint(200, 255), rng.randint(200, 255), rng.randint(200, 255)), [(glow_radius, rng.random())])
    bevel_highlight, bevel_shadow = bevel_light(mask_L, rng.uniform(-45, 135), rng.random() * 0.5 + 0.8)

    shadow_effect = drop_shadow(mask_L, int(rng.gauss(2, 1)), int(rng.gauss(6, 2)), int(rng.gauss(4, 1)), rng.randint(60, 190))

    extruded_image = extrude(mask_L, int(rng.gauss(3, 1)), rng.uniform(-45, 135), palette[rng.randint(0, len(palette) - 1)], palette[(rng.randint(0, len(palette) - 1)) + 1])

    return composite(base_color, gradient_color, glow_effect, bevel_highlight, bevel_shadow, shadow_effect, extruded_image, size=(mw, mh))


