def render_retro_v711(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'retro'
    font_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, font_size, rng))
    mw, mh = mask_L.size

    base_color = flat_color(mask_L, (255, 193, 37))  # Retro yellow
    gradient_colors = [(0, 244, 241), (186, 23, 186)]  # Gradient from blue to pinkish
    colorized_img = colorize(mask_L, gradient_colors)

    glow_color = (197, 151, 255)  # Retro purple
    glow_radii = [(0, rng.uniform(4, 6)), (3, rng.uniform(8, 12))]
    glow_layer_img = glow_layer(mask_L, glow_color, glow_radii)

    inner_glow_color = (255, 217, 99)  # Retro yellowish
    inner_glow_radii = [(0, rng.uniform(3, 4)), (2, rng.uniform(6, 8))]
    inner_glow_img = inner_glow(mask_L, inner_glow_color, inner_glow_radii)

    bevel_angle = rng.choice([120, 270])  # Retro light angle
    highlight, shadow = bevel_light(mask_L, bevel_angle, strength=30)
    bevel_img = composite(highlight, shadow, size=(mw, mh))

    drop_shadow_color = (45, 45, 45)  # Retro dark grey
    drop_shadow_offset_x = rng.randint(-2, 2)
    drop_shadow_offset_y = rng.randint(3, 5)
    drop_shadow_blur_radius = rng.randint(6, 8)
    drop_shadow_alpha = rng.randint(100, 200)
    shadow_img = drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y,
                              drop_shadow_blur_radius, drop_shadow_alpha)

    extruded_depth = rng.randint(3, 5)
    extrude_angle = rng.choice([45, 90])
    near_color = (255, 165, 0)  # Retro orange
    far_color = (255, 78, 78)   # Retro redish
    extruded_img = extrude(mask_L, extruded_depth, extrude_angle, near_color, far_color)

    return composite(base_color, colorized_img, glow_layer_img,
                     inner_glow_img, bevel_img, shadow_img, extruded_img, size=(mw, mh))


