def render_rusted_iron(title: str, rng: random.Random) -> Image.Image:
    font = F('heavy', auto_size(title), rng)
    mask_L = make_mask(title.upper(), font)
    mw, mh = mask_L.size

    # Base iron gray colorize layer
    base_color = (51, 51, 40)
    base_layer = flat_color(mask_L, base_color)

    # Generate rust noise and overlay as tint
    rust_noise = np.random.rand(mw, mh) * rng.uniform(2.0, 3.5)
    rust_colors = [(165 + int(x), 42 + int(y), 0) for x in np.linspace(20, 80, 3) for y in np.linspace(40, 90, 3)]
    rust_layer = colorize(dilate(mask_L, rng.randint(-2, 1)), rust_colors)

    # Bevel effect
    bevel_angle_deg = 315 + rng.randint(-10, 10)
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, bevel_angle_deg, strength=rng.uniform(0.1, 0.4))

    return composite(base_layer,
                     rust_layer,
                     apply_mask(highlight_RGBA, mask_L),
                     apply_mask(shadow_RGBA, mask_L),
                     size=(mw, mh))


