def render_space_chrome_dark_wild1743(title: str, rng: random.Random) -> Image.Image:
    font_role = "tech"
    title_upper = title.upper()
    font_size = auto_size(title)
    font_obj = F(font_role, size=font_size, rng=rng)
    mask_L = make_mask(title_upper, font_obj, pad=40)
    mw, mh = mask_L.size

    # Base colorize with random purple/blue tint
    base_colors = [(128, 128, 128), (64, 64, 64)]
    space_tint = (rng.randint(50, 100), rng.randint(100, 130), rng.randint(130, 170))
    colorize_layers = base_colors + [space_tint]
    rgba_img_base = colorize(mask_L, colorize_layers)

    # Bevel effect
    bevel_angle_deg = rng.uniform(-45, -20)
    bevel_strength = rng.uniform(0.3, 0.7)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    # Outer glow in deep blue at large radius
    outer_glow_color = (0, rng.randint(50, 100), rng.randint(80, 120))
    outer_glow_radii = [(rng.uniform(3.0, 6.0), rng.uniform(1.0, 2.0))]
    rgba_img_outer_glow = glow_layer(mask_L, outer_glow_color, radii=outer_glow_radii)

    # Inner glow in white
    inner_glow_color = (255, 255, 255)
    inner_glow_radii = [(rng.uniform(0.3, 1.0), rng.uniform(1.5, 2.5))]
    rgba_img_inner_glow = inner_glow(mask_L, inner_glow_color, radii=inner_glow_radii)

    # Combine all layers
    final_rgba_img = composite(
        apply_mask(rgba_img_base, mask_L),
        apply_mask(highlight_rgba, dilate(mask_L, 1)),
        apply_mask(shadow_rgba, dilate(mask_L, -1)),
        rgba_img_outer_glow,
        rgba_img_inner_glow,
        size=(mw, mh)
    )

    return final_rgba_img


