    mw, mh = mask_L.size

    base_color = (96, 96, 96)
    space_tint_colors = [(85 + rng.randint(-20, 20), 85 + rng.randint(-20, 20), 170),
                         (40 + rng.randint(0, 30), 40 + rng.randint(0, 30), 160)]
    bevel_angle = 135 + rng.uniform(-20, 20)
    glow_radius = [(rng.uniform(8, 12), rng.random() * 0.2 + 0.2)]

    base_layer = flat_color(mask_L, base_color)
    space_tinted_layer = colorize(mask_L, space_tint_colors)

    bevel_highlight, bevel_shadow = bevel_light(mask_L, bevel_angle, 140 + rng.randint(0, 50))
    outer_glow = glow_layer(dilate(mask_L, 2), (30, 30, 90), radii=glow_radius)
    inner_white_glow = inner_glow(mask_L, (255, 255, 255), [(rng.uniform(1.5, 2.5), rng.random() * 0.4 + 0.3)])

    final_layer = composite(base_layer,
                            space_tinted_layer,
                            bevel_highlight,
                            bevel_shadow,
                            outer_glow,
                            inner_white_glow,
                            size=(mw, mh))
    return final_layer


