    drop_shadow_img = drop_shadow(mask_L, dx, dy, int(3 + rng.random() * 4), 80)

    return composite(base_color, glow_layer_img, highlight_RGBA, shadow_RGBA, inner_glow_img, drop_shadow_img, size=(mw, mh))


