    gradient_colors = [(rng.randint(0, 128), rng.randint(128, 255), rng.randint(128, 255)),
                       (rng.randint(128, 255), rng.randint(64, 192), rng.randint(64, 192))]
    colorized_img = colorize(mask_L, gradient_colors)

    glow_radii = [(3 + rng.random() * 5, 0.2 + rng.random() * 0.8)]
    glow_color = (rng.randint(224, 255), rng.randint(160, 255), rng.randint(64, 192))
    glow_layer_img = glow_layer(mask_L, glow_color, radii=glow_radii)

    inner_glow_radii = [(2 + rng.random() * 3, 0.2 + rng.random() * 0.8),
                        (5 + rng.random() * 7, 0.1 + rng.random() * 0.4)]
    inner_glow_color = (rng.randint(64, 192), rng.randint(0, 128), rng.randint(128, 255))
    inner_glow_img = inner_glow(mask_L, inner_glow_color, radii=inner_glow_radii)

    bevel_angle_deg = (rng.random() * 360) % 360
    bevel_strength = rng.uniform(0.4, 1.2)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    drop_shadow_ox = rng.randint(-8, 8)
    drop_shadow_oy = rng.randint(-8, 8)
