    drop_shadow_alpha = rng.randint(64, 192)
    shadow_img = drop_shadow(mask_L, drop_shadow_ox, drop_shadow_oy, drop_shadow_blur_radius, drop_shadow_alpha)

    return composite(base_color,
                     colorized_img,
                     glow_layer_img,
                     inner_glow_img,
                     apply_mask(highlight_rgba, dilate(mask_L, 2)),
                     apply_mask(shadow_rgba, dilate(mask_L, -2)),
                     shadow_img,
                     size=(mw, mh))


