def render_sport_v1523(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'athletic'
    font_size = auto_size(title, base=200, pivot=14)
    mask_L = make_mask(title, F(font_role, font_size, rng))
    mw, mh = mask_L.size

    bg_color = flat_color(mask_L, (rng.randint(0, 50), rng.randint(0, 50), rng.randint(200, 255)))
    glow_radii = [(10 * rng.random(), 30 + 40 * rng.random())]
    bloom_outer = glow_layer(mask_L, (rng.randint(200, 255), rng.randint(200, 255), rng.randint(0, 80)), radii=glow_radii)

    inner_glow_color = (rng.randint(120, 200), rng.randint(120, 200), rng.randint(160, 255))
    bloom_inner = inner_glow(mask_L, inner_glow_color, radii=[(4 * rng.random(), 3 + 8 * rng.random()), (10 * rng.random(), 7.5 + 12.5 * rng.random())])

    shadow_x = int(rng.uniform(-mw // 8, mw // 6))
    shadow_y = int(rng.uniform(mw // 12, mw // 3))
    drop_shadow_intensity = int(rng.uniform(0.4 * mh, 0.8 * mh))

    text_dropshadow = drop_shadow(mask_L, shadow_x, shadow_y, int(shadow_y / 5), int(drop_shadow_intensity * rng.random()))

    highlight_angle_deg = rng.randint(-60, 60)
    light_highlight_strength = rng.uniform(0.7, 1.2)
    (text_light_highlight, text_dark_shadow) = bevel_light(mask_L, highlight_angle_deg, light_highlight_strength)

    extrude_depth = int(rng.uniform(3 * mh / 400, 5 * mh / 400))
    extrude_angle_deg = rng.randint(-60, 60)
    near_color = (rng.randint(200, 255), rng.randint(200, 255), rng.randint(180, 255))
    far_color = (rng.randint(70, 120), rng.randint(70, 120), rng.randint(40, 160))

    text_extrude = extrude(mask_L, extrude_depth, extrude_angle_deg, near_color, far_color)

    return composite(bg_color, bloom_outer, bloom_inner, text_dropshadow, text_light_highlight, apply_mask(text_extrude, mask_L), size=(mw, mh))


