    drop_shadow_blur_radius = rng.randint(2, mh // 4)
    drop_shadow_alpha = rng.randint(64, 192)
    drop_shadow_RGBA = drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y, drop_shadow_blur_radius, drop_shadow_alpha)

    extrusion_depth = rng.randint(mh // 8, mh // 4)
    highlight_color = (rng.randint(200, 255), rng.randint(128, 192), rng.randint(64, 128))
    shadow_color = (rng.randint(32, 64), rng.randint(0, 64), rng.randint(0, 32))
    extrusion_RGBA = extrude(mask_L, extrusion_depth, highlight_angle, highlight_color, shadow_color)

    # Composite all layers
    return composite(extrusion_RGBA, inner_glow_RGBA, glow_layer_RGBA, drop_shadow_RGBA, apply_mask(flat_color(mask_L, base_color), mask_L), size=(mw, mh))


