def render_sport_v251(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'athletic'
    mask_L = make_mask(title, F(font_role, 40 + auto_size(title), rng))
    mw, mh = mask_L.size

    # Solid color fill with glow effect
    base_color = (rng.randint(150, 255), rng.randint(80, 160), rng.randint(30, 90))
    rgba_img = flat_color(mask_L, base_color)
    glow_radii = [(5 + i * rng.random(), 4 + i) for i in range(3)]
    glow_img = glow_layer(mask_L, (rng.randint(200, 255), rng.randint(160, 210), rng.randint(100, 180)), glow_radii)

    # Inner edge highlight with inner glow
    inner_color = (base_color[0] + 30, base_color[1] - 20, base_color[2])
    inner_glow_img = inner_glow(mask_L, inner_color, [(4 + rng.random(), 4), (6 + rng.random() * 2, 5)])

    # Beveled edge with drop shadow
    angle_deg = 90 + rng.randint(-10, 10)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, angle_deg, strength=80 / mh)
    drop_shadow_img = drop_shadow(mask_L, int(rng.gauss(5, 2)), int(rng.gauss(3, 1)), int(rng.gauss(4, 1)), 128)

    # Extrude effect for depth and texture
    extrusion_depth = int(rng.randint(10, 20))
    near_color = (base_color[0] - 50, base_color[1], base_color[2])
    far_color = (rng.randint(0, 30), rng.randint(50, 80), rng.randint(40, 70))
    extrude_img = extrude(mask_L, extrusion_depth, angle_deg - 90, near_color, far_color)

    # Composite all layers
    return composite(extrude_img, inner_glow_img, glow_img, rgba_img, drop_shadow_img, size=(mw, mh))


