    inner_glow_effect = inner_glow(mask_L, (rng.randint(150, 255), rng.randint(100, 200), rng.randint(80, 170)), radii=[(mw // 60 + rng.random(), mh / mw * mw // 60 + rng.random()), (mw // 30 + rng.random(), mh / mw * mw // 30 + rng.random())])
    shadow = drop_shadow(mask_L, rng.randint(-15, 15), rng.randint(20, 40), rng.randint(10, 20), rng.randint(80, 160))
    bevel_effect = bevel_light(mask_L, rng.uniform(0, 360), rng.random())

    extruded = extrude(mask_L, rng.randint(-5, -2), rng.uniform(0, 360), (rng.randint(40, 80), rng.randint(60, 120), rng.randint(70, 130)), (rng.randint(150, 255), rng.randint(100, 200), rng.randint(80, 170)))

    return composite(solid_fill, color_gradient, glow, inner_glow_effect, shadow, bevel_effect[0], bevel_effect[1], extruded, size=(mw, mh))


