def render_sport_v827(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'athletic'
    size = auto_size(title)
    mask_L = make_mask(title, F(font_role, size, rng))
    mw, mh = mask_L.size

    # Base color and glow
    base_color = (rng.randint(50, 130), rng.randint(120, 200), rng.randint(180, 250))
    glow_radii = [(int(rng.gauss(4, 2)), float(rng.uniform(.6, .9))) for _ in range(2)]
    glow_img = flat_color(mask_L, base_color)
    glow_layer_rgba = glow_layer(mask_L, base_color, radii=glow_radii)

    # Bevel and inner glow
    angle_deg = rng.randint(-45, 45)
    strength = rng.uniform(.6, .9)
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, angle_deg, strength)
    inner_glow_rgba = inner_glow(mask_L, base_color, radii=[(int(rng.gauss(10, 3)), float(rng.uniform(.4, .7)))])

    # Drop shadow
    ox_int, oy_int = int(rng.gauss(-2, 2)), int(rng.gauss(5, 2))
    blur_int = int(rng.gauss(6, 2))
    alpha_0to255 = rng.randint(100, 220)
    drop_shadow_rgba = drop_shadow(mask_L, ox_int, oy_int, blur_int, alpha_0to255)

    # Composite layers
    return composite(glow_layer_rgba, inner_glow_rgba, highlight_RGBA, shadow_RGBA, drop_shadow_rgba, glow_img, size=(mw, mh))


