def render_sport_v83(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'athletic'
    base_font_size = auto_size(title)
    mask_L = make_mask(title, F(font_role, base_font_size, rng))
    mw, mh = mask_L.size

    # Core text color
    core_color = flat_color(mask_L, (rng.randint(0, 255), rng.randint(169, 255), rng.randint(0, 169)))
    
    # Gradient for impact effect
    gradient_colors = [(rng.randint(0, 255), rng.randint(180, 255), rng.randint(0, 169)),
                       (rng.randint(127, 255), rng.randint(0, 127), rng.randint(0, 255))]
    gradient = colorize(mask_L, gradient_colors)
    
    # Glow effect
    glow_radii = [(rng.randint(3, 6) + rng.random(), rng.uniform(0.5, 1.5))]
    glow_color = (rng.randint(0, 80), rng.randint(240, 255), rng.randint(0, 255))
    glow_effect = glow_layer(mask_L, glow_color, glow_radii)
    
    # Inner Glow
    inner_glow_colors = [(rng.randint(0, 169), rng.randint(80, 255), rng.randint(0, 255))]
    inner_radius = (rng.randint(1, 3) + rng.random(), rng.uniform(0.4, 0.7))
    inner_glow_effect = inner_glow(mask_L, glow_color, [inner_radius])
    
    # Bevel effect
    angle_deg = rng.randint(25, 65)
    strength = rng.uniform(0.3, 1.0)
    highlight, shadow = bevel_light(mask_L, angle_deg, strength)

    # Drop Shadow
    drop_shadow_offset_x = -rng.randint(-7, -3)
    drop_shadow_offset_y = rng.randint(2, 6)
    drop_shadow_blur_radius = rng.randint(4, 8)
    drop_shadow_alpha = rng.randint(100, 200)
    shadow_layer = drop_shadow(mask_L, drop_shadow_offset_x, drop_shadow_offset_y,
                               drop_shadow_blur_radius, drop_shadow_alpha)

    # Extrude effect
    depth = rng.randint(3, 6)
    angle_deg_extrude = -rng.randint(-45, -10) + (90 * rng.choice([-1, 1]))
    near_color = (rng.randint(200, 255), rng.randint(80, 169), rng.randint(0, 80))
    far_color = (rng.randint(0, 70), rng.randint(180, 255), rng.randint(0, 240))
    extrude_effect = extrude(mask_L, depth, angle_deg_extrude, near_color, far_color)

    return composite(extrude_effect, glow_effect, inner_glow_effect, core_color,
                     gradient, shadow_layer, highlight, size=(mw, mh))


