# ============================================================

def render_stained_glass_med(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F("serif", auto_size(title), rng)
    mask_L = make_mask(title, font, pad=40)
    mw, mh = mask_L.size

    jewel_colors = [(255, 0, 0), (0, 0, 255), (0, 128, 0), (255, 165, 0)]
    base_color = rng.choice(jewel_colors)
    gradient_stops = [base_color, rng.choice(jewel_colors)]

    jewel_text = colorize(mask_L, gradient_stops)

    black_ring_thickness = rng.randint(6, 8)
    thick_outline_mask = dilate(mask_L, black_ring_thickness)
    highlight_RGBA, shadow_RGBA = bevel_light(thick_outline_mask, angle_deg=rng.uniform(-45, 45), strength=0.7)
    black_bevel = composite(shadow_RGBA, highlight_RGBA, size=(mw, mh))

    final_layer = composite(jewel_text, black_bevel, size=(mw, mh))
    
    if rng.randint(1, 2) == 1:
        gold_color = (255, 215, 0)
        thin_ring_thickness = rng.randint(2, 4)
        thin_outline_mask = dilate(mask_L, thin_ring_thickness)
        final_layer = composite(final_layer, flat_color(thin_outline_mask, gold_color), size=(mw, mh))

    return apply_mask(final_layer, mask_L)


