def render_sticker_bomb_wild2429(title: str, rng: random.Random) -> Image.Image:
    font_role = "comic"
    mask_L = make_mask(title.upper(), F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    # Randomize parameters
    base_color = (rng.randint(0, 255), rng.randint(128, 255), rng.randint(0, 127))
    outline_widths = [4, 2]
    outline_colors = ["white", "black"]
    bevel_angle_deg = rng.uniform(-60, 60)
    bevel_strength = rng.uniform(0.3, 0.8)
    glow_radii = [(rng.randint(1, 5), 0.4 + rng.random() * 0.2) for _ in range(3)]
    candy_colors = [
        (rng.randint(0, 255), rng.randint(64, 192), rng.randint(0, 127)),
        (rng.randint(0, 255), rng.randint(128, 255), rng.randint(0, 255))
    ]
    drop_shadow_offset = (rng.choice([-3, -2, -1, 1, 2, 3]), rng.choice([4, 5]))
    drop_shadow_blur = rng.randint(4, 8)
    drop_shadow_alpha = rng.randint(64, 192)

    # Outline rings
    outline_layers = []
    for width, color in zip(outline_widths, outline_colors):
        dilated_mask_L = dilate(mask_L, width // 2)
        outline_layer = flat_color(dilated_mask_L, (255, 255, 255) if color == "white" else (0, 0, 0))
        outline_layers.append(outline_layer)

    # Base color
    base_fill_layer = flat_color(mask_L, base_color)
    
    # Candy colorize gradient
    candy_layer = colorize(mask_L, candy_colors)

    # Strong bevel
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    # Specular inner glow
    white_specular_glow = inner_glow(mask_L, (255, 255, 255), glow_radii)
    
    # Chunky drop shadow
    chunky_shadow = drop_shadow(mask_L, *drop_shadow_offset, drop_shadow_blur, drop_shadow_alpha)

    return composite(*outline_layers + [base_fill_layer, candy_layer, highlight_RGBA, shadow_RGBA, white_specular_glow, chunky_shadow], size=(mw, mh))


