def render_sticker_bomb_wild63(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font_role = 'comic'
    mask_L = make_mask(title, F(font_role, auto_size(title), rng))
    mw, mh = mask_L.size

    # Randomize parameters
    candy_color = (rng.randint(0, 255), rng.randint(180, 255), rng.randint(0, 150))
    bevel_angle_deg = rng.uniform(30, 60)
    bevel_strength = rng.uniform(0.9, 1.2)
    drop_shadow_intensity = rng.choice([4, 6])
    inner_glow_radius = [(rng.uniform(3, 5), rng.uniform(0.7, 1)), (rng.uniform(2, 3), rng.uniform(0.8, 1))]

    # Build outline rings
    mask_white_outline = glow_layer(mask_L, (255, 255, 255), [(4, rng.uniform(0.6, 0.9))])
    mask_black_outline = inner_glow(dilate(mask_white_outline, -1).convert('L'), (0, 0, 0), [(2, rng.uniform(0.8, 1))])

    # Apply bevel light effect
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    # Colorize with candy colors and add drop shadow
    candy_layer = colorize(mask_L, [candy_color, (255, 190, 165), (255, 127, 80)])

    drop_shadow_layer = drop_shadow(dilate(candy_layer.convert('L'), -drop_shadow_intensity),
                                    rng.randint(-4, 4), rng.randint(3, 6), 128,
                                    rng.uniform(64, 192))

    # Add white inner glow
    inner_glow_layer = inner_glow(mask_L, (255, 255, 255), inner_glow_radius)

    return composite(drop_shadow_layer, candy_layer, mask_black_outline, mask_white_outline, highlight_RGBA, shadow_RGBA,
                     inner_glow_layer, size=(mw, mh))


