def render_texture_v1264(title: str, rng: random.Random) -> Image.Image:
    font_role = 'slab'
    size = auto_size(title)
    mask_L = make_mask(title.upper(), F(font_role, size, rng))
    mw, mh = mask_L.size

    # Generate a noisy texture (simulating cloth or fabric)
    base_texture = np.random.rand(mw, mh) * 255
    blurred_texture = Image.fromarray(np.uint8(base_texture)).filter(ImageFilter.BLUR)

    # Apply color variations to the texture
    colors = [(rng.randint(100, 200), rng.randint(100, 200), rng.randint(100, 255)) for _ in range(rng.randint(3, 6))]
    textured_image = colorize(mask_L, colors)

    # Add a bevel effect to the letters
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, angle_deg=rng.uniform(-45, 45), strength=0.8)
    
    # Create an inner glow for depth and realism
    inner_glow_rgba = inner_glow(mask_L, (rng.randint(200, 230), rng.randint(170, 200), rng.randint(160, 255)), [(mw/80, mh/80)])

    # Apply extrusion to make letters pop out
    depth = rng.randint(2, mw//40)
    angle_deg = rng.uniform(-30, 30)
    col_near_rgb = (rng.randint(160, 255), rng.randint(160, 255), rng.randint(160, 255))
    col_far_rgb = (rng.randint(100, 180), rng.randint(100, 180), rng.randint(130, 200))
    extruded_image = extrude(mask_L, depth, angle_deg, col_near_rgb, col_far_rgb)

    # Blend all layers together
    return composite(textured_image, inner_glow_rgba, highlight_RGBA, shadow_RGBA, extruded_image, size=(mw, mh))


