# outline_v1649
# ============================================================

def render_texture_v1696(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('slab', auto_size(title), rng)
    mask_L = make_mask(title, font, pad=40)
    mw, mh = mask_L.size

    # Randomize parameters
    base_color = (rng.randint(50, 120), rng.randint(60, 90), rng.randint(70, 130))
    glow_color = (rng.randint(200, 240), rng.randint(220, 240), rng.randint(210, 250))
    bevel_angle_deg = rng.uniform(-60, -120)
    bevel_strength = rng.random() * 0.3
    extrude_depth_int = int(rng.gauss(8, 2))

    # Create texture pattern (fabric-like effect using numpy)
    texture_w, texture_h = mw + mh, mw + mh
    noise_scale = 1 / (texture_w // 4)
    x, y = np.meshgrid(np.arange(texture_w), np.arange(texture_h))
    noise = np.sin(x * noise_scale + rng.random()) + np.cos(y * noise_scale + rng.random())
    noise -= noise.min()
    noise /= noise.max()
    texture = (noise * 255).astype(np.uint8)
    texture_img = Image.fromarray(texture, mode='L')

    # Apply texture as a color overlay
    base_rgba = flat_color(mask_L, base_color)
    texture_overlay = apply_mask(base_rgba, texture_img.resize((mw, mh)).filter(ImageFilter.GaussianBlur(radius=2)))

    # Glow effect for depth and luminance
    glow_rgba = glow_layer(mask_L, glow_color, radii=[(4, 0.3), (8, 0.1)])

    # Bevel lighting
    highlight_rgba, shadow_rgba = bevel_light(mask_L, bevel_angle_deg, bevel_strength)

    # Extrude to give material form
    extrusion_rgba = extrude(dilate(mask_L, 2), extrude_depth_int, -45, base_color, (100, 100, 100))

    return composite(texture_overlay, glow_rgba, highlight_rgba, shadow_rgba, extrusion_rgba, size=(mw, mh))


