def render_thermal_heatmap_wild2688(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('tech', auto_size(title), rng)
    mask_L = make_mask(title, font)

    mw, mh = mask_L.size

    # Gradient color map for thermal effect
    gradient_colors = [(0, 0, 255), (0, 255, 0), (255, 255, 0), (255, 0, 0)]
    h_values = np.linspace(240, 0, len(gradient_colors)).tolist()
    s_value, v_value = 100, 100
    gradient_hsv = [(h / 360.0, s_value / 100.0, v_value / 100.0) for h in h_values]
    color_stops = [tuple(int(c * 255) for c in np.array(colorsys.hsv_to_rgb(hsv[0], hsv[1], hsv[2]))) for hsv in gradient_hsv]

    thermal_gradient_rgba = colorize(mask_L, [(c[0], c[1], c[2]) for c in gradient_colors])

    # Random outer glow parameters
    gl_radius = rng.uniform(4, 8)
    gl_color_index = rng.randint(1, len(color_stops) - 1)
    gl_color = color_stops[gl_color_index]
    gl_layer_rgba = glow_layer(mask_L, gl_color, radii=[(int(gl_radius), gl_radius)])

    # Randomize heat direction for thermal effect
    heat_direction = rng.choice(['left', 'right'])

    if heat_direction == 'right':
        heat_start_stop = [(mw // 2 + int(rng.uniform(-10, 10)), mw - int(rng.uniform(5, 20))),
                           (0, mw // 2 - int(rng.uniform(-10, 10)))]
    else:
        heat_start_stop = [(0, mw // 2 - int(rng.uniform(-10, 10))),
                           (mw // 2 + int(rng.uniform(-10, 10)), mw)]

    # Compose the thermal effect layers
    return composite(thermal_gradient_rgba, gl_layer_rgba, size=(mw, mh))


