    pink_cyan, teal_orange = color_group

    # Base text layer
    base_layer = colorize(mask_L, [teal_orange, pink_cyan])

    # Glow effect
    glow_color = (255, 0, 255) if rng.choice([1, 2]) == 1 else (148, 0, 211)
    glow_radius = [(rng.randint(3, 6), rng.uniform(.7, .9))]
    glow_layer_rgba = glow_layer(mask_L, glow_color, glow_radius)

    # Inner glow effect
    inner_glow_radius = [(rng.randint(1, 3), rng.uniform(.2, .4))]
    white_glow_layer = inner_glow(mask_L, (255, 255, 255), inner_glow_radius)

    # Thin purple outline
    outer_shadow_color = (70, 0, 130) if rng.choice([1, 2]) == 1 else (255, 0, 0)
    outline_layer = drop_shadow(mask_L, -2, -2, 1, 192)

    # Composite all layers
    return composite(base_layer, glow_layer_rgba, white_glow_layer, outline_layer, size=(mw, mh))


