def render_wax_seal_pressed(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('elegant', auto_size(title), rng)
    mask_L = make_mask(title, font)
    mw, mh = mask_L.size

    wax_color_stops = [
        (rng.randint(128, 255), rng.randint(0, 32), rng.randint(0, 32)),
        (rng.randint(64, 192), rng.randint(32, 96), rng.randint(32, 96)),
        (rng.randint(0, 128), rng.randint(32, 128), rng.randint(32, 128))
    ]
    wax_color = colorize(mask_L, wax_color_stops)

    bevel_angle_deg = rng.uniform(315, 330)
    highlight_rgba, shadow_rgba = bevel_light(mask_L, angle_deg=bevel_angle_deg, strength=rng.uniform(2.8, 3.2))
    
    gold_outline_rgba = flat_color(mask_L, (rng.randint(224, 255), rng.randint(192, 224), rng.randint(0, 64)))
    
    return composite(wax_color, apply_mask(highlight_rgba, dilate(mask_L, -3)), 
                     apply_mask(shadow_rgba, dilate(mask_L, 3)), gold_outline_rgba,
                     size=(mw, mh))


# ============================================================
# plasma_globe
# ============================================================

def render_weathered_bronze(title: str, rng: random.Random) -> Image.Image:
    title = title.upper()
    font = F('slab', auto_size(title, pivot=12), rng)
    mask_L = make_mask(title, font, pad=30)
    mw, mh = mask_L.size

    # Randomize patina amount
    patina_amount = rng.uniform(0.75, 1.0)

    # Warm brown-green colorize (verdigris) with random variations
    stops = [(rng.randint(64, 96), 64 + int(patina_amount * rng.randint(80, 128)), 32),
             (rng.randint(80, 128), 64 + int(patina_amount * rng.randint(128, 160)), 56)]
    rgba_img = colorize(mask_L, stops)

    # Add random noise for oxidation texture
    noise_alpha = np.random.normal(size=(mw, mh)) * patina_amount
    noise_mask = Image.fromarray(np.clip(noise_alpha * 255, 0, 255).astype(np.uint8), mode='L')
    rgba_img = apply_mask(rgba_img, dilate(mask_L, rng.randint(-3, 4)))

    # Strong concave bevel with random angle and strength
    angle_deg = rng.uniform(160, 200)
    strength = rng.uniform(0.5, 1.0)
    highlight_RGBA, shadow_RGBA = bevel_light(mask_L, angle_deg, strength)

    rgba_img = composite(shadow_RGBA,
                         apply_mask(highlight_RGBA, dilate(mask_L, -rng.randint(-3, -1))),
                         rgba_img,
                         size=(mw, mh))

    return rgba_img


