def render_cyber_split(title: str, rng: random.Random) -> Image.Image:
    """Geometric/tech font, magenta+cyan split color, futuristic."""
    fs = auto_size(title, 200, 14)
    font = F("futuristic", fs, rng)
    mask = make_mask(title.upper(), font, pad=50)
    mw, mh = mask.size
    col_a, col_b, glow_a, glow_b = rng.choice([
        ((255,0,120), (0,255,240), (255,60,160), (60,255,250)),   # magenta/cyan
        ((255,60,0),  (0,200,255), (255,120,60), (60,220,255)),   # red/blue
        ((200,0,255), (0,255,120), (230,80,255), (80,255,160)),   # purple/green
        ((255,200,0), (0,120,255), (255,230,60), (60,160,255)),   # gold/blue
    ])
    m = np.array(mask, dtype=np.float32) / 255.0
    h, w = m.shape
    split = np.zeros((h, w, 4), dtype=np.uint8)
    mid = w // 2
    for i in range(3):
        split[:, :mid, i] = col_a[i]
        split[:, mid:, i] = col_b[i]
    split[:, :, 3] = (m * 255).astype(np.uint8)
    face = Image.fromarray(split, "RGBA")
    bloom_a = glow_layer(mask, glow_a, radii=[(rng.randint(20, 32), 0.4)])
    bloom_b = glow_layer(mask, glow_b, radii=[(rng.randint(20, 32), 0.4)])
    ig = inner_glow(mask, (255, 255, 255), radii=[(4, 0.9)])
    return composite(bloom_a, bloom_b, face, ig, size=(mw, mh))


