def render_hand_sketch(title: str, rng: random.Random) -> Image.Image:
    """Handwritten font, sketch-like outline, no fill — just strokes."""
    fs = auto_size(title, 180, 14)
    font = F("brush", fs, rng)
    mask = make_mask(title, font, pad=40)
    mw, mh = mask.size
    col = rng.choice([
        (40, 40, 50),      # charcoal
        (60, 30, 20),      # brown pencil
        (20, 40, 80),      # blue pen
        (80, 20, 20),      # red pen
    ])
    outline_outer = flat_color(dilate(mask, 3), col)
    eroded = dilate(mask, -2)
    inner_cut = flat_color(eroded, (0, 0, 0))
    # Composite: outer outline, then cut away the interior to leave just the edge
    canvas = Image.new("RGBA", (mw, mh), (0, 0, 0, 0))
    canvas = Image.alpha_composite(canvas, outline_outer)
    # Erase inner
    m_inner = np.array(eroded, dtype=np.float32) / 255.0
    c_arr = np.array(canvas, dtype=np.float32)
    c_arr[:, :, 3] = c_arr[:, :, 3] * (1.0 - m_inner * 0.85)
    return Image.fromarray(c_arr.astype(np.uint8), "RGBA")


