def render_candy_stripe(title: str, rng: random.Random) -> Image.Image:
    """Bold font, horizontal color stripes through text, fun and playful."""
    fs = auto_size(title, 200, 14)
    font = F("heavy", fs, rng)
    mask = make_mask(title.upper(), font, pad=40)
    mw, mh = mask.size
    stripe_colors = rng.choice([
        [(255,60,80),(255,200,0),(60,200,255),(255,120,200)],      # primary party
        [(255,100,150),(100,200,255),(255,220,80),(150,255,150)],   # pastel party
        [(255,60,0),(255,180,0),(0,200,80),(0,150,255)],           # bold spectrum
        [(255,80,200),(80,255,200),(255,255,80),(200,80,255)],     # neon party
    ])
    m = np.array(mask, dtype=np.float32) / 255.0
    h, w = m.shape
    stripe_h = max(1, h // len(stripe_colors))
    img = np.zeros((h, w, 4), dtype=np.uint8)
    for i, col in enumerate(stripe_colors):
        y0 = i * stripe_h
        y1 = min(h, (i + 1) * stripe_h) if i < len(stripe_colors) - 1 else h
        img[y0:y1, :, 0] = col[0]
        img[y0:y1, :, 1] = col[1]
        img[y0:y1, :, 2] = col[2]
    img[:, :, 3] = (m * 255).astype(np.uint8)
    face = Image.fromarray(img, "RGBA")
    outline_mask = dilate(mask, 3)
    outline = flat_color(outline_mask, (30, 30, 40))
    ds = drop_shadow(mask, rng.randint(3, 5), rng.randint(5, 8), blur=rng.randint(8, 12), alpha=140)
    return composite(ds, outline, face, size=(mw, mh))


