def render_street_neon(title: str, rng: random.Random) -> Image.Image:
    """Heavy font, dual neon outline (no fill), gritty urban neon sign."""
    fs = auto_size(title, 200, 14)
    font = F("heavy", fs, rng)
    mask = make_mask(title.upper(), font, pad=55)
    mw, mh = mask.size
    col_a, col_b = rng.choice([
        ((255,0,100), (0,255,200)),   # pink/cyan
        ((255,120,0), (0,200,255)),   # orange/blue
        ((255,0,255), (0,255,100)),   # magenta/green
        ((255,255,0), (0,150,255)),   # yellow/blue
    ])
    outer = dilate(mask, rng.randint(5, 7))
    inner = dilate(mask, rng.randint(2, 3))
    # Outer glow ring
    outer_glow = glow_layer(outer, col_a, radii=[(rng.randint(15, 25), 0.5), (rng.randint(6, 10), 0.8)])
    outer_line = flat_color(outer, col_a, alpha=220)
    # Inner glow ring
    inner_glow_l = glow_layer(inner, col_b, radii=[(rng.randint(10, 18), 0.5), (rng.randint(4, 7), 0.8)])
    inner_line = flat_color(inner, col_b, alpha=220)
    # Cut out fill to leave just the outlines
    m_mask = np.array(mask, dtype=np.float32) / 255.0
    for layer in [outer_line, inner_line]:
        arr = np.array(layer, dtype=np.float32)
        arr[:, :, 3] = arr[:, :, 3] * (1.0 - m_mask * 0.9)
        layer.paste(Image.fromarray(arr.astype(np.uint8), "RGBA"))
    return composite(outer_glow, outer_line, inner_glow_l, inner_line, size=(mw, mh))


