def render_chrome_v2(title: str, rng: random.Random) -> Image.Image:
    """Environment-mapped chrome with specular highlights and grain."""
    fs = auto_size_hd(title)
    font = F("heavy", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=100)
    mw, mh = mask.size
    stops = rng.choice([
        [(30,35,45),(180,190,210),(255,255,255),(60,70,90),(200,210,230),(255,255,255),(100,110,130)],
        [(20,22,28),(150,160,180),(240,245,255),(45,50,65),(190,200,220),(250,252,255),(80,90,110)],
        [(40,35,30),(170,165,155),(245,240,230),(70,65,55),(200,195,185),(240,235,225),(110,105,95)],
    ])
    chrome = env_map_chrome(mask, stops=stops, angle=rng.uniform(-20, 20),
                            stretch=rng.uniform(1.2, 2.0), noise_amount=0.06, seed=rng.randint(0, 9999))
    spec = specular_highlight(mask, pos_y=rng.uniform(0.2, 0.35),
                              width=rng.uniform(0.1, 0.2), intensity=rng.uniform(0.5, 0.8))
    hl, sh = bevel_light(mask, angle_deg=rng.choice([125, 135, 145]), strength=rng.uniform(2.0, 3.0))
    ds = drop_shadow(mask, rng.randint(4, 8), rng.randint(6, 12), blur=rng.randint(10, 18), alpha=180)
    result = composite(ds, chrome, hl, sh, spec, size=(mw, mh))
    return grain_overlay(result, amount=rng.uniform(0.02, 0.05), seed=rng.randint(0, 9999))


