def render_marble_v2(title: str, rng: random.Random) -> Image.Image:
    """Marble texture with veining and carved emboss."""
    fs = auto_size_hd(title)
    font = F("serif", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=100)
    mw, mh = mask.size
    base = rng.choice([
        ((235, 230, 225), (250, 248, 244)),  # white Carrara
        ((200, 195, 185), (235, 230, 220)),  # warm cream
        ((180, 185, 195), (230, 235, 245)),  # cool gray
    ])
    fill = texture_fill(mask, base[0], base[1], noise_scale=0.008, seed=rng.randint(0, 9999))
    # Veining — darker noise layer at different scale
    vein_noise = noise_texture(mw, mh, scale=0.025, octaves=3, seed=rng.randint(0, 9999))
    vein_mask = (vein_noise > 0.55).astype(np.float32) * 0.3
    fill_arr = np.array(fill, dtype=np.float32)
    fill_arr[:, :, :3] = np.clip(fill_arr[:, :, :3] * (1.0 - vein_mask[:, :, None] * 0.4), 0, 255)
    fill = Image.fromarray(fill_arr.astype(np.uint8), "RGBA")
    emb = emboss_deep(mask, depth=2.5, angle_deg=135, ambient=0.4)
    fill = Image.alpha_composite(fill, emb)
    hl, sh = bevel_light(mask, angle_deg=135, strength=1.8)
    ds = drop_shadow(mask, 8, 12, blur=20, alpha=120)
    return composite(ds, fill, hl, sh, size=(mw, mh))


def render_lava_v2(title: str, rng: random.Random) -> Image.Image:
    """Molten lava with cracked rock texture and orange glow."""
    fs = auto_size_hd(title)
    font = F("heavy", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=120)
    mw, mh = mask.size
    # Dark rock base with hot lava showing through cracks
    rock = texture_fill(mask, (30, 20, 15), (60, 40, 30), noise_scale=0.02, seed=rng.randint(0, 9999))
    lava_noise = noise_texture(mw, mh, scale=0.015, octaves=5, seed=rng.randint(0, 9999))
    # Lava shows where noise is bright
    lava_mask = np.clip((lava_noise - 0.45) * 4.0, 0, 1)
    rock_arr = np.array(rock, dtype=np.float32)
    m_arr = np.array(mask, dtype=np.float32) / 255.0
    for y in range(mh):
        for c, lava_val in enumerate([(255, 180, 50), (200, 80, 0)]):
            pass
    # Vectorized lava blend
    lava_color = np.array([255, 140, 20], dtype=np.float32)
    for c in range(3):
        rock_arr[:, :, c] = np.clip(
            rock_arr[:, :, c] * (1 - lava_mask) + lava_color[c] * lava_mask * m_arr, 0, 255
        )
    rock = Image.fromarray(rock_arr.astype(np.uint8), "RGBA")
    hl, sh = bevel_light(mask, angle_deg=135, strength=2.5)
    ig = inner_glow(mask, (255, 120, 0), radii=[(10, 0.6), (4, 0.9)])
    bloom = glow_layer(mask, (255, 100, 0), radii=[(35, 0.2), (15, 0.35)])
    ds = drop_shadow(mask, 10, 16, blur=24, alpha=160)
    return composite(bloom, ds, rock, hl, sh, ig, size=(mw, mh))


def render_ice_v2(title: str, rng: random.Random) -> Image.Image:
    """Crystalline ice with frost texture and cold blue glow."""
    fs = auto_size_hd(title)
    font = F("geometric", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=120)
    mw, mh = mask.size
    fill = texture_fill(mask, (160, 210, 240), (230, 245, 255), noise_scale=0.012, seed=rng.randint(0, 9999))
    # Frost cracks
    crack_noise = noise_texture(mw, mh, scale=0.03, octaves=3, seed=rng.randint(0, 9999))
    crack_mask = (crack_noise > 0.6).astype(np.float32) * 0.5
    fill_arr = np.array(fill, dtype=np.float32)
    fill_arr[:, :, :3] = np.clip(fill_arr[:, :, :3] + crack_mask[:, :, None] * 60, 0, 255)
    fill = Image.fromarray(fill_arr.astype(np.uint8), "RGBA")
    spec = specular_highlight(mask, pos_y=0.25, width=0.18, intensity=0.7)
    hl, sh = bevel_light(mask, angle_deg=130, strength=2.2)
    ig = inner_glow(mask, (180, 230, 255), radii=[(8, 0.6)])
    bloom = glow_layer(mask, (120, 200, 255), radii=[(30, 0.15)])
    ds = drop_shadow(mask, 8, 14, blur=20, alpha=140)
    return composite(bloom, ds, fill, hl, sh, spec, ig, size=(mw, mh))


def render_neon_v2(title: str, rng: random.Random) -> Image.Image:
    """Ultra-realistic neon tube with multiple bloom layers and flicker."""
    fs = auto_size_hd(title)
    font = F("script", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=160)
    mw, mh = mask.size
    col = rng.choice([
        (255, 50, 120), (0, 240, 200), (255, 120, 0), (80, 180, 255),
        (200, 0, 255), (255, 240, 0), (0, 255, 120), (255, 50, 200),
    ])
    # Multi-layer bloom for realistic neon falloff
    bloom_far = glow_layer(mask, col, radii=[(60, rng.uniform(0.15, 0.25))])
    bloom_mid = glow_layer(mask, col, radii=[(35, rng.uniform(0.3, 0.45))])
    bloom_near = glow_layer(mask, col, radii=[(18, rng.uniform(0.55, 0.7))])
    tube = glow_layer(mask, col, radii=[(6, 0.85)])
    core = flat_color(mask, (255, 255, 255))
    ig = inner_glow(mask, col, radii=[(8, 0.9), (3, 1.0)])
    # Optional dual color accent
    if rng.random() < 0.5:
        col2 = rng.choice([(255, 240, 0), (0, 200, 255), (255, 60, 200), (0, 255, 160)])
        accent = glow_layer(mask, col2, radii=[(50, 0.12)])
        return composite(accent, bloom_far, bloom_mid, bloom_near, tube, core, ig, size=(mw, mh))
    return composite(bloom_far, bloom_mid, bloom_near, tube, core, ig, size=(mw, mh))


def render_diamond_v2(title: str, rng: random.Random) -> Image.Image:
    """Diamond/gem cut with faceted highlights and sparkle."""
    fs = auto_size_hd(title)
    font = F("heavy", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=100)
    mw, mh = mask.size
    base_col = rng.choice([
        ((180, 210, 240), (230, 245, 255)),  # diamond
        ((200, 180, 220), (240, 220, 255)),  # amethyst
        ((180, 220, 200), (220, 255, 240)),  # emerald
        ((240, 200, 200), (255, 230, 230)),  # ruby
        ((220, 220, 180), (255, 255, 230)),  # topaz
    ])
    fill = texture_fill(mask, base_col[0], base_col[1], noise_scale=0.02, seed=rng.randint(0, 9999))
    # Faceted look via strong multi-angle emboss
    emb = emboss_deep(mask, depth=3.5, angle_deg=rng.choice([120, 135, 150]), ambient=0.35)
    fill = Image.alpha_composite(fill, emb)
    spec1 = specular_highlight(mask, pos_y=0.2, width=0.08, intensity=0.9)
    spec2 = specular_highlight(mask, pos_y=0.6, width=0.06, intensity=0.5)
    hl, sh = bevel_light(mask, angle_deg=135, strength=2.8)
    ig = inner_glow(mask, base_col[1], radii=[(6, 0.5)])
    ds = drop_shadow(mask, 10, 16, blur=24, alpha=150)
    bloom = glow_layer(mask, base_col[1], radii=[(20, 0.1)])
    return composite(bloom, ds, fill, hl, sh, spec1, spec2, ig, size=(mw, mh))


def render_brushed_steel(title: str, rng: random.Random) -> Image.Image:
    """Brushed stainless steel with directional grain."""
    fs = auto_size_hd(title)
    font = F("stark", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=90)
    mw, mh = mask.size
    # Horizontal brushing = noise stretched in x
    steel = texture_fill(mask, (140, 145, 155), (200, 205, 215),
                         noise_scale=0.005, seed=rng.randint(0, 9999))
    # Add horizontal streaks
    streak_noise = noise_texture(mw, mh, scale=0.003, octaves=2, seed=rng.randint(0, 9999))
    steel_arr = np.array(steel, dtype=np.float32)
    steel_arr[:, :, :3] = np.clip(steel_arr[:, :, :3] + (streak_noise[:, :, None] - 0.5) * 40, 0, 255)
    steel = Image.fromarray(steel_arr.astype(np.uint8), "RGBA")
    spec = specular_highlight(mask, pos_y=0.3, width=0.12, intensity=0.6)
    hl, sh = bevel_light(mask, angle_deg=135, strength=2.0)
    ds = drop_shadow(mask, 8, 14, blur=20, alpha=160)
    result = composite(ds, steel, hl, sh, spec, size=(mw, mh))
    return grain_overlay(result, amount=0.03, seed=rng.randint(0, 9999))


def render_copper_patina(title: str, rng: random.Random) -> Image.Image:
    """Aged copper with green patina texture."""
    fs = auto_size_hd(title)
    font = F("serif", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=100)
    mw, mh = mask.size
    copper = env_map_chrome(mask, stops=[
        (60, 35, 15), (190, 110, 50), (230, 165, 85), (180, 100, 40),
        (140, 75, 25), (210, 140, 65), (100, 55, 20)
    ], angle=rng.uniform(-15, 15), stretch=1.5, noise_amount=0.06, seed=rng.randint(0, 9999))
    # Green patina overlay
    patina_noise = noise_texture(mw, mh, scale=0.02, octaves=4, seed=rng.randint(0, 9999))
    patina_mask = np.clip((patina_noise - 0.4) * 2.5, 0, 0.6)
    cop_arr = np.array(copper, dtype=np.float32)
    m_arr = np.array(mask, dtype=np.float32) / 255.0
    patina_color = np.array([80, 160, 120], dtype=np.float32)
    for c in range(3):
        cop_arr[:, :, c] = np.clip(
            cop_arr[:, :, c] * (1 - patina_mask) + patina_color[c] * patina_mask * m_arr, 0, 255
        )
    copper = Image.fromarray(cop_arr.astype(np.uint8), "RGBA")
    hl, sh = bevel_light(mask, angle_deg=140, strength=2.0)
    ds = drop_shadow(mask, 10, 16, blur=24, alpha=140)
    return grain_overlay(composite(ds, copper, hl, sh, size=(mw, mh)), amount=0.04)


def render_onyx_v2(title: str, rng: random.Random) -> Image.Image:
    """Black onyx with subtle purple inner glow and sharp bevel."""
    fs = auto_size_hd(title)
    font = F("heavy", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=100)
    mw, mh = mask.size
    fill = texture_fill(mask, (15, 10, 25), (40, 30, 55), noise_scale=0.015, seed=rng.randint(0, 9999))
    hl, sh = bevel_light(mask, angle_deg=135, strength=3.0)
    ig = inner_glow(mask, rng.choice([(120, 60, 200), (60, 120, 200), (200, 60, 120)]),
                    radii=[(10, 0.5), (4, 0.8)])
    bloom = glow_layer(mask, (100, 50, 180), radii=[(30, 0.1)])
    ds = drop_shadow(mask, 10, 16, blur=28, alpha=180)
    stroke = outline_stroke(mask, width=2, rgb=(80, 40, 140), alpha=180)
    return composite(bloom, ds, fill, hl, sh, ig, stroke, size=(mw, mh))


def render_holographic_v2(title: str, rng: random.Random) -> Image.Image:
    """Rainbow holographic foil with diagonal sweep."""
    fs = auto_size_hd(title)
    font = F("geometric", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=100)
    mw, mh = mask.size
    # Rainbow diagonal gradient
    angle = rng.uniform(30, 60)
    stops = [(255,80,120),(255,200,60),(80,255,120),(60,200,255),(180,80,255),(255,80,160)]
    fill = diagonal_gradient_fill(mask, stops, angle_deg=angle)
    # Add noise for shimmer
    fill_arr = np.array(fill, dtype=np.float32)
    shimmer = noise_texture(mw, mh, scale=0.04, seed=rng.randint(0, 9999))
    fill_arr[:, :, :3] = np.clip(fill_arr[:, :, :3] + (shimmer[:, :, None] - 0.5) * 50, 0, 255)
    fill = Image.fromarray(fill_arr.astype(np.uint8), "RGBA")
    spec = specular_highlight(mask, pos_y=0.3, width=0.1, intensity=0.6)
    hl, sh = bevel_light(mask, angle_deg=130, strength=1.8)
    ds = drop_shadow(mask, 8, 12, blur=20, alpha=130)
    return composite(ds, fill, hl, sh, spec, size=(mw, mh))


def render_electric_v2(title: str, rng: random.Random) -> Image.Image:
    """Electric plasma with crackling energy bloom."""
    fs = auto_size_hd(title)
    font = F("futuristic", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=140)
    mw, mh = mask.size
    col = rng.choice([(80, 160, 255), (160, 80, 255), (80, 255, 200), (255, 80, 200)])
    core = flat_color(mask, (255, 255, 255))
    tube = glow_layer(mask, col, radii=[(6, 0.9)])
    mid = glow_layer(mask, col, radii=[(20, 0.5)])
    bloom = glow_layer(mask, col, radii=[(45, 0.2)])
    # Noise-based "crackling" modulation on the bloom
    crack = noise_texture(mw, mh, scale=0.05, octaves=3, seed=rng.randint(0, 9999))
    bloom_arr = np.array(bloom, dtype=np.float32)
    bloom_arr[:, :, 3] = np.clip(bloom_arr[:, :, 3] * (0.5 + crack * 1.0), 0, 255)
    bloom = Image.fromarray(bloom_arr.astype(np.uint8), "RGBA")
    ig = inner_glow(mask, col, radii=[(8, 0.8)])
    return composite(bloom, mid, tube, core, ig, size=(mw, mh))


def render_wood_burn(title: str, rng: random.Random) -> Image.Image:
    """Wood-burned / pyrography effect with warm brown texture."""
    fs = auto_size_hd(title)
    font = F("serif", fs, rng)
