def render_sticker_badge(title: str, rng: random.Random) -> Image.Image:
    """Sticker effect — thick colorful concentric outlines."""
    fs = auto_size_hd(title)
    font = F("heavy", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=120)
    mw, mh = mask.size
    palette = rng.choice([
        [(255, 255, 255), (255, 60, 100), (40, 40, 50)],
        [(255, 255, 0), (255, 80, 0), (20, 20, 30)],
        [(0, 255, 200), (0, 100, 200), (20, 20, 40)],
        [(255, 200, 255), (200, 50, 200), (30, 20, 40)],
    ])
    rings = contour_lines(mask, count=3, spacing=rng.randint(4, 7), colors=palette)
    face_col = rng.choice([
        [(255,255,255),(240,240,250)],
        [(255,240,200),(255,220,150)],
        [(200,255,240),(180,250,230)],
    ])
    face = colorize(mask, face_col)
    ds = drop_shadow(mask, 8, 12, blur=20, alpha=140)
    hl, sh = bevel_light(mask, angle_deg=135, strength=1.5)
    return composite(ds, rings, face, hl, sh, size=(mw, mh))


def render_retro_chrome_3d(title: str, rng: random.Random) -> Image.Image:
    """80s-style chrome 3D text with lit extrusion and specular."""
    fs = auto_size_hd(title)
    font = F("stark", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=110)
    mw, mh = mask.size
    ext_color = rng.choice([(60, 50, 80), (80, 50, 60), (50, 60, 80)])
    ext = lit_extrude(mask, depth=rng.randint(12, 20), angle_deg=rng.choice([225, 240, 250]),
                      base_rgb=ext_color, light_angle=135, light_strength=0.6)
    chrome = env_map_chrome(mask, angle=rng.uniform(-15, 15), stretch=1.6,
                            noise_amount=0.05, seed=rng.randint(0, 9999))
    spec = specular_highlight(mask, pos_y=0.28, width=0.12, intensity=0.7)
    hl, sh = bevel_light(mask, angle_deg=135, strength=2.5)
    ds = drop_shadow(mask, 12, 20, blur=28, alpha=180)
    return composite(ds, ext, chrome, hl, sh, spec, size=(mw, mh))


def render_glitch_v2(title: str, rng: random.Random) -> Image.Image:
    """Chromatic aberration glitch with scanlines."""
    fs = auto_size_hd(title)
    font = F("futuristic", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=100)
    mw, mh = mask.size
    fill = colorize(mask, [(255, 255, 255), (220, 230, 255)])
    ca = chromatic_aberration(fill, offset=rng.randint(3, 7))
    ca = scanlines(ca, spacing=rng.choice([2, 3, 4]), alpha=rng.uniform(0.2, 0.35))
    glow_col = rng.choice([(0, 255, 200), (255, 50, 150), (80, 200, 255)])
    bloom = glow_layer(mask, glow_col, radii=[(20, 0.2)])
    return composite(bloom, ca, size=(mw, mh))


def render_silk_luxury(title: str, rng: random.Random) -> Image.Image:
    """Silk satin text with contour-following sheen."""
    fs = auto_size_hd(title)
    font = F("luxury", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=100)
    mw, mh = mask.size
    base_col = rng.choice([
        [(80, 20, 40), (150, 40, 70), (200, 60, 100)],    # burgundy
        [(15, 20, 60), (30, 50, 130), (60, 80, 180)],     # navy
        [(50, 30, 60), (100, 50, 120), (160, 80, 180)],   # purple
        [(20, 40, 30), (40, 90, 60), (70, 140, 100)],     # emerald
    ])
    fill = colorize(mask, base_col)
    sheen_col = rng.choice([(255, 220, 240), (220, 230, 255), (240, 230, 255), (220, 255, 240)])
    sat = satin_sheen(mask, rgb=sheen_col, angle_deg=rng.uniform(120, 160),
                      width=rng.uniform(0.3, 0.5), intensity=rng.uniform(0.4, 0.6))
    hl, sh = bevel_light(mask, angle_deg=140, strength=1.8)
    ds = drop_shadow(mask, 8, 14, blur=20, alpha=130)
    stroke = gradient_stroke(mask, width=2, stops=[(200, 180, 160), (255, 240, 220)])
    return composite(ds, stroke, fill, sat, hl, sh, size=(mw, mh))


def render_sport_stripe(title: str, rng: random.Random) -> Image.Image:
    """Athletic/sports style with bold stripes and sharp outlines."""
    fs = auto_size_hd(title)
    font = F("stark", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=110)
    mw, mh = mask.size
    colors = rng.choice([
        [(255, 0, 50), (255, 255, 255)],       # red/white
        [(0, 80, 200), (255, 200, 0)],          # blue/gold
        [(0, 130, 60), (255, 255, 255)],        # green/white
        [(30, 30, 30), (255, 180, 0)],          # black/gold
    ])
    fill = stripe_fill(mask, colors, stripe_width=rng.randint(8, 14),
                       angle_deg=rng.choice([45, -45, 60, -60]))
    outline = outline_stroke(mask, width=rng.randint(3, 5), rgb=(255, 255, 255))
    outer = outline_stroke(
        dilate(mask, 3), width=2,
        rgb=rng.choice([(0, 0, 0), (40, 40, 50)])
    )
    hl, sh = bevel_light(mask, angle_deg=135, strength=1.6)
    ds = drop_shadow(mask, 10, 16, blur=24, alpha=170)
    return composite(ds, outer, outline, fill, hl, sh, size=(mw, mh))


