def render_neon_contour(title: str, rng: random.Random) -> Image.Image:
    """Multiple neon contour lines with no fill — outline-only neon."""
    fs = auto_size_hd(title)
    font = F("geometric", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=140)
    mw, mh = mask.size
    col = rng.choice([(255, 50, 120), (0, 240, 200), (255, 120, 0), (80, 180, 255), (200, 0, 255)])
    # Multiple glowing contour rings
    rings = contour_lines(mask, count=3, spacing=rng.randint(5, 8),
                          colors=[col, col, col], alpha=200)
    # Blur each ring for glow
    bloom = glow_layer(mask, col, radii=[(40, 0.15), (20, 0.3)])
    # Ring glow
    ring_bloom_arr = np.array(rings, dtype=np.float32)
    ring_bloom = Image.fromarray(
        np.clip(ring_bloom_arr, 0, 255).astype(np.uint8), "RGBA"
    ).filter(ImageFilter.GaussianBlur(6))
    return composite(bloom, ring_bloom, rings, size=(mw, mh))


def render_embossed_leather(title: str, rng: random.Random) -> Image.Image:
    """Embossed into leather texture."""
    fs = auto_size_hd(title)
    font = F("serif", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=100)
    mw, mh = mask.size
    leather_col = rng.choice([
        ((60, 30, 15), (100, 55, 30)),   # dark brown
        ((30, 15, 10), (70, 40, 25)),    # espresso
        ((70, 35, 20), (120, 70, 40)),   # tan
        ((20, 20, 25), (50, 50, 60)),    # black leather
    ])
    fill = texture_fill(mask, leather_col[0], leather_col[1], noise_scale=0.025, seed=rng.randint(0, 9999))
    emb = emboss_deep(mask, depth=2.5, angle_deg=135, ambient=0.35)
    fill = Image.alpha_composite(fill, emb)
    ig = inner_glow(mask, (leather_col[1][0] + 40, leather_col[1][1] + 30, leather_col[1][2] + 20),
                    radii=[(5, 0.3)])
    ds = drop_shadow(mask, 6, 10, blur=16, alpha=120)
    return grain_overlay(composite(ds, fill, ig, size=(mw, mh)), amount=0.06)


def render_vapor_chrome(title: str, rng: random.Random) -> Image.Image:
    """Vaporwave chrome — pink/cyan gradient on chrome env map."""
    fs = auto_size_hd(title)
    font = F("geometric", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=110)
    mw, mh = mask.size
    stops = rng.choice([
        [(255,100,180),(200,80,200),(100,120,255),(80,200,255),(180,255,240)],
        [(80,200,255),(120,80,255),(255,80,200),(255,200,100),(100,255,200)],
    ])
    # Chrome base
    chrome = env_map_chrome(mask, angle=rng.uniform(-20, 20), stretch=1.8,
                            noise_amount=0.04, seed=rng.randint(0, 9999))
    # Overlay vapor gradient
    vapor = diagonal_gradient_fill(mask, stops, angle_deg=rng.uniform(30, 60))
    result = blend_screen(chrome, vapor)
    hl, sh = bevel_light(mask, angle_deg=135, strength=2.0)
    spec = specular_highlight(mask, pos_y=0.3, width=0.1, intensity=0.5)
    ds = drop_shadow(mask, 10, 16, blur=24, alpha=150)
    bloom = glow_layer(mask, (200, 100, 255), radii=[(25, 0.1)])
    return composite(bloom, ds, result, hl, sh, spec, size=(mw, mh))


def render_retro_halftone(title: str, rng: random.Random) -> Image.Image:
    """Retro halftone pop art style."""
    fs = auto_size_hd(title)
    font = F("heavy", fs, rng)
    mask = make_mask_hd(title.upper(), font, pad=100)
    mw, mh = mask.size
    col = rng.choice([(255, 50, 50), (0, 100, 200), (255, 180, 0), (200, 0, 150)])
    fill = halftone_fill(mask, col, dot_size=rng.randint(5, 8),
                         spacing=rng.randint(7, 10))
    outline = outline_stroke(mask, width=3, rgb=(0, 0, 0))
    ds = colored_shadow(mask, 12, 12, rgb=col, blur=0, alpha=200)
    return composite(ds, outline, fill, size=(mw, mh))


